-- Poems batch 389
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('9dc2eaac-00f1-4648-a4a0-9611566f58a4','擬峴臺','黎道華','宋','宋诗','song-poetry','','[]','我因訪古獨來遊，萬頃風煙一目收。',64,'全唐诗/poet.song.98000.json','["我因訪古獨來遊，萬頃風煙一目收。", "靈谷諸峰排檻出，巽溪幾曲抱城流。", "帆檣影亂汀洲晚，蘆葦聲寒雁鶩秋。", "墮淚豐碑那得見，片雲落日是襄州。"]'),
('a0df5064-cf97-4c9e-8e64-48efc6bad475','明水寺','黎道華','宋','宋诗','song-poetry','','[]','寒日荒荒野外昏，亂山深處訪祇園。',64,'全唐诗/poet.song.98000.json','["寒日荒荒野外昏，亂山深處訪祇園。", "一條澗水穿龍洞，十里松陰蔽寺門。", "衲子茹蔬惟鶴瘦，吾儕飲酒作鯨吞。", "夜闌笑語喧空闊，驚起棲鴉過別村。"]'),
('04ebd3e2-41ee-466d-a41d-857cd1ba6ce2','謝惠蘭花','黎道華','宋','宋诗','song-poetry','','[]','曉起微涼病骨蘇，國香和露到貧居。',32,'全唐诗/poet.song.98000.json','["曉起微涼病骨蘇，國香和露到貧居。", "我今不向當門種，免被時人取次鋤。"]'),
('81ddd47b-fa22-480f-a335-a0bd31c3896b','謝惠五月菊','黎道華','宋','宋诗','song-poetry','','[]','道人移菊到山家，細裊薰風带露華。',32,'全唐诗/poet.song.98000.json','["道人移菊到山家，細裊薰風带露華。", "便有淵明籬下趣，誰人着眼看荷花。"]'),
('9464dfc6-9a26-4204-8ebf-d0e7de526a75','金石臺遙碧堂','黎道華','宋','宋诗','song-poetry','','[]','三真駕鶴朝上清，金童前導雙霓旌。',160,'全唐诗/poet.song.98000.json','["三真駕鶴朝上清，金童前導雙霓旌。", "去如摶風不復返，至今霧雨愁青冥。", "空山樓觀纔煙靄，山根水作青羅带。", "道人綠髪映方瞳，呼吸嵐光餐沆瀣。", "瀛洲有路接蓬壺，欲往從之無飛車。", "白浪如山海風惡，此時目斷空愁予。", "何如散髪一堂上，水色山容相蕩漾。", "賦詩把酒弄清暉，酒人奇胸詩益壯。", "三真在天今幾秋，瑤林琪樹連瓊樓。", "會看雲鶴下塵世，金石巖前尋舊遊。"]'),
('53a29790-c7ca-48c8-812e-2236f3fc435f','疏山','黎道華','宋','宋诗','song-poetry','','[]','杖藜徐步興何長，宛宛嵐光接水光。',64,'全唐诗/poet.song.98000.json','["杖藜徐步興何長，宛宛嵐光接水光。", "蟬噪荒林桐葉老，風回半野稻花香。", "卻過蕭寺尋僧話，又入松軒臥晚涼。", "雨後微雲山更好，與君行李未須忙。"]'),
('1eaa3365-b362-44ed-9111-c1da9490d12e','句  其一','周虎臣','宋','宋诗','song-poetry','','[]','綵旆西來橫鐵甕，大江東轉湧金山。',16,'全唐诗/poet.song.98000.json','["綵旆西來橫鐵甕，大江東轉湧金山。"]'),
('6ed612cf-a46e-4192-a59c-3c33aa2cbb7a','句  其二','周虎臣','宋','宋诗','song-poetry','','[]','長日林皋獨醉吟。',8,'全唐诗/poet.song.98000.json','["長日林皋獨醉吟。"]'),
('c17614ac-360a-4ff7-8ea0-67dca130ca50','句','某衛尉','宋','宋诗','song-poetry','','[]','清音見江來，載酒送江去。',12,'全唐诗/poet.song.98000.json','["清音見江來，載酒送江去。"]'),
('e6b30ac4-4f37-44ca-9731-2f6d2c1d4ded','吳孫王墓','楊友夔','宋','宋诗','song-poetry','','[]','闔閭城南荒之丘，昔誰葬者孫豫州。',160,'全唐诗/poet.song.98000.json','["闔閭城南荒之丘，昔誰葬者孫豫州。", "久無過客爲下馬，時有牧童來放牛。", "居然珍寶出光怪，識者夜見蹤其由。", "玉環金碗到城市，土花不蝕餘千秋。", "州家廉問亟封守，賊曹掩骼窮姦偷。", "已知其中有可欲，亦恐未免無窮憂。", "當時義師奮四海，少日已無袁與劉。", "英雄異世凜如在，暴露無乃爲神羞。", "人生浮脆無可料，螻蟻烏鳶從所求。", "高陵勸爾一杯酒，自古南山能錮不。"]'),
('35385f35-7ae8-4684-9e68-8ffa7aa655f6','題三高祠','楊友夔','宋','宋诗','song-poetry','','[]','長橋度已盡，有亭枕江湄。',168,'全唐诗/poet.song.98000.json','["長橋度已盡，有亭枕江湄。", "常時閉其門，爲問居者誰。", "范蠡其明哲，功成學鴟夷。", "煙波五湖上，風月一西施。", "張翰輕紱冕，歸及鱸魚時。", "生前一杯足，何以身後爲。", "魯望棲甫里，有田常若饑。", "不應州縣辟，鬰此胸中奇。", "並爲吳越人，名與日月垂。", "相去二千載，今乃同一祠。", "壁間面如生，凜然人在茲。", "我本江海客，一焉起遐思。", "死者不可作，來者詎可期。", "手持一釣竿，浩歌孰從之。"]'),
('f5208729-3e9e-4d02-b25d-2479cb34295a','松江','楊友夔','宋','宋诗','song-poetry','','[]','落日滿大江，孤舟猶獨行。',84,'全唐诗/poet.song.98000.json','["落日滿大江，孤舟猶獨行。", "蒹葭交相風，中有肅殺聲。", "適從城中來，始覺秋氣清。", "世路若迫隘，江湖自寬宏。", "平生獨往志，久與白鳥盟。", "陳人多所閱，新事屢可驚。", "惟有江上峰，殘年眼中青。"]'),
('cf4a7216-647a-4fbb-a5e8-2d3c6112d487','在敵營作','何𣓨','宋','宋诗','song-poetry','','[]','念念通前劫，依依返舊魂。',24,'全唐诗/poet.song.98000.json','["念念通前劫，依依返舊魂。", "人生會有死，遺恨滿乾坤。"]'),
('7b006318-8df3-4d52-8ead-45b43dc99895','句','何𣓨','宋','宋诗','song-poetry','','[]','水涸梁未成，火覿道猶茀。',12,'全唐诗/poet.song.98000.json','["水涸梁未成，火覿道猶茀。"]'),
('0b8b95c2-0011-46aa-820b-3643c740681b','次韻何文縝墨梅二絕  其一','張于文','宋','宋诗','song-poetry','','[]','偃蹙江頭臥夕煙，嬾將玉雪鬬春妍。',32,'全唐诗/poet.song.98000.json','["偃蹙江頭臥夕煙，嬾將玉雪鬬春妍。", "心期老氏能知白，興寄楊雄獨守玄。"]'),
('7286b253-a1d0-4212-b2f3-4008828afcd9','次韻何文縝墨梅二絕  其二','張于文','宋','宋诗','song-poetry','','[]','仙衣雲樣拂輕緇，林下神情特地宜。',32,'全唐诗/poet.song.98000.json','["仙衣雲樣拂輕緇，林下神情特地宜。", "妬婦津頭風怨急，壞粧聊爲□水姿。"]'),
('1aeb17c6-973e-42d6-88cf-3de179734171','次韻何文縝墨梅二絕  其一','墨梅','宋','宋诗','song-poetry','','[]','年端喚醒玉梅魂，滿袖春風不見痕。',32,'全唐诗/poet.song.98000.json','["年端喚醒玉梅魂，滿袖春風不見痕。", "未許卷簾新月上，卻教煙雨惱黄昏。"]'),
('31ad89a3-65bd-4fe7-921e-1bc33a1f2bd2','次韻何文縝墨梅二絕  其二','墨梅','宋','宋诗','song-poetry','','[]','憶昨江湖倒載歸，暗香夾路雨霏微。',32,'全唐诗/poet.song.98000.json','["憶昨江湖倒載歸，暗香夾路雨霏微。", "誰人貌得春風景，遠看如煙近卻非。"]'),
('f661fe24-7ddd-4658-8239-76ed0f630435','次韻何文縝墨梅二絕  其三','墨梅','宋','宋诗','song-poetry','','[]','逸少池邊發興新，管城別作一家春。',32,'全唐诗/poet.song.98000.json','["逸少池邊發興新，管城別作一家春。", "臨風玉笛無人會，鬒髪空歸想太真。"]'),
('e9ccb3d0-4c0b-4222-9544-f3d53d0b7ad4','次韻秦會之題墨梅二首  其一','墨梅','宋','宋诗','song-poetry','','[]','南枝春色弄微溫，記得清香撲酒尊。',32,'全唐诗/poet.song.98000.json','["南枝春色弄微溫，記得清香撲酒尊。", "今日相逢隔煙霧，揚州殘夢足銷魂。"]'),
('3f2618d4-67bd-441f-b485-2976795295d8','次韻秦會之題墨梅二首  其二','墨梅','宋','宋诗','song-poetry','','[]','長愛孤標似君子，不禁橫行巧擠排。',32,'全唐诗/poet.song.98000.json','["長愛孤標似君子，不禁橫行巧擠排。", "短幅離離乃遺像，至今寒蝶誤飛來。"]'),
('6bb562f7-9a1c-4119-9f81-df0bb461bdc6','題古寺','吳敏','宋','宋诗','song-poetry','','[]','古木霜根重，殘僧雪頂深。',24,'全唐诗/poet.song.98000.json','["古木霜根重，殘僧雪頂深。", "棟梁元剝落，香火半消沉。"]'),
('f7feb3ff-9e3b-4116-a120-5c1d31bc8a1a','贈吳正仲','吳敏','宋','宋诗','song-poetry','','[]','先生古人風，文字祖西漢。',24,'全唐诗/poet.song.98000.json','["先生古人風，文字祖西漢。", "不令萬錢食，亦合五花判。"]'),
('f5e96d1d-35b6-43ed-8817-e63820953c90','題山光寺壁上墨竹','吳敏','宋','宋诗','song-poetry','','[]','綠髪青衫舊竹君，墨卿揮拂更清新。',32,'全唐诗/poet.song.98000.json','["綠髪青衫舊竹君，墨卿揮拂更清新。", "斷枝活葉風蕭瑟，想見凌雲百尺身。"]'),
('e8ff8119-fa97-4c4b-a987-9118cae4bdf6','射鶚山','吳敏','宋','宋诗','song-poetry','','[]','東山空闊原野平，吳王養雞築高城。',96,'全唐诗/poet.song.98000.json','["東山空闊原野平，吳王養雞築高城。", "秋天饑鶚未飽食，側翅下攫殊無情。", "守城壯士心孔惡，旦夕窺茲捕雞鶚。", "雕弓一展羽箭發，鶚也時從半空落。", "山人學射藝漸精，遂使山無鶚鳥鳴。", "卻思勾踐侵吳日，何不令之射越兵。"]'),
('bc68ff10-ce94-46ef-9d81-0756ba652023','句  其一','吳敏','宋','宋诗','song-poetry','','[]','人事少陵詩外見，人煙子厚記中行。',16,'全唐诗/poet.song.98000.json','["人事少陵詩外見，人煙子厚記中行。"]'),
('01a8351f-e477-4329-8b47-20ab5750e170','句  其二','吳敏','宋','宋诗','song-poetry','','[]','回首風光橫萬里，他年應記柳侯城。',16,'全唐诗/poet.song.98000.json','["回首風光橫萬里，他年應記柳侯城。"]'),
('7382aadc-32c7-4ec5-ab3a-80498c477189','句  其三','吳敏','宋','宋诗','song-poetry','','[]','萬里西來客，溪山先有名。',12,'全唐诗/poet.song.98000.json','["萬里西來客，溪山先有名。"]'),
('c16bc270-8b73-4494-acae-465449aa2492','句  其四','吳敏','宋','宋诗','song-poetry','','[]','醉中擲筆金鑾殿，睡起鳴笳鐵甕城。',16,'全唐诗/poet.song.98000.json','["醉中擲筆金鑾殿，睡起鳴笳鐵甕城。"]'),
('9f24dcbc-1e7e-47d4-a18e-df717f8590dc','泛舟鑑湖同程致道趙來叔聯句','趙子晝','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.98000.json','["無正文。"]'),
('7f72a8bd-e2f8-419c-a091-4ee7478950ac','題崇蘭館圃  其一','趙子晝','宋','宋诗','song-poetry','','[]','勝境茲辰得重尋，喚人同厲碧溪深。',32,'全唐诗/poet.song.98000.json','["勝境茲辰得重尋，喚人同厲碧溪深。", "兩公未遽嘲糠粃，舊悉山林勇往心。"]'),
('3f6eb73b-dc13-4cd4-994e-16f5d351eb48','題崇蘭館圃  其二','趙子晝','宋','宋诗','song-poetry','','[]','疏食深山謝擊鮮，瓠肥那得此枵然。',32,'全唐诗/poet.song.98000.json','["疏食深山謝擊鮮，瓠肥那得此枵然。", "祇應久絕紛華念，亦笑臞儒不是仙。"]'),
('f4950739-c6e4-420b-999e-cb015b698c58','泛舟鑑湖同程致道趙叔問聯句','趙子泰','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.98000.json','["無正文。"]'),
('21dc4d03-780f-444f-b335-9150563ea1a3','奉詔討范汝爲過寧德西陂訪阮大成','韓世忠','宋','宋诗','song-poetry','','[]','萬頃琉璃到底清，寒光不動海門平。',64,'全唐诗/poet.song.98000.json','["萬頃琉璃到底清，寒光不動海門平。", "鑑開波面一天凈，虹吸潮頭萬里聲。", "吹斷海風漁笛遠，載歸秋月落帆輕。", "芍陂曾上孤舟看，何似今朝雙眼明。"]'),
('d39227cc-7caa-403b-9bea-a0fed96a1585','題雲居壁','韓世忠','宋','宋诗','song-poetry','','[]','芒鞋行杖是生涯，老鬢今年玩物華。',32,'全唐诗/poet.song.98000.json','["芒鞋行杖是生涯，老鬢今年玩物華。", "爲愛雲居松檜好，不須更看牡丹花。"]'),
('a082ef4e-2b9a-48f1-a823-2a64466e3fe4','偈十首  其一','釋道行','宋','宋诗','song-poetry','','[]','動則萬丈懸崖，不動則當處沈埋。',43,'全唐诗/poet.song.98000.json','["動則萬丈懸崖，不動則當處沈埋。", "千重萬重關鎖，一鎚當面擊開。", "伎死禪和無數，依前似鴨聞雷。"]'),
('3794c783-b8c4-42eb-afde-6f25761c5b73','偈十首  其二','釋道行','宋','宋诗','song-poetry','','[]','車不橫推，理無曲斷。',20,'全唐诗/poet.song.98000.json','["車不橫推，理無曲斷。", "若是此花，佛與帝釋。"]'),
('0cb60ad3-72ce-4819-910a-2a7f89ac8adc','偈十首  其三','釋道行','宋','宋诗','song-poetry','','[]','正宗法眼，歷古昭彰。',54,'全唐诗/poet.song.98000.json','["正宗法眼，歷古昭彰。", "大因因緣，此時成現。", "迅機掣電處密密綿綿，綿綿密密中迅機掣電。", "更問如之若何，我面何殊佛面。"]'),
('bd009fa7-0a2a-4f2c-91ab-092dddf96011','偈十首  其四','釋道行','宋','宋诗','song-poetry','','[]','金烏急，玉兔速，天上星兮地下要。',46,'全唐诗/poet.song.98000.json','["金烏急，玉兔速，天上星兮地下要。", "衲僧要透祖師關，勸君拈卻面前大案山，自然會得五祖把火入牛欄。"]'),
('791f78d4-b3ab-4d1e-a17d-002a69ad2021','偈十首  其五','釋道行','宋','宋诗','song-poetry','','[]','一不成，二不是。',26,'全唐诗/poet.song.98000.json','["一不成，二不是。", "三不定，四不可。", "拗折弓箭，踏翻射垛。"]'),
('259da7a5-1957-406f-9a55-37a1619d1ca1','偈十首  其六','釋道行','宋','宋诗','song-poetry','','[]','狗子佛性無，韶石不相辜。',24,'全唐诗/poet.song.98000.json','["狗子佛性無，韶石不相辜。", "爲君重決破，秋至雁銜蘆。"]'),
('8f6155bc-bdba-4865-8a57-b09c787a8739','偈十首  其七','釋道行','宋','宋诗','song-poetry','','[]','門前石塔子，八白與九紫。',24,'全唐诗/poet.song.98000.json','["門前石塔子，八白與九紫。", "方道既分明，免被巡官使。"]'),
('4bd7411d-e575-41c2-94de-326e1f32d400','偈十首  其八','釋道行','宋','宋诗','song-poetry','','[]','從上宗門事，直是少時輩。',57,'全唐诗/poet.song.98000.json','["從上宗門事，直是少時輩。", "兔子不喫窼邊草，象王走入野狐隊。", "若是少林禪，達磨自不會。", "爲甚如此，苦瓠苦連根，甜苽甜徹蒂。"]'),
('61bb341d-1f59-4eae-adc8-d48403826334','偈十首  其九','釋道行','宋','宋诗','song-poetry','','[]','問問不差，答答不錯。',20,'全唐诗/poet.song.98000.json','["問問不差，答答不錯。", "問答去來，龜毛兔角。"]'),
('897391f3-33a5-46a3-8a21-33222744e767','偈十首  其一○','釋道行','宋','宋诗','song-poetry','','[]','依經解義，三世佛冤。',20,'全唐诗/poet.song.98000.json','["依經解義，三世佛冤。", "離經一字，即同魔說。"]'),
('fb53a601-eac3-42ce-9c0e-6e1980257c7d','頌古三首  其一','釋道行','宋','宋诗','song-poetry','','[]','紫羅抹額繡腰裙，傾國風流宛勝秦。',32,'全唐诗/poet.song.98000.json','["紫羅抹額繡腰裙，傾國風流宛勝秦。", "玉笛插藏人不見，夜深吹起鳳樓春。"]'),
('dd88e2e8-e5d2-43a5-a0a7-0fa22c41586f','頌古三首  其二','釋道行','宋','宋诗','song-poetry','','[]','不於三界現身意，誰謂維摩談不二。',32,'全唐诗/poet.song.98000.json','["不於三界現身意，誰謂維摩談不二。", "山空晝永鳥無聲，春光不在千花裏。"]'),
('f0b9e104-e393-4673-8494-09705b44e62d','頌古三首  其三','釋道行','宋','宋诗','song-poetry','','[]','白雲山出復山沒，寒澗日西還日東。',32,'全唐诗/poet.song.98000.json','["白雲山出復山沒，寒澗日西還日東。", "長老不歸予又去，唯留蘿月與松風。"]'),
('f0b33630-aaff-4ef2-9ada-e629f0cc9b47','頌二首  其一','釋道行','宋','宋诗','song-poetry','','[]','我不會兮不如你，達磨當門缺兩齒。',32,'全唐诗/poet.song.98000.json','["我不會兮不如你，達磨當門缺兩齒。", "滿堂無限白蘋風，明明不自秋江起。"]'),
('f438c9eb-0de0-4276-bbea-5386e18f8aab','頌二首  其二','釋道行','宋','宋诗','song-poetry','','[]','我不會兮不如你，堪笑千花生碓觜。',32,'全唐诗/poet.song.98000.json','["我不會兮不如你，堪笑千花生碓觜。", "善財謾說百城游，何曾踏着自家底。"]'),
('4cb80c17-3d95-44c5-8356-4afda0c1e08e','偈一首','釋道行','宋','宋诗','song-poetry','','[]','溪聲廣長舌，山色清凈身。',24,'全唐诗/poet.song.98000.json','["溪聲廣長舌，山色清凈身。", "八萬四千偈，明明舉似人。"]'),
('5a34d06a-13d3-4b7f-a6bc-75d55b6cef82','偈五首  其一','釋道行','宋','宋诗','song-poetry','','[]','會即便會，玉本無暇。',48,'全唐诗/poet.song.98000.json','["會即便會，玉本無暇。", "若言不會，碓觜生花。", "試問九年面壁，何如大會拈華。", "南明恁麽商確，也是順風潵沙。"]'),
('a87f1e5e-da1f-4115-8a6f-7f62e11c4f48','偈五首  其二','釋道行','宋','宋诗','song-poetry','','[]','雲籠嶽頂，百鳥無聲。',66,'全唐诗/poet.song.98000.json','["雲籠嶽頂，百鳥無聲。", "月隱寒潭，龍珠自耀。", "直得石梁忽然大悟，石洞頓爾心休。", "虛空開口作證，溪北石僧點頭。", "諸人總在這裏瞌睡，笑殺陝府鐵牛。"]'),
('e4d658da-3f1f-48fd-8c50-8855626f1a39','偈五首  其三','釋道行','宋','宋诗','song-poetry','','[]','通身是口，說得一半。',75,'全唐诗/poet.song.98000.json','["通身是口，說得一半。", "通身是眼，用得一橛。", "用不到處說有餘，說不到處用無盡。", "所以道，當用無說，當說無用。", "用說同時，用說不同時。", "諸人若也擬議，西峰在你腳底。"]'),
('880d93c6-44ce-4f48-a30c-5186bfbe3142','偈五首  其四','釋道行','宋','宋诗','song-poetry','','[]','句亦剗，意亦剗，絕毫絕釐處，如山如嶽。',38,'全唐诗/poet.song.98000.json','["句亦剗，意亦剗，絕毫絕釐處，如山如嶽。", "句亦到，意亦到，如山如嶽處，絕毫絕釐。"]'),
('b02ec8fe-bde0-46a8-8a72-fa0e10e877f0','偈五首  其五','釋道行','宋','宋诗','song-poetry','','[]','黄梅雨，麥秋寒。',32,'全唐诗/poet.song.98000.json','["黄梅雨，麥秋寒。", "恁麽會，太無端。", "時節因緣佛性義，大都須是髑髏乾。"]'),
('b5ffbac4-24de-47ed-9ef3-c9ad34d60a23','臨終偈','釋道行','宋','宋诗','song-poetry','','[]','識則識自本心，見則見自本性。',28,'全唐诗/poet.song.98000.json','["識則識自本心，見則見自本性。", "識得本心本性，正是宗門大病。"]'),
('8666cc7f-6bd3-4d8f-9893-b7b4bbbe1d81','頌古五首  其一','釋道行','宋','宋诗','song-poetry','','[]','西天屠子氣雄豪，欺負神洲罪莫逃。',32,'全唐诗/poet.song.98000.json','["西天屠子氣雄豪，欺負神洲罪莫逃。", "武帝當頭輕一拶，果然提起活人刀。"]'),
('9c8c9634-2105-4667-b0d7-fcc0b11d9e88','頌古五首  其二','釋道行','宋','宋诗','song-poetry','','[]','不是風幡動，天生李老君。',24,'全唐诗/poet.song.98000.json','["不是風幡動，天生李老君。", "出胎頭上髪，寸寸白如銀。"]'),
('40404d67-0e07-41d3-85e2-fccb4e06f91f','頌古五首  其三','釋道行','宋','宋诗','song-poetry','','[]','一語離窼窟，千生出蓋纏。',24,'全唐诗/poet.song.98000.json','["一語離窼窟，千生出蓋纏。", "夜來風雪惡，木折古巖前。"]'),
('00e25d54-4a22-4d4b-98fc-ece4096e6a31','頌古五首  其四','釋道行','宋','宋诗','song-poetry','','[]','金不博金，水上洗水。',24,'全唐诗/poet.song.98000.json','["金不博金，水上洗水。", "二祖腦後露腮，達磨當門無齒。"]'),
('2a4b8fef-38c0-478f-89b8-3167e70d4a51','頌古五首  其五','釋道行','宋','宋诗','song-poetry','','[]','生死自憐同室穴，因何中路隔關山。',32,'全唐诗/poet.song.98000.json','["生死自憐同室穴，因何中路隔關山。", "一朝忽得親兒證，趯踏方知蓋覆難。"]'),
('c9a79280-e3fb-4dd6-9def-d3a8ec54497c','贈禪者','釋道行','宋','宋诗','song-poetry','','[]','句下出諸礙，翻身古劍寒。',24,'全唐诗/poet.song.98000.json','["句下出諸礙，翻身古劍寒。", "欲明如上事，須是髑髏乾。"]'),
('a0d03573-a1da-4e96-984c-ab2dee7e1d92','贊佛眼和尚','釋道行','宋','宋诗','song-poetry','','[]','因我得禮你，玄沙出窼臼，龍門與薦燈後。',22,'全唐诗/poet.song.98000.json','["因我得禮你，玄沙出窼臼，龍門與薦燈後。", "咄！。"]'),
('c07213aa-807d-42e5-9d85-080569812706','頌古十七首  其一','釋道行','宋','宋诗','song-poetry','','[]','枯樹雲充葉，凋梅雪作花。',34,'全唐诗/poet.song.98000.json','["枯樹雲充葉，凋梅雪作花。", "擊桐成木響，蘸雪喫冬瓜。", "長天秋水，孤鶩落霞。"]'),
('f1881170-660e-4d11-bff3-2c194b876331','頌古十七首  其二','釋道行','宋','宋诗','song-poetry','','[]','落葉歸根，鐵牛當路。',36,'全唐诗/poet.song.98000.json','["落葉歸根，鐵牛當路。", "來時無口，索鹽得醋。", "金槌不動落群機，列聖叢中第六祖。"]'),
('d681426f-cad1-474a-8b53-72e964baf3d7','頌古十七首  其三','釋道行','宋','宋诗','song-poetry','','[]','用盡自己心，笑破他人口。',28,'全唐诗/poet.song.98000.json','["用盡自己心，笑破他人口。", "八角磨盤空裏走，金毛師子變作狗。"]'),
('ff681925-f60a-4959-9ea0-8d26f3575bd7','頌古十七首  其四','釋道行','宋','宋诗','song-poetry','','[]','趙州庭前柏樹子，崑崙眼睛如點漆。',32,'全唐诗/poet.song.98000.json','["趙州庭前柏樹子，崑崙眼睛如點漆。", "笑他法眼謗先師，覺公心苦口如蜜。"]'),
('c6a6f31c-c499-47bd-a92e-501a40ac3f79','頌古十七首  其五','釋道行','宋','宋诗','song-poetry','','[]','不立孤危機本峻，趙州老子玉無瑕。',32,'全唐诗/poet.song.98000.json','["不立孤危機本峻，趙州老子玉無瑕。", "當頭指出殿裏底，剗盡茫茫眼裏花。"]'),
('65b181c5-fcbd-4124-92e6-c9984bd0f98b','頌古十七首  其六','釋道行','宋','宋诗','song-poetry','','[]','趙州放下著，碓觜忽生花。',24,'全唐诗/poet.song.98000.json','["趙州放下著，碓觜忽生花。", "雖然無一事，驗盡當行家。"]'),
('7b5dd743-a9df-4437-ad69-b042fac631bd','頌古十七首  其七','釋道行','宋','宋诗','song-poetry','','[]','土埋處處鐵菱角，半夜經由未覺難。',32,'全唐诗/poet.song.98000.json','["土埋處處鐵菱角，半夜經由未覺難。", "於曉嶺根傷中倒，方知行過鐵門關。"]'),
('3caf2ea0-d4bf-4af5-8051-bf4d2656117f','頌古十七首  其八','釋道行','宋','宋诗','song-poetry','','[]','蒼龍带雨離深洞，彩鳳啣花入帝關。',32,'全唐诗/poet.song.98000.json','["蒼龍带雨離深洞，彩鳳啣花入帝關。", "一句古今無滲漏，祖師不在東西山。"]'),
('36794bff-4d6b-4252-abc3-b931cc206626','頌古十七首  其九','釋道行','宋','宋诗','song-poetry','','[]','天生白額南山虎，牙爪曾當八面風。',32,'全唐诗/poet.song.98000.json','["天生白額南山虎，牙爪曾當八面風。", "月落三更穿市過，癡人投曉覓行蹤。"]'),
('2a3fee27-fbe5-4e61-8052-294490866e52','頌古十七首  其一○','釋道行','宋','宋诗','song-poetry','','[]','因我得禮你，崑崙臥潭底。',24,'全唐诗/poet.song.98000.json','["因我得禮你，崑崙臥潭底。", "雖然浪拍天，身上無滴水。"]'),
('f37dad24-c423-46fb-9650-55d3157d310d','頌古十七首  其一一','釋道行','宋','宋诗','song-poetry','','[]','新年佛法晢真風，笑殺街頭賀歲翁。',32,'全唐诗/poet.song.98000.json','["新年佛法晢真風，笑殺街頭賀歲翁。", "三級浪高何處去，謾將雙劍定雌雄。"]'),
('ec9918ae-57a8-403f-ad47-0309cd80b5d3','頌古十七首  其一二','釋道行','宋','宋诗','song-poetry','','[]','古人一莫，切忌啗啄。',48,'全唐诗/poet.song.98000.json','["古人一莫，切忌啗啄。", "臨濟權寄庫，德山頓蕭索。", "截斷佛祖機關，顯出頂門一著。", "子細審思量，分明欠一著。"]'),
('1e41727f-1e0f-4f55-bac5-1463140f8d2a','頌古十七首  其一三','釋道行','宋','宋诗','song-poetry','','[]','棒下血淋淋，真鍮不博金。',24,'全唐诗/poet.song.98000.json','["棒下血淋淋，真鍮不博金。", "鴛鴦親繡出，休更覓金針。"]'),
('d992134e-bb4a-429f-b6fb-ac4b66088f1f','頌古十七首  其一四','釋道行','宋','宋诗','song-poetry','','[]','如何是佛，口是禍門。',20,'全唐诗/poet.song.98000.json','["如何是佛，口是禍門。", "一錢不直，賣與買人。"]'),
('af26edc8-0f00-4a95-ba40-b15fa8b5731e','頌古十七首  其一五','釋道行','宋','宋诗','song-poetry','','[]','門前石塔子，八白與九紫。',24,'全唐诗/poet.song.98000.json','["門前石塔子，八白與九紫。", "方道既分明，免被巡官使。"]'),
('caa08435-296b-470e-9ec2-e3c17602d88f','頌古十七首  其一六','釋道行','宋','宋诗','song-poetry','','[]','堂堂白日上刀梯，任是崑崙眼亦迷。',32,'全唐诗/poet.song.98000.json','["堂堂白日上刀梯，任是崑崙眼亦迷。", "多謝門前案山子，春來秋去泄天機。"]'),
('2c0f1f2f-dff7-4541-bb69-6550a677f1de','頌古十七首  其一七','釋道行','宋','宋诗','song-poetry','','[]','江南江北勿同倫，疑了還疑笑殺人。',32,'全唐诗/poet.song.98000.json','["江南江北勿同倫，疑了還疑笑殺人。", "誰信一盤油煠底，古今塞斷是非門。"]'),
('d82861d4-2700-4755-9dea-e29a28a893f8','次韻學士兄發毘陵之作','李彌遜','宋','宋诗','song-poetry','','[]','頻年走離亂，忙苦落落景。',204,'全唐诗/poet.song.98000.json','["頻年走離亂，忙苦落落景。", "浮家去復還，生理紛不整。", "有身著無處，遇事到輒屏。", "冥然如醉心，閲歲良未醒。", "披衣坐愁夜，月露共清永。", "緬懷顔段流，抱義心炯炯。", "臨危快先登，疾甚涉夷境。", "全生豈不樂，王事有綱領。", "嗟今肉食謀，捕賊如捕影。", "王師苦摧傷，敵騎困馳騁。", "朝廷信多賢，一死誰敢請。", "不知覆轍改，安敢傾夏拯。", "歸休及秋風，墓檟痛瞻省。", "念兹家國遙，有淚漲清潁。", "黄巾蔽行路，關戶晝猶警。", "何當收戈鋋，禁暴但制梃。", "林泉倘可卜，名字忌丹柄。"]'),
('9b6c1095-c37a-4443-9a2b-aea3d116ee40','自毘陵與兄弟避地南來約爲連江之歸中塗各以事留遂成獨往念茲離亂易於隔絕作詩以寄之','李彌遜','宋','宋诗','song-poetry','','[]','胡塵暗中原，大駕巡江都。',288,'全唐诗/poet.song.98000.json','["胡塵暗中原，大駕巡江都。", "春風遂南渡，百辟咸奔趨。", "衣冠困陵暴，川陸紛舟輿。", "微生本萍寄，寧復安吾廬。", "褰裳犯深險，顛仆妻與孥。", "懷恩痛未報，無路先貔貙。", "巖穴多遺賢，天網固亦疏。", "驊騮懼捐弃，未數十駕駑。", "銜悲望君門，忍作永訣圖。", "扁舟兄及弟，去指東海隅。", "夜榜亞修舳，曉帆趁横蒲。", "如何忽參商，行止分半途。", "怡怡風月夕，來若同隊魚。", "慘慘霜露秋，去如獨翔鳬。", "歲晏道路長，隻影誰與俱。", "但憂赤眉間，能致黄耳無。", "青燈攪寒夢，起坐中腸枯。", "載歌鶺鴒詩，引淚零襟裾。", "閩山我舊國，下隱同姓居。", "潮田歲再穫，海錯日兩漁。", "荔子擘絳縠，江瑤截冰膚。", "家家潑春釀，取醉不待沽。", "木落終糞本，兹言紳可書。", "悲心久更微，正坐簪紱拘。"]'),
('3784786c-e51f-4bb5-a342-ad2153f3ac56','次韻王得之禮部夜直有作','李彌遜','宋','宋诗','song-poetry','','[]','緱仙勇於詩，若醉得全者。',132,'全唐诗/poet.song.98000.json','["緱仙勇於詩，若醉得全者。", "百川供微吟，不復事杯斚。", "五車載胸中，萬卷生筆下。", "一一成丹青，遇物輒圖寫。", "昨朝紫宸班，裳珮雜魚雅。", "捷書來九天，爲遣雨師灑。", "公時青綾臥，逸思動秋野。", "霜風助凄清，露月供容冶。", "坐令續貂人，得語若乖寡。", "猶如策疲駑，倒步逐風馬。", "未施歷塊功，相望倚天社。"]'),
('410fa49e-aeb7-4cb3-9a11-5e89bab9b711','與同館晝會王公衡家分韻得瓜字','李彌遜','宋','宋诗','song-poetry','','[]','秋曦上觀闕，晨騶散蜂衙。',120,'全唐诗/poet.song.98000.json','["秋曦上觀闕，晨騶散蜂衙。", "追隨我輩人，偶到蓬萊家。", "主人心遠塵，門無車馬譁。", "峰巒生几棐，圖書亂籖牙。", "午簟琅玕清，蓴甌荐流霞。", "坐令秋風思，悠悠起天涯。", "微官浪自縛，霜蔓縈寒瓜。", "愛子庭宇靜，同官謝紛華。", "寓意語成劇，忘機慮乃賒。", "得酒且復盡，昏林欲藏鴉。"]'),
('fde5fc8d-090b-4a3f-80e7-090cf4e842cb','同天隱少章遊嵩少懷元明','李彌遜','宋','宋诗','song-poetry','','[]','秦公我輩士，早踏翰墨場。',240,'全唐诗/poet.song.98000.json','["秦公我輩士，早踏翰墨場。", "萬言若投石，十年猶枯嚢。", "若欲泛江海，有親在高堂。", "牢落京華春，門無一壺漿。", "長鞭策瘦馬，送我古道旁。", "憐我值險艱，赤心寫摧傷。", "鏗鏘五字句，勢與鵰鶚翔。", "感此坐矯首，星星鬢成蒼。", "西風小搖落，雨洗烟嵐光。", "嶂曉露孤秀，野陰棲暗芳。", "更攜鮑謝流，履盡千巖霜。", "搜奇得幽深，訪古到渺茫。", "月落潭影空，清吟殊未央。", "緬懷紫芝宇，百憂繞迴腸。", "三嘆已晡食，十起中夜牀。", "雲埋長安日，魂夢不敢驤。", "茂苑富山水，結廬予所嘗。", "我欲放船下，卜鄰俯滄浪。", "耦耕種林田，共掃三徑荒。", "頭白青山裏，長歌樂歲觴。"]'),
('fa03f0fc-50ea-4c7f-9d84-d61160bb1655','五石 群玉峰','李彌遜','宋','宋诗','song-poetry','','[]','五城十二樓，高下聳寒玉。',48,'全唐诗/poet.song.98000.json','["五城十二樓，高下聳寒玉。", "天空開翠微，不受塵土觸。", "半生嗟環轅，萬事驚轉轂。", "寄語山中人，爲占一峰綠。"]'),
('b40c38aa-cfcd-4977-9a6b-4cb2aa16a12d','五石 水月巖','李彌遜','宋','宋诗','song-poetry','','[]','明泉落巖隈，滿月掛山額。',48,'全唐诗/poet.song.98000.json','["明泉落巖隈，滿月掛山額。", "疏星淡月漢，下與水光白。", "了然心境空，炯炯照瓊宅。", "鴻鳴夜更清，欲臥已終夕。"]'),
('a458db2c-fced-4737-be5e-d0c343d0d786','五石 遙岑','李彌遜','宋','宋诗','song-poetry','','[]','宿雨洗空闊，出此方寸岑。',48,'全唐诗/poet.song.98000.json','["宿雨洗空闊，出此方寸岑。", "聯綿翠光浮，妙巧不可尋。", "飛雲去未返，慰我千里心。", "誰爲具徽絃，有酒聊自斟。"]'),
('739a9b98-6ab0-4efe-8675-c4a6167406e7','五石 碧澗','李彌遜','宋','宋诗','song-poetry','','[]','蒼崖高鬰盤，下有千仞傾。',48,'全唐诗/poet.song.98000.json','["蒼崖高鬰盤，下有千仞傾。", "當時捐珮侣，寄此琤琮聲。", "坐石風露晚，心與秋月明。", "滄浪若可濯，勿負冠上纓。"]'),
('108082f1-3226-452b-bd6f-673e8bbafcf3','五石 陰壑','李彌遜','宋','宋诗','song-poetry','','[]','春山秋亦佳，霜樹風更落。',48,'全唐诗/poet.song.98000.json','["春山秋亦佳，霜樹風更落。", "陰晴卷復舒，氣象今非昨。", "功名等浮雲，文字懸高閣。", "賸掃胸中奇，還將貯丘壑。"]'),
('a1c4e474-dd27-425c-93b7-9898b7bd8822','贈浮光王教授','李彌遜','宋','宋诗','song-poetry','','[]','剝啄誰氏子，清晨過寒院。',240,'全唐诗/poet.song.98000.json','["剝啄誰氏子，清晨過寒院。", "瞭然雙瞳光，偶坐肆雄辨。", "自言同川裔，世列金閨彦。", "聲名重青錢，文字妙黄絹。", "插架三萬軸，撐腸五千卷。", "八十朝明光，好語動天眷。", "遺芳落諸孫，往往嗜經傳。", "我獨甘悲辛，敢負籯金彥。", "藏刀十九年，收霸在一戰。", "猶紆從事衫，局促類秋燕。", "翻思訪梅福，不待買陽羨。", "鏗鏘七言贈，字字經鍛鍊。", "愛之忍去手，喁噞日千轉。", "黄鐘未雷鳴，羞比釡與甗。", "璠璵入磨琢，會作清廟獻。", "待價古或然，毁櫝聖所唁。", "明良羅雋英，不命速邦傳。", "胡爲有遐心，賸起林壑戀。", "青冥閶闔開，駃足謝媒援。", "願持北闕書，自效唐衢薦。"]'),
('3da138cd-b996-4e22-9b3b-b6b1b6fa19ff','和何斯舉戒食牛','李彌遜','宋','宋诗','song-poetry','','[]','饑腸慕羶腥，如渇待拾汁。',156,'全唐诗/poet.song.98000.json','["饑腸慕羶腥，如渇待拾汁。", "雖窮爪掌勞，不助唇吻濕。", "屬厭能幾何，忍復貴難得。", "三犧良可哀，一割倘未急。", "貪夫恣糜爛，梁稻委鵝鴨。", "鸞刀久紛綸，餘胾猶在羃。", "寧思百畝間，功大等黔赤。", "翻令雜雞豚，就死不見白。", "置食爲三嘆，起坐或忘幘。", "若人妙箴規，隱惻鬼神泣。", "由儀見古風，未使斯文缺。", "藥石知良醫，樂餌止過客。", "仁言可紳書，善應知響集。"]'),
('c69a8862-8fca-4dcd-9bf2-cdffbb15b746','淮陰遇風雨','李彌遜','宋','宋诗','song-poetry','','[]','吾廬豈不好，白日苦易夕。',120,'全唐诗/poet.song.98000.json','["吾廬豈不好，白日苦易夕。", "如何芳歲闌，尚此千里役。", "乾坤一虚舟，浩蕩楚天碧。", "江山已在眼，道路修且隔。", "風雨怕不休，波浪蹴天擲。", "船頭困九牛，屢挽不進尺。", "人生造化間，有似風中翮。", "偶去還復來，胡爲事形迹。", "杜陵誅雲師，韓子詛風伯。", "我已兩忘言，引觴聊自適。"]'),
('4edadfbb-a373-4ede-a738-182a59c22784','宿揚州城外','李彌遜','宋','宋诗','song-poetry','','[]','舟横城郭繞，缺月疏林杪。',48,'全唐诗/poet.song.98000.json','["舟横城郭繞，缺月疏林杪。", "窈窕一溪深，微茫衆星小。", "忘言對詩書，適意親魚鳥。", "幸此絕紛華，行歌閲昏曉。"]'),
('25841015-fd2a-415a-ad00-4624f05602d3','承天寺','李彌遜','宋','宋诗','song-poetry','','[]','宿雨洗蒼骨，峰巒發新秀。',144,'全唐诗/poet.song.98000.json','["宿雨洗蒼骨，峰巒發新秀。", "尋幽躡奇蹤，騰踏衆山囿。", "層林鎖巖隈，突兀見危構。", "空高望浮黎，靜聖逼靈鷲。", "我來風雨秋，白霧欲昏晝。", "但聞百川赴，鳴玉瀉寒竇。", "岳示閟嶫峨，路絕不得簉。", "扳緣仰脇息，坐右俯長溜。", "带露摘山芎，披榛覓仙酎。", "山光晚逾清，雲壑若相授。", "終期爛漫遊，陽烏欲回咮。", "更約十日留，曾子緩蹄輳。"]'),
('98b58421-0776-45df-94e2-bcab11204784','法王東庵','李彌遜','宋','宋诗','song-poetry','','[]','吾宗丘壑資，耿耿抱幽獨。',96,'全唐诗/poet.song.98000.json','["吾宗丘壑資，耿耿抱幽獨。", "結構祗洹家，縈回轉巖腹。", "前川布黄金，合嶂來蒼玉。", "步出覺華天，乘凌眩生目。", "雲間起層林，林際懸高屋。", "斷砌滴疏泉，微蹤隱深麓。", "堂空貝葉昏，苔封半階綠。", "朱幡久不來，哀猿響秋谷。"]'),
('76231cec-42e0-4a9d-827b-95d3a7467d07','五峰寺','李彌遜','宋','宋诗','song-poetry','','[]','五峰如五城，草樹皆秀發。',48,'全唐诗/poet.song.98000.json','["五峰如五城，草樹皆秀發。", "人間白玉京，此土黄金刹。", "長松蔭步武，目改心已雪。", "稅鞅罷言歸，前山寫薇蕨。"]'),
('9905d0bd-325e-4198-b667-91e48cd0a0f0','碧霄泉','李彌遜','宋','宋诗','song-poetry','','[]','山根出清泉，云自九天落。',48,'全唐诗/poet.song.98000.json','["山根出清泉，云自九天落。", "風潮带江腥，天黑魚龍泊。", "何當寸雲敷，一灑徧寥廓。", "滄浪勿復歌，吾纓久已濯。"]'),
('dbb71c2e-ce1a-4cc8-85d0-5b0c186df07b','杯渡塔','李彌遜','宋','宋诗','song-poetry','','[]','青松轉路頭，白塔枕山肋。',48,'全唐诗/poet.song.98000.json','["青松轉路頭，白塔枕山肋。", "錫飛歸上方，杯渡空塵跡。", "真源不可取，香火供晨夕。", "客至亦忘言，荒庭秋草積。"]'),
('c6d8a17b-4a38-4b59-8813-87a889bc6e22','秋居雜詠  其一','李彌遜','宋','宋诗','song-poetry','','[]','久懷簡書畏，幸解紳笏束。',72,'全唐诗/poet.song.98000.json','["久懷簡書畏，幸解紳笏束。", "忘年効兒女，適意揮僮僕。", "植杖理新蕉，埋盆養寒菊。", "前除馴鵲烏，近檻遊麋鹿。", "遐觀時倚楹，瞑坐或忘燭。", "門闌迹如掃，我亦甘幽獨。"]'),
('c8836d38-e1a1-419a-92ff-45031a03cc0f','秋居雜詠  其二','李彌遜','宋','宋诗','song-poetry','','[]','薿薿庭前林，離離夾中道。',72,'全唐诗/poet.song.98000.json','["薿薿庭前林，離離夾中道。", "靈柯結繁陰，顔色四時好。", "豈無霜雪侵，不改凌雲操。", "緬懷壯士心，雅契幽人抱。", "如何方寸搖，懸若風中纛。", "吾廬偶與鄰，聊擬七松號。"]'),
('d4fca2ab-0c2b-4e7e-83cc-5e14f0689f57','秋居雜詠  其三','李彌遜','宋','宋诗','song-poetry','','[]','青春背我去，白日不吾謀。',72,'全唐诗/poet.song.98000.json','["青春背我去，白日不吾謀。", "霜飈驚草木，寒威戒衣裘。", "寓形復幾時，四序忽一周。", "世路伏劍戟，中懷孕螟蟊。", "營營事長久，頽齡如置郵。", "丘園倘未卜，悟悅心自休。"]'),
('e0e20c8f-5d3d-4417-b40e-2ead0672a780','秋居雜詠  其四','李彌遜','宋','宋诗','song-poetry','','[]','窮秋雜花遠，眷此霜下傑。',72,'全唐诗/poet.song.98000.json','["窮秋雜花遠，眷此霜下傑。", "明金委珞瓔，寶璐綴環玦。", "依依風遞蘭，皓皓日穿雪。", "若無夭冶姿，不受衆目悅。", "共杯泛其英，攬之腸爲結。", "誰能踵高門，持以浣中熱。"]'),
('6a6838d8-8682-4486-bc8a-74b23b6ba031','秋居雜詠  其五','李彌遜','宋','宋诗','song-poetry','','[]','出門泥活活，不聞車馬喧。',72,'全唐诗/poet.song.98000.json','["出門泥活活，不聞車馬喧。", "一身謝羈絆，百事從弃捐。", "坐曠非息慮，逃空遂忘言。", "青燈有餘燼，妙香無續烟。", "涓涓簷間霤，獵獵窗上鳶。", "夫物具成禮，胡爲尚求筌。"]'),
('d57532dd-568f-4153-b7f2-bd5c1ad3ff7b','秋居雜詠  其六','李彌遜','宋','宋诗','song-poetry','','[]','顒顒集癯仙，娟娟羅靜女。',72,'全唐诗/poet.song.98000.json','["顒顒集癯仙，娟娟羅靜女。", "孤標與秀色，翛然出環堵。", "我來三二月，離立僅成伍。", "及秋新梢敷，接葉庇風雨。", "一日不可無，幸兹共寒暑。", "高枝有垂賞，鳴鳯在何許。"]'),
('dd01c26f-821b-4a2b-9b05-a808ec845d30','秋居雜詠  其七','李彌遜','宋','宋诗','song-poetry','','[]','駕言出城闕，行行陟崇山。',72,'全唐诗/poet.song.98000.json','["駕言出城闕，行行陟崇山。", "舒懷到昭曠，未覺天地寬。", "鴥彼離群雁，嘹嘹浮雲端。", "嗟我遠兄弟，千里同歲寒。", "舉頭不見日，况復遠長安。", "歸飛胡不早，聽此彫朱顔。"]'),
('080f32f2-c571-4f82-931c-032d84ae9282','秋居雜詠  其八','李彌遜','宋','宋诗','song-poetry','','[]','茅茨八九椽，中有插架軸。',72,'全唐诗/poet.song.98000.json','["茅茨八九椽，中有插架軸。", "琅函與貝葉，落落皆在目。", "閑依浄几繙，緩繞疏篁讀。", "困即抱之眠，擁鼾寧厭熟。", "不知老將至，一時肯載腹。", "此樂殊未央，吾生亦云足。"]'),
('ae1c33a7-f231-440c-9339-1a995c822b70','秋居雜詠  其九','李彌遜','宋','宋诗','song-poetry','','[]','公園十畝餘，日陟亦成趣。',72,'全唐诗/poet.song.98000.json','["公園十畝餘，日陟亦成趣。", "浮陰未全收，晴沙已勝步。", "杖藜相與行，童稚雜冠履。", "枯魚泳微瀾，悴菊飲晞露。", "欣物各有時，撫懷偶軒慮。", "安得三徑餘，誅茅種瓜芋。"]'),
('128670b4-81a9-4a91-b448-20ed9ae4873d','秋居雜詠  其一○','李彌遜','宋','宋诗','song-poetry','','[]','凝雲吐秋曦，翳目眩晴晝。',72,'全唐诗/poet.song.98000.json','["凝雲吐秋曦，翳目眩晴晝。", "扶行憩高堂，恍若歷辰宿。", "清涵城角池，碧聳林端岫。", "微茫縱遐瞻，佳處時一覯。", "冷風生襟裾，俯仰小宇宙。", "何必如雲翮，超然追禦寇。"]'),
('60650a73-76d5-49d6-8760-8b64070e71c2','春日種菊東籬顧叢蘭衰謝欲棄之因取以植牆下','李彌遜','宋','宋诗','song-poetry','','[]','天公善轉物，剪爪不停軫。',240,'全唐诗/poet.song.98000.json','["天公善轉物，剪爪不停軫。", "春工未削迹，秋事已張本。", "檀欒嘉菊叢，戢戢露奇藴。", "枝分要及時，手植須著緊。", "清晨東籬下，畚插自畦畛。", "土膏入新萌，秀色來袞袞。", "歸休顧衰蘭，面目吁可憫。", "兒童互撏拏，奴僕恣嘲哂。", "敢望群蕭艾，棄置等朝菌。", "即之粹而温，忍死子不愠。", "山翁飽經事，遇物輒思忖。", "理得心亦欣，爲發一笑劙。", "向來芳深林，孤潔玉在韞。", "知音苦不多，况此香色隕。", "紉佩倘未遂，焚膏真可忍。", "爬梳牆角陰，樹之羅九畹。", "好風動融怡，新雨洗寒窘。", "未甘五柳獨，聊釋三閭憤。", "炎涼循若環，榮謝平可凖。", "春風行復來，萬彙發幽隱。"]'),
('9092e9aa-5245-4ca8-97a4-ad98a66ab2ff','與羅邵諸公同遊陳氏園分江頭千樹春欲暗得樹字','李彌遜','宋','宋诗','song-poetry','','[]','春風亦世情，去我若馳騖。',144,'全唐诗/poet.song.98000.json','["春風亦世情，去我若馳騖。", "北枝未破粉，斷萼已飄素。", "殷勤南郭綦，邀我整冠履。", "著鞭向晴原，盤傳咄嗟具。", "移樽晚色間，醉入衆香聚。", "花浮承露盤，座繞臨風樹。", "停杯憶昨遊，香色尚深駐。", "重來未旬浹，頓覺心腹露。", "後會雖可期，稍稍迫遲暮。", "酬花了無計，一醉其殆庶。", "如何競剪燭，雕繪覓奇句。", "願當百罰深，肯效黄金注。"]'),
('d1c4be3b-2d2a-466d-9bfc-349038e59a87','雪後詹伯尹周少隱見過置酒次伯尹韻','李彌遜','宋','宋诗','song-poetry','','[]','春雪不禁風，散作六花墮。',84,'全唐诗/poet.song.98000.json','["春雪不禁風，散作六花墮。", "方庭截明玉，純白不可唾。", "枯腸索慳句，喁噞空百過。", "同襟得二妙，敵我愁城破。", "試酌扶龍鍾，重觴念頔鬌。", "西齋尚有氈，庶足供雲臥。", "壁間見三閭，推枕爲賡些。"]'),
('f60af0d3-d529-4ee4-9440-91e009caa200','次韻張嵇仲侍郎','李彌遜','宋','宋诗','song-poetry','','[]','燕公提大筆，萬象入陶冶。',252,'全唐诗/poet.song.98000.json','["燕公提大筆，萬象入陶冶。", "公今真似之，信是渥洼馬。", "當年動天眷，愕睨肉食者。", "珥貂漢廷臣，往往富平下。", "朅來楚江城，百事聊復且。", "傳聞九門開，裳珮翼如也。", "巖廊正需公，料理及閑暇。", "不然坐玉堂，堵立看揮洒。", "胡爲尚居東，一麾凡屢假。", "憶昔從公遊，端門正槐夏。", "午騎聯輕肥，晨班從魚雅。", "頻年江淮臥，隻影未爲寡。", "誰云若遺□，殆甚履中苴。", "相逢屢解榻，得句即邀社。", "重追一笑歡，百憂罷牽惹。", "况陪賦文機，不數分金賈。", "青蒿倚長松，懷抱肯舒寫。", "殘枝到春歸，風燈不留灺。", "世人重虚名，自視輕拱把。", "獨醒竟何事，空負月中斚。", "及茲春尚餘，得酒勿復捨。"]'),
('9cfb0021-7110-4f83-8c11-3b3db1548cb5','和張嵇仲秋日病中見示','李彌遜','宋','宋诗','song-poetry','','[]','浮生一虚舟，流景半修夜。',192,'全唐诗/poet.song.98000.json','["浮生一虚舟，流景半修夜。", "塵勞互牽挽，荏苒柏間麝。", "晚從農圃遊，徑欲老閑暇。", "二年古陵陽，邂逅穎川霸。", "薰然君子風，臥致此邦化。", "公庭散鳬騖，文字雜休假。", "江山助悽惋，句法妙曹謝。", "客來飲以醇，味語兼膾炙。", "長風起百圍，微日下三舍。", "高秋攪羈懷，遊子念歸駕。", "身名兩將隱，焉俟連城價。", "譬之草木姿，榮枯信冬夏。", "公材可支顛，乃復用苴罅。", "天其遣鯨鯢，慰我波濤下。", "忠良人樂推，正直神所迓。", "會看擊南溟，風雲生叱咤。"]'),
('ae5c2ee3-a480-4b7a-97d8-e6fddbb1a6ce','寄題蕪湖韋深道所居二首 寄傲軒','李彌遜','宋','宋诗','song-poetry','','[]','男兒騖功名，浪起四方志。',72,'全唐诗/poet.song.98000.json','["男兒騖功名，浪起四方志。", "轍環百年間，正足消兩髀。", "達人坐進此，妙處不容喙。", "卷舒周古今，俯仰小天地。", "南窗有餘清，松菊爽朝氣。", "豈獨傲世懷，吾生真可寄。"]'),
('8aa88de9-2871-4c91-8954-1c7647e0fc6a','寄題蕪湖韋深道所居二首 獨樂堂','李彌遜','宋','宋诗','song-poetry','','[]','韋郎江海士，心與凡子各。',72,'全唐诗/poet.song.98000.json','["韋郎江海士，心與凡子各。", "折腰卑小官，不事干祿學。", "觀身一牛毛，閲世兩蝸角。", "紛華豈不好，名教自有樂。", "虚堂卷書罷，覓酒供自酌。", "誰云苦幽獨，秋風響猿鶴。"]'),
('d26b50ee-e0bf-4fe4-9822-0bb09498930f','巖巄寺','李彌遜','宋','宋诗','song-poetry','','[]','披榛得深徑，漾楫過陰壑。',72,'全唐诗/poet.song.98000.json','["披榛得深徑，漾楫過陰壑。", "巖開雙牖戶，石立四壁落。", "斕斑旁累丸，空洞中懸櫜。", "誰於崑崙腹，施此混沌鑿。", "潛移蛟黿宫，歘搆佛祖閣。", "世無探穴公，造化終冥漠。"]'),
('8e17940d-3224-4f7d-8044-882ac2eb6686','東峰亭','李彌遜','宋','宋诗','song-poetry','','[]','芒鞋着層丘，甘若臥華屋。',144,'全唐诗/poet.song.98000.json','["芒鞋着層丘，甘若臥華屋。", "了然非夢覺，似是前境熟。", "行行上青冥，下視八荒促。", "回溪綰文練，叠障環群玉。", "廚煙起城隅，遠借晴林綠。", "恍疑坐虚堂，淡墨寫縑幅。", "緬懷季與劉，靜躁等臧穀。", "身名千載後，巖影空遺躅。", "霜林木葉下，悲籟喧寒谷。", "我如凌風翰，不受世網束。", "蒲團白氈帳，清夜倘可卜。", "更隨孤月來，一洗昏衢目。"]'),
('01b889f4-c182-481b-8dbf-24c29859cb26','五松寺','李彌遜','宋','宋诗','song-poetry','','[]','秋風吹客衣，去路倚天碧。',144,'全唐诗/poet.song.98000.json','["秋風吹客衣，去路倚天碧。", "躋扳一何苦，政坐愛山癖。", "人言五松下，曾是瞿曇宅。", "至今梧竹陰，列屋栖禪寂。", "塵纓得暫解，俗駕聊可息。", "怡顔巖間樹，洗耳泉上石。", "孤雲共還往，窈窕去無迹。", "道人粲可流，獨步少林席。", "客來了不言，碧眼照庭柏。", "希聲出鍾梵，妙意生牆壁。", "寒灰暗青燈，偶坐遂終夕。", "歸來人境空，缺月挂山額。"]'),
('6f9d95bf-6853-4ddd-b62b-78bf5251454f','大寧寺','李彌遜','宋','宋诗','song-poetry','','[]','三山覆蒼鼎，一澗走青蛇。',96,'全唐诗/poet.song.98000.json','["三山覆蒼鼎，一澗走青蛇。", "檀巒衆好樹，密護如來家。", "當年契禪人，虎御穿雲霞。", "真蹤久不昧，殿閣峨金沙。", "我來風雨秋，腳踏繽紛華。", "松窗歷高下，石磴緣欹斜。", "境靜心自遠，山窮興徒賒。", "歸轡不可留，哀猿響清笳。"]'),
('71c38895-1e2f-4742-9afb-30a067e73f74','春日同伯氏遊問政山門意似表弟舊題用其韻先是嘗持書招之篇末幷以見意','李彌遜','宋','宋诗','song-poetry','','[]','晴妍入遐瞻，佳處在林樾。',192,'全唐诗/poet.song.98000.json','["晴妍入遐瞻，佳處在林樾。", "歸雲紛卷舒，列岫互明滅。", "偶從青都行，遂與凡境絕。", "輿肩俯清陰，屣齒破苔滑。", "坡陀度崇岡，窈窕閟真闕。", "燼餘見頽基，紙上得遺碣。", "紅白抹花臉，嘲哳掉禽舌。", "傷殘起孤憤，感物動深悦。", "稍羅肴核豐，共弔泉石咽。", "雲冠儼臧護，霓騎想飛越。", "靈蹤尚儲休，爽氣亦時發。", "散花步危壇，引蔓探幽穴。", "胎田倘可丹，石髓未成鉄。", "卻思棠棣篇，已換桃李節。", "雁書當解封，鹿駕定回轍。", "兹遊約重尋，晚笋政堪擷。"]'),
('6a62d092-f6ce-40cb-8fe1-481b1dc5fc0f','宿雲軒','李彌遜','宋','宋诗','song-poetry','','[]','平生念丘壑，著我胸中雲。',60,'全唐诗/poet.song.98000.json','["平生念丘壑，著我胸中雲。", "偶爲山樊居，白雲亂衣巾。", "物類感濕燥，人情異蕕薰。", "奇峰靄朱夏，擘絮浮陽春。", "興來攬之游，要觀塵外身。"]'),
('de0c6836-13d7-4dd1-846f-b6e11e6d95d7','晞陽軒','李彌遜','宋','宋诗','song-poetry','','[]','山高竹柏陰，得之近亭午。',60,'全唐诗/poet.song.98000.json','["山高竹柏陰，得之近亭午。", "兹軒揖朝暾，精色快先覩。", "濛濛勒花春，十日九風雨。", "羲和爲返旆，照我衣上縷。", "眩然九陽遊，誰云在環堵。"]'),
('b909491e-6160-419d-8655-e48898d26809','春日奉陪子安諸公遊石門','李彌遜','宋','宋诗','song-poetry','','[]','提壺喚新晴，病客春思攪。',240,'全唐诗/poet.song.98000.json','["提壺喚新晴，病客春思攪。", "茶甌曲肱罷，聯屐事幽討。", "叩門探繁香，翠蔓花尚少。", "卻攜二三子，深行出飛鳥。", "羊腸走鳴泉，鳯尾搖寒篠。", "俯窺萬井烟，笻聲響林杪。", "湯休真解事，煮餅禪坊悄。", "杯盤生晚澗，落葉風自掃。", "眼明玉華陰，桃枝露紅小。", "更傾樽中餘，邀月下雲表。", "澄江靜可鑑，合嶂青未了。", "石梁接樓居，屋角掛參昴。", "誰知人間世，彷彿見三島。", "烟塵暗中原，懷抱鎮煎煼。", "一行瘴海頭，歲月不知老。", "金蘭有佳士，相見獨不早。", "青蒿得長松，頗亦慰枯槁。", "春風正顛狂，日日被花惱。", "懽來即相覓，真處在草草。", "身名兩姑置，有酒爲君倒。"]'),
('c1dcea45-9696-43e9-bf17-814409abf97b','次韻學士兄春日謾成','李彌遜','宋','宋诗','song-poetry','','[]','飄泊悲生事，人情翻手雲。',48,'全唐诗/poet.song.98000.json','["飄泊悲生事，人情翻手雲。", "習閑真似懶，補拙謾知勤。", "老作漁樵計，夢觀鍾鼎勳。", "成虧皆一戲，不復問斯文。"]'),
('0a5dc281-85df-4f4f-bc2e-0dd8960c60e8','次韻連江陳丞閔雨','李彌遜','宋','宋诗','song-poetry','','[]','春雨兩甲子，夏雨知復多。',120,'全唐诗/poet.song.98000.json','["春雨兩甲子，夏雨知復多。", "麰麥已受弊，波及秫與禾。", "禾秫尚有望，霖霪人告瘥。", "雲師挾風伯，斥去煩撝訶。", "后土不得乾，浸欲乖時和。", "山翁食病粟，一飽寧憂佗。", "軍儲涸鄰國，柰此黔赤何。", "誰爲四達聰，黜陟分兩科。", "陳謨坐臯夔，禦侮用牧頗。", "上當天公心，立致擊壤歌。"]'),
('b4546c06-baed-4c59-bc99-154adc80ec21','次韻陳蹈元種竹池上之什','李彌遜','宋','宋诗','song-poetry','','[]','冶容多嫵媚，勁節自髙尚。',168,'全唐诗/poet.song.98000.json','["冶容多嫵媚，勁節自髙尚。", "絕知尤物美，寧似此君放。", "疏蕖望修竹，凛凛丈人行。", "雖然合九奏，未必遺一唱。", "移根拂雲姿，作伴滿月相。", "客來與周旋，一洗眼中瘴。", "烝哉太丘徒，風味晋人上。", "五言落凡目，失喜狂欲恙。", "渭川植千畝，玉井開十丈。", "幷吞羅心胸，出語還自狀。", "我窮海濱臥，局促隱霧瘴。", "遠公有佳招，子猷得真養。", "風庭散鳬鶩，倘許共清曠。", "茗盌煩屢移，早秫行可釀。"]'),
('3e2afe69-1a05-4c08-bdf2-14f89d71341f','石門竹生巖下拳曲無取衆方笑之蹈元乃獨諷詠嘉嘆託物興懷有古人之風輙用韻以廣其志','李彌遜','宋','宋诗','song-poetry','','[]','農丞免官歸，門第冷於鐵。',96,'全唐诗/poet.song.98000.json','["農丞免官歸，門第冷於鐵。", "屬國埋邊塵，旁觀爲心折。", "一朝百僚上，衆目仰光潔。", "賢愚雜平居，髙士見錯節。", "君看巖下竹，九曲困巖穴。", "風雷頭角露，歘蔽夏日烈。", "男児未盖棺，不用傷歇滅。", "感物思故人，長吟賴詩傑。"]'),
('22dc9bed-993c-4e2d-9024-4d72d9684a6d','送王三十六機宜召赴行在','李彌遜','宋','宋诗','song-poetry','','[]','烟昏海樹春，草木有秋色。',240,'全唐诗/poet.song.98000.json','["烟昏海樹春，草木有秋色。", "登臨翻百憂，念子將遠適。", "子如楸柏桑，那有十圍杙。", "長年百僚底，許國心自赤。", "光明一朝去，櫪驥得暫釋。", "邊塵暗江水，此事未聞昔。", "咨詢勤袞衣，謀議困肉食。", "將軍縱失伍，戰士輕笑百。", "腥風鬰義氣，血污土花碧。", "機牙不先壞，百發恐未息。", "近聞管夷吾，御敵富長策。", "能持一鈎金，力轉萬鈞石。", "子行勿俟駕，當宁方側席。", "時危急良籌，如救火下積。", "置身倘有地，膚髪詎足惜。", "王綱有關紐，着處在一拍。", "言大終少成，圖多易生惑。", "向來宣對間，未必有可績。", "徐行要好步，遇險各努力。", "明年取金印，快我歌壌擊。"]'),
('ed266427-dee7-4526-9765-87031e60077c','次韻仲輔山中之作','李彌遜','宋','宋诗','song-poetry','','[]','崖陰坐清暝，目爲山光注。',84,'全唐诗/poet.song.98000.json','["崖陰坐清暝，目爲山光注。", "妙意不可名，悠然與心晤。", "疏泉石中鳴，落葉衣上住。", "冷風起虚籟，還向無中去。", "三生聽鐘魚，偶失來時步。", "佛屋倚秋風，團團兩桂樹。", "卻疑此境中，曾是經行處。"]'),
('c66adf94-cbf6-472b-9e07-b5445e4f02bf','黄蘗歸途以碧潭清皎潔爲韻分得碧字真歇泛舟先歸','李彌遜','宋','宋诗','song-poetry','','[]','苦爲捫蘿行，正坐愛山癖。',144,'全唐诗/poet.song.98000.json','["苦爲捫蘿行，正坐愛山癖。", "振衣雲中樹，洗耳泉上石。", "稍尋優缽林，偶旁瞿曇宅。", "溪横走羊腸，山轉回龍脊。", "兩難伴榰笻，二老共飛錫。", "望迷落葉秋，坐斷蒲團夕。", "雲歸遶窗明，香盡出簷碧。", "希聲發巖竇，妙觀生墻壁。", "塵緣苦椎板，勝事成今昔。", "離家月垂鈎，歸路月掛壁。", "師今一帆輕，我向百里役。", "船子罷持橈，趙州行驀直。"]'),
('ff87bdb2-f482-47b5-bbf2-6fffe45b19c0','群玉五詠 樵谷','李彌遜','宋','宋诗','song-poetry','','[]','蝸牛負空軀，能避外物觸。',60,'全唐诗/poet.song.98000.json','["蝸牛負空軀，能避外物觸。", "微生寄寰宇，天地容粒粟。", "巖棲小天下，俯仰心自足。", "採薪百不憂，髙視賢版築。", "豈無潭潭居，違已詎所欲。"]'),
('43e65a54-2da9-48b9-b9f3-7f890df5d0d6','群玉五詠 赤松庵','李彌遜','宋','宋诗','song-poetry','','[]','留侯帷幄勳，平勃未足數。',60,'全唐诗/poet.song.98000.json','["留侯帷幄勳，平勃未足數。", "晚從赤松君，雅志在輕舉。", "公今卜真遊，百藴未一吐。", "古來賢達人，不必同出處。", "那知無心雲，解作及時雨。"]'),
('e2530d72-e607-4c94-8e11-3cccc80a4b3d','群玉五詠 百花洲','李彌遜','宋','宋诗','song-poetry','','[]','芳洲面林薄，山響疏泉落。',60,'全唐诗/poet.song.98000.json','["芳洲面林薄，山響疏泉落。", "小綠綴肥梅，疏青隕驚籜。", "周遭不盈丈，思與江湖廓。", "幽人百慮空，獨立聽鳴壑。", "物我偶俱忘，何必知魚樂。"]'),
('47fc32eb-0c11-4693-a102-acd1ec8ba383','群玉五詠 梅塢','李彌遜','宋','宋诗','song-poetry','','[]','嘉木開繁陰，疊障圍空翠。',60,'全唐诗/poet.song.98000.json','["嘉木開繁陰，疊障圍空翠。", "蟠根得疏梅，凛凛有髙致。", "餘芳敢追扳，薰蕕不同器。", "相期忘機友，共結棲真計。", "清姿固可人，所樂在臭味。"]'),
('fcbf003c-e8bc-4ebe-b7d9-28be6379ba80','群玉五詠 浮金峰','李彌遜','宋','宋诗','song-poetry','','[]','浮金鎖佳氣，不掛凡子目。',60,'全唐诗/poet.song.98000.json','["浮金鎖佳氣，不掛凡子目。", "髙人有餘清，别墅廣新築。", "有懷鴻雁行，風月伴幽獨。", "還爲稻粱謀，去傍蒹葭宿。", "歸飛會有時，分我一窗綠。"]'),
('eb2e9e1f-b2c8-456a-9dfe-dad7467f47fc','早行','李彌遜','宋','宋诗','song-poetry','','[]','飛鳴屋上鳥，入我夢中聽。',48,'全唐诗/poet.song.98000.json','["飛鳴屋上鳥，入我夢中聽。", "遲明月方昃，平曉風更静。", "游雲四山幕，止水萬象鏡。", "身如走空塵，南北了不定。"]'),
('3eb057a6-6d17-44dc-bc91-2ab9744ad9a1','次韻劉寬夫','李彌遜','宋','宋诗','song-poetry','','[]','向來志功名，唯恐着鞭後。',204,'全唐诗/poet.song.98000.json','["向來志功名，唯恐着鞭後。", "老來倦軒冕，待兔但知守。", "晨昏課朱墨，歲月計升斗。", "微官成底事，坐費白駒晝。", "晚從松竹遊，忘言到心友。", "十年成莫逆，百念付烏有。", "誰念愚溪愚，未種柳州柳。", "有如壓糠覈，責以出醇酎。", "蒼官與青士，賴爾對巵酒。", "不知我形穢，浪處珠玉右。", "劉侯妙雕琢，真是運斤手。", "鵬風若有待，豹霧恐難久。", "清池環小翠，一室僅十肘。", "胸中着雲夢，不數渭川畝。", "嗟予遠世心，大似與君偶。", "擬歌于蒍于，擊節和鳴玖。", "覓句了不工，青燈坐搔首。"]'),
('affdd7c3-63e2-4f73-92f1-54a4bb9eb9c7','次韻劉寬夫題學士進此庵','李彌遜','宋','宋诗','song-poetry','','[]','道人清净觀，夢幻閲諸有。',156,'全唐诗/poet.song.98000.json','["道人清净觀，夢幻閲諸有。", "成心自得師，論世方結友。", "默如彼上人，語合亡是叟。", "問焉一得三，疑者十居九。", "人情置冰炭，賦性甚杞柳。", "一波失源流，六鑿開戶牖。", "客塵不暫住，習氣既悠久。", "聞言雖轉頭，遇事還掣肘。", "志目或中眉，畫虎終類狗。", "我持測海心，來聽談天口。", "尚迷指端月，那辨日中斗。", "如抽一蠒絲，欲縳千牛首。", "勉賡進此歌，代斵恐傷手。"]'),
('27e33af2-0419-4026-9a11-7e58cfb8082e','青原臺與兄弟同賦','李彌遜','宋','宋诗','song-poetry','','[]','髙臺瞰層碧，岫幌森筠幢。',144,'全唐诗/poet.song.98000.json','["髙臺瞰層碧，岫幌森筠幢。", "恍如青原人，覿面呼老龎。", "胡爲未免俗，儒冠學爲邦。", "曾無白雨手，但補百碎腔。", "平生愛山癖，至老成膏肓。", "窮探偶會意，夜半力欲扛。", "一存短豆戀，心境不得雙。", "坐曠燕巢幕，覽勝猿窺窗。", "故山如故人，未見心已降。", "脂車蠟兩屐，烟雲恣衝撞。", "竹根掃三徑，荷鍤懸酒缸。", "外物不可必，斯言有如江。"]'),
('dc6c9ac1-d669-4c3c-b23d-b5b99805a5f4','次韻見獨知宗朝議見貽之什','李彌遜','宋','宋诗','song-poetry','','[]','遙遙幽人居，宛在蒼林間。',96,'全唐诗/poet.song.98000.json','["遙遙幽人居，宛在蒼林間。", "霜華駐秋清，風月喧晝閑。", "臞仙厭山寂，按竹俯人寰。", "面會良獨少，語酣遂忘還。", "豈無紛華地，心事了不關。", "詩成若鳴琴，志在水與山。", "君看陌上塵，工作頷下斑。", "何如對茗盌，泉罌煮潺潺。"]'),
('d0752829-0cea-4504-9d6f-a568a4996445','次韻明甫西園之什  其一','李彌遜','宋','宋诗','song-poetry','','[]','莫作園上紅，寧爲徑中綠。',60,'全唐诗/poet.song.98000.json','["莫作園上紅，寧爲徑中綠。", "多花必早彫，依依不如竹。", "一枝寄他林，翛然傲華屋。", "填饑飯秋英，借健膏石斛。", "坐斷百懶身，無心問雞足。"]'),
('5da13e7b-2dd0-4b33-8321-96869fc4ade1','次韻明甫西園之什  其二','李彌遜','宋','宋诗','song-poetry','','[]','輕飇自何來，破我池面綠。',60,'全唐诗/poet.song.98000.json','["輕飇自何來，破我池面綠。", "龍牙可方床，清夢遶修竹。", "苦遭鳥將雛，吚喔丈人屋。", "兩家餉濁醪，誰能問斗斛。", "妙意不可名，杯深睡初足。"]'),
('cb69edaf-60df-4fc4-a767-04bd3b4c46a9','次韻明甫西山之詠','李彌遜','宋','宋诗','song-poetry','','[]','秋畦靄黄雲，神用報力穡。',84,'全唐诗/poet.song.98000.json','["秋畦靄黄雲，神用報力穡。", "腰鐮誰家子，喜見眼中碧。", "我車返山阿，木落山更寂。", "年登妻啼饑，掩戶坐太息。", "不知多田翁，安用作弦直。", "已矣復何言，兹理斷可析。", "浩歌出長林，披榛攜子姪。"]'),
('86b72eae-ebee-411e-8e13-90d2cd1acceb','才彦置酒筠谿明甫有詩次其韻','李彌遜','宋','宋诗','song-poetry','','[]','曳杖循清池，浩歌理憂端。',96,'全唐诗/poet.song.98000.json','["曳杖循清池，浩歌理憂端。", "憂端不可解，遇酒即暫懽。", "聯綿九疑髙，置我胸中蟠。", "一澆豈易得，橡栗無朝餐。", "赤鯉信久絕，白鷗盟亦寒。", "何人過子雲，慰此風月閑。", "杯行不停手，共惜良夜闌。", "陶然竹根臥，衾枕天地間。"]'),
('dc4fafb1-3290-4501-b14b-3583a9d3a0b5','西山次林尉韻','李彌遜','宋','宋诗','song-poetry','','[]','凱之半痴黠，我來痴更深。',168,'全唐诗/poet.song.98000.json','["凱之半痴黠，我來痴更深。", "手除一抔土，坐待千畝陰。", "三年客東都，髙山但鳴琴。", "歸來見此君，挺挺環蒼琛。", "居然覺影穢，鬢白况已森。", "浮生關朝市，渠用多贏金。", "無煩北山移，自濯塵土襟。", "茂樹獨箕踞，清流恣窺臨。", "蝶游入窈窕，蛇捕尋崎嶔。", "鞭鸞叩門誰，亂我風竹音。", "能回折腰態，來和支頤吟。", "妙香□壑源，慰子千古心。", "霜天麗初日，石壁乾餘霖。", "相攜步林杪，烟中見孤岑。"]'),
('5c0387d2-6a20-4e26-8946-c19631bb88f1','望後德新弟邀池上酒闌浩歌潮落人散粹之即席成詩次韻和之','李彌遜','宋','宋诗','song-poetry','','[]','平生七不堪，造物不能令。',144,'全唐诗/poet.song.98000.json','["平生七不堪，造物不能令。", "從人較痴黠，百負未一勝。", "一丘收桑榆，外物聽衰盛。", "解纓清泠上，稍覺塵土凈。", "孤飛團團月，似我靈府瑩。", "偶逢一坳水，即現大圓鏡。", "杯中見山綠，夜午覺已正。", "喧呼衆賓歡，嗑嗒四谷應。", "新詩带潮湍，浩唱起人定。", "褰衣踏清影，藻荇耿深徑。", "江山有精色，遠目不知暝。", "欲去還復留，蘋梢惹歸艇。"]'),
('20453c5f-c09a-4292-8d80-aef406de09a1','六月四日飯石門風雷大作而雨不成滴戲以詩趣之','李彌遜','宋','宋诗','song-poetry','','[]','疾風捲落葉，六月秋欲變。',72,'全唐诗/poet.song.98000.json','["疾風捲落葉，六月秋欲變。", "雲生澗底松，雷走巖下電。", "雨華如棼絲，熟視乃不見。", "借令車軸飛，來救龜兆徧。", "常暘起民瘼，吻噪不得嚥。", "寄言行空龍，若藥須暝眩。"]'),
('7ed5d9f1-da09-4980-bc58-1f00be8c0a52','再和久旱望雨韻','李彌遜','宋','宋诗','song-poetry','','[]','髙田黄欲枯，下田青欲變。',72,'全唐诗/poet.song.98000.json','["髙田黄欲枯，下田青欲變。", "三更轣轤聲，挈水急於電。", "汙池魚不遊，坎井蛙自見。", "助苗敢辭勞，人力詎能徧。", "那憂日一食，正懼李三嚥。", "微雲不成雨，但作眼中眩。"]'),
('785982e3-b917-4127-8ddb-42ed43fed643','次韻葉觀文遊鼓山','李彌遜','宋','宋诗','song-poetry','','[]','謝公憂民餘，妙語繼兩禪。',120,'全唐诗/poet.song.98000.json','["謝公憂民餘，妙語繼兩禪。", "兹遊瞰滄溟，宛在一葉蓮。", "木密虚可步，石立髙莫緣。", "從來看山眼，一洗俱茫然。", "蓬萊如有無，空翠蒙雲烟。", "卻疑浩蕩中，天津渺歸船。", "崎嶇訪幽勝，衆象爭相鮮。", "凌髙寓遠目，孤雲共軒軿。", "歸來擁寒衾，耳底酒鳴泉。", "覓句了不工，青燈暗孤眠。"]'),
('9f2aecab-3807-4196-95ce-bcc1a42698a9','次韻葉觀文東禪開堂','李彌遜','宋','宋诗','song-poetry','','[]','閩山多勝地，列屋栖髙禪。',120,'全唐诗/poet.song.98000.json','["閩山多勝地，列屋栖髙禪。", "妙供積香苾，寶華散金蓮。", "往時入廛手，來見住世緣。", "遼遼百年後，慧炬無復然。", "我公具正眼，爲續旃檀烟。", "諸方坐老衲，具足世法船。", "少開迷雲昬，氛埃遂澄鮮。", "我來偶相值，杖履參髙軿。", "拈花起一笑，歸去跨林泉。", "從兹竹陰下，飽飯縱横眠。"]'),
('fc4091ca-5658-479e-b206-703ef63d03df','次韻葉觀文遊賢沙鳯池安國之作','李彌遜','宋','宋诗','song-poetry','','[]','春雲覆老屋，孤僧正安禪。',120,'全唐诗/poet.song.98000.json','["春雲覆老屋，孤僧正安禪。", "繽紛雨天花，云是千歲蓮。", "誰知天上相，來結林下緣。", "倘徉愛亭陰，灌木蒼虬然。", "古意弔鳯穴，祖風契漁船。", "豐隆亦解事，一掃千林烟。", "光風尙駘蕩，芳物俱蕃鮮。", "詩成喚阿買，平處凌羲軿。", "登臨賴陶寫，可但思平泉。", "郊原問農事，柔桑起蠶眠。"]'),
('1e03c2cb-dc8f-4925-b4af-e2d616154488','次韻葉觀文再賦遊靈源桃花二洞之作  其一','李彌遜','宋','宋诗','song-poetry','','[]','雙旌耀林丘，小隊喧笳鼓。',120,'全唐诗/poet.song.98000.json','["雙旌耀林丘，小隊喧笳鼓。", "鞭鸞相招攜，拂石共容與。", "愛山晋羊祜，好士漢何武。", "胸中補天石，筆下修月斧。", "追遊愧後乘，遇景詫先覩。", "捫參或三嘆，探穴聊一俯。", "會意時目成，忘言但心許。", "徐行詎敢留，有語不得吐。", "真遊未易再，外物何足數。", "酒盡倘可繼，君歌爲君舞。"]'),
('e4c2e24b-9c83-420e-b2a6-227e94fdce02','次韻葉觀文再賦遊靈源桃花二洞之作  其二','李彌遜','宋','宋诗','song-poetry','','[]','山行有底急，路轉乃爾長。',120,'全唐诗/poet.song.98000.json','["山行有底急，路轉乃爾長。", "輿肩憇清蔭，屐齒尋幽芳。", "突兀見古殿，委蛇度飛梁。", "餘紅點澗色，新絲浮巖光。", "人徑出鳥道，僧居儼蜂房。", "前山去未了，後騎低可望。", "逢人貴同氣，偶地忘殊方。", "徑催文字飲，稍近花草香。", "語味寫素隱，詩工發深藏。", "湛輩欣有得，折楊愧成章。"]'),
('f433c52c-aad9-4176-91bb-7f80d12eb037','次韻富季申樞密','李彌遜','宋','宋诗','song-poetry','','[]','半生類猿狙，褁以周公服。',144,'全唐诗/poet.song.98000.json','["半生類猿狙，褁以周公服。", "炙手安敢近，唾面未爲辱。", "天公亦解事，縱之走林谷。", "長年飽烟霞，形影自相逐。", "晚從我公遊，在側愧珠玉。", "公居廊廟間，排難不枚卜。", "挺然國蓍龜，盛事紀湘竹。", "愛閑能幾時，天道七日復。", "吾儕三折肱，顧步敢求速。", "願公膏澤流，長保薪十束。", "負暄撫稚子，一飯倘能續。", "胡椒縱可營，安用八百斛。"]'),
('ea944933-8c7a-4c9d-8c95-3519164ca37e','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其一','李彌遜','宋','宋诗','song-poetry','','[]','崔嵬孔明柏，結陰衆所依。',72,'全唐诗/poet.song.98000.json','["崔嵬孔明柏，結陰衆所依。", "移根天衢上，曾撫日月暉。", "如何去大厦，卻遶烏鵲飛。", "終當煩萬牛，挽取廊廟歸。", "鄭公澤既遠，何以慰調饑。", "公其踵前修，一洗貧士悲。"]'),
('9830b5c1-4715-480b-8ce4-7bff21527376','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其二','李彌遜','宋','宋诗','song-poetry','','[]','夕郎富文采，早歲從君軒。',72,'全唐诗/poet.song.98000.json','["夕郎富文采，早歲從君軒。", "承明久厭直，著書効文園。", "十年坐蘭若，鼻觀參晨烟。", "撐腸正患多，敎外多窮研。", "豈惟寄絕交，對客今忘言。", "肯違蓮社友，來從竹林賢。"]'),
('4f867a1a-cd55-4245-a006-569b4a395719','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其三','李彌遜','宋','宋诗','song-poetry','','[]','甯生但叩角，馬卿亦能琴。',72,'全唐诗/poet.song.98000.json','["甯生但叩角，馬卿亦能琴。", "托物寫孤憤，舉世誰知音。", "敲門喚良友，舍木森十尋。", "茶甌荐甘薺，索酒那得斟。", "非無膏粱子，此藥聖所欽。", "誰知半刺史，而有尊堯心。"]'),
('3235cc3e-0535-497a-a00e-3cbd0faec590','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其四','李彌遜','宋','宋诗','song-poetry','','[]','一言悟漢祖，千戶遂封婁。',72,'全唐诗/poet.song.98000.json','["一言悟漢祖，千戶遂封婁。", "士窮必有遇，榮悴交相酬。", "堂堂張公子，謝事歲幾周。", "不作折腰能，每懷餬口憂。", "才華賈馬上，風味陶謝儔。", "舌在吾不患，已矣勿浪求。"]'),
('f87a6a54-42d6-439d-811d-42eb26b6ac55','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其五','李彌遜','宋','宋诗','song-poetry','','[]','廣文負才名，閉戶衆莫干。',72,'全唐诗/poet.song.98000.json','["廣文負才名，閉戶衆莫干。", "長安不肯近，詎肯卑小官。", "爨無欲清人，日昃未及餐。", "借書紛滿席，不顧坐客寒。", "斯人抱長饑，我輩亦厚顔。", "何當置君側，用表賢士關。"]'),
('d2e556a1-3b23-458a-8ae3-9ad0cd6bc530','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其六','李彌遜','宋','宋诗','song-poetry','','[]','方子困海江，長松隱蒿蓬。',72,'全唐诗/poet.song.98000.json','["方子困海江，長松隱蒿蓬。", "多能隱所長，最喜五字工。", "好古遠可紹，結友久益恭。", "寒饑了不慍，清坐與我同。", "縱今四壁立，未效一錢通。", "長鑱斸山雲，君去吾亦從。"]'),
('59e9bfe3-f741-4a04-bcf5-1ef579469244','暇日約諸友生飯於石泉以講居貧之策樞密富丈欣然肯顧賓至者七人次方德順和貧士韻人賦一章  其七','李彌遜','宋','宋诗','song-poetry','','[]','樞君有美子，酷愛柳柳州。',72,'全唐诗/poet.song.98000.json','["樞君有美子，酷愛柳柳州。", "作詩陋元白，欲擬晋魏儔。", "情知鸞鳯穴，不宿燕雀流。", "簡編正在目，冠冕奚足憂。", "傳家一經力，造物行見酬。", "江蘺與辟芷，終當荐靈修。"]'),
('4425e88a-d6c0-4717-bb19-b279f115474c','次韻王才元少師酴醿','李彌遜','宋','宋诗','song-poetry','','[]','繁英雪作堆，新葉帷尙隘。',108,'全唐诗/poet.song.98000.json','["繁英雪作堆，新葉帷尙隘。", "一薰有餘清，三嗅詎可廢。", "淡彦融仲宗，彦錫德順子。", "立然不爭妍，晚乃入鍳裁。", "風流巵酒間，穎脱衆香內。", "緱仙厭繁華，醉臥日炙背。", "經旬被花惱，妙語撃環珮。", "曉來雨翻盆，春事逐破塊。", "誰憐青銅錢，相期世紛外。"]'),
('305c85ea-fad3-426d-ab04-6befab5511d0','次韻王才元少師招遊東山客有不至者遂已促其尋盟','李彌遜','宋','宋诗','song-poetry','','[]','我從西山居，不作東山夢。',168,'全唐诗/poet.song.98000.json','["我從西山居，不作東山夢。", "聯綿翠光浮，遠目不暇送。", "飄飄貴公子，萬卷輙成誦。", "髙懷到林丘，杖履邀我從。", "褰裳欲從之，未發神已動。", "何人折柬客，不結蓮社供。", "勝遊遂中休，一簣真可痛。", "詩成美六逸，敘事一一中。", "但慚猿狙杙，乃與杞梓共。", "閩山寒更青，森木閟陰洞。", "鹿澗清自流，醴井淺可弄。", "尋幽當及辰，爲樂要與衆。", "兹遊倘再卜，勇往不待風。", "徑須理百屣，日日聽鞭鳯。"]'),
('c54f3d66-2c19-405a-9a41-5001186bfb99','再用王才元少師韻','李彌遜','宋','宋诗','song-poetry','','[]','十年趁飛蓬，來作海邉夢。',168,'全唐诗/poet.song.98000.json','["十年趁飛蓬，來作海邉夢。", "曾無竹馬迎，長辦柳車送。", "長鬚乞米收，驥子學詩誦。", "自公弭節歸，許我執鞭從。", "聽詩鬼神泣，看劍星辰動。", "歡留文字飲，靜憇苾芻供。", "辨疑每及爭，攻短不憚痛。", "捜奇至旁求，探賾或奇中。", "誰知烟霞姿，肯與塵土共。", "長風起青冥，逸思攪空洞。", "豈無酒百船，可待角三弄。", "不勞行炙人，一見散花衆。", "敢違江山招，寧受児女風。", "可但東山佳，西池有儀鳯。"]'),
('c735aeca-99f3-49fd-a5f7-885fd076158b','次韻王才元陪季申樞密諸公遊東山之作','李彌遜','宋','宋诗','song-poetry','','[]','游雲本無心，時爲晴山留。',264,'全唐诗/poet.song.98000.json','["游雲本無心，時爲晴山留。", "我曹等雲閑，亦作尋山遊。", "駕言出城闕，古寺聊相投。", "摩挲鑄金像，不知幾春秋。", "行行及佳境，真成上揚州。", "追隨况當人，華胄皆通侯。", "髙名邁姚宋，餘事卑曹劉。", "向來金鑾御，一一親垂旒。", "如何丘壑中，乃與猿鶴儔。", "寒威靳山秀，幽處不可求。", "清溪訪鹿跡，古澗窺龍頭。", "枯藤路斷磴，未上愁吳牛。", "人言昔仙去，疑是竹務猷。", "雲昏看山眼，欲展還復收。", "伊予巖穴走，南北萬里遒。", "烟霞入膏肓，瞑眩不可瘳。", "群公上界侣，解后天南陬。", "敢言同心臭，長抱躐等羞。", "心知造物戲，駑駘間驊騮。", "鶴書偶未下，愛日尚可偷。", "花風起群萌，枝上春欲流。", "更催小槽紅，一笑非人謀。"]'),
('e14f8269-3339-47b0-9fb8-15c3750e718b','與德洪明甫伯與暮春六日同登烏石飲於浴鴉池琴侍以石上坐忘歸分韻得石字','李彌遜','宋','宋诗','song-poetry','','[]','老懷不知春，但愛遠峰碧。',120,'全唐诗/poet.song.98000.json','["老懷不知春，但愛遠峰碧。", "乘髙恣遐觀，未快雙目擊。", "稍爲松根坐，遂與參井逼。", "女媧補天餘，墜此百鍊石。", "摩挲蒼蘚痕，上有鴉沿迹。", "引觴起自斟，醆面不容滴。", "舉頭挽飛雲，頗覺天半窄。", "追隨二三子，顧我獨衰白。", "向來舞雩春，勝踐同今昔。", "偶忘千歲憂，共此一笑適。"]'),
('8360a24a-ff18-4999-be2a-509bdcf27358','次韻趙表之水口道中','李彌遜','宋','宋诗','song-poetry','','[]','我從楚江來，不見閩江大。',132,'全唐诗/poet.song.98000.json','["我從楚江來，不見閩江大。", "雲山路嶮巇，水石勢澎湃。", "舟行屈曲間，溪面浮百怪。", "篙師力推拏，如下吾儂拜。", "丈人入吾閩，險阻嘗一带。", "風霜經幾時，鬚髪乃爾奈。", "營營復何求，赫赫祗自賣。", "如何遣諸緣，直養以無害。", "秋風着蒲柳，物態亦榮憇。", "終當從公遊，萬法等成壞。", "杖藜款禪房，還盡三生債。"]'),
('21cf6597-b6ad-4688-b74f-f8e75361b3da','次韻趙表之久别相會於福唐見貽之什','李彌遜','宋','宋诗','song-poetry','','[]','十年海南年，世味嘗欲徧。',120,'全唐诗/poet.song.98000.json','["十年海南年，世味嘗欲徧。", "昔爲擔板痴，今作繞指轉。", "誰能濯我纓，人欲唾其面。", "故人千里來，髙義動深眷。", "問答不及已，驚我神髪變。", "功名眼中花，日月弦上箭。", "公今已超然，富貴非所願。", "南遊訪知識，氣習要百煉。", "授我不死術，老骨倘可健。", "是身走空雷，當作如是見。"]'),
('1f8ba1b3-7434-42eb-9801-61330426aa1a','題葉擇甫繡壁軒','李彌遜','宋','宋诗','song-poetry','','[]','閩山固多奇，會意一峰足。',144,'全唐诗/poet.song.98000.json','["閩山固多奇，會意一峰足。", "豈徒快登臨，政欲伴幽獨。", "丈人隱禪關，窗戶閉秋綠。", "簷間絕壁起，秀色近可掬。", "丹黄與白紅，楓櫟間花木。", "微雲一過之，綉錦初脱軸。", "是翁貧不憂，朝飯罄儲粟。", "隻雞呼近社，笑傲杯中玉。", "酒酣自起舞，身外置榮辱。", "君家大児手，千障入縑幅。", "何妨寫顛崖，老樹傍髙屋。", "佗年明光歸，展玩長在目。"]'),
('29ab4e3e-949b-4eeb-859c-e8a743ad7e9d','陪館中同舍遊方池分韻得香字','李彌遜','宋','宋诗','song-poetry','','[]','紅蕖碧水如曲江，醉惱諸人欲斷腸。',64,'全唐诗/poet.song.98000.json','["紅蕖碧水如曲江，醉惱諸人欲斷腸。", "波光花氣來無旁，人面生春酒面凉。", "男兒莫遣兩鬂霜，何妨騎馬似知章。", "銀鈎未落片雲黑，定有六丁呼阿香。"]'),
('bc3fff39-a36b-4910-b4a9-71e3f6452b54','贈朱少章','李彌遜','宋','宋诗','song-poetry','','[]','堂堂如叟雲夢胸，筆端日夜生雲風。',64,'全唐诗/poet.song.98000.json','["堂堂如叟雲夢胸，筆端日夜生雲風。", "地臨嵩少萃奇秀，雕鎪彷彿窮天功。", "捷如接猱健搏虎，嫵媚清切歸深雄。", "六丁不取四天黑，陰山直恐喧雷公。"]'),
('95a452ca-81f6-48e4-aeda-cb5f592c9d6f','寄題翠樊亭','李彌遜','宋','宋诗','song-poetry','','[]','何郎愛山知貴目，不着芒鞋踏空谷。',192,'全唐诗/poet.song.98000.json','["何郎愛山知貴目，不着芒鞋踏空谷。", "誅茅結竹凾丈間，坐揖崔嵬遶江綠。", "我亦尋幽不憚遠，半世一身隨轉轂。", "峰巒過眼已成夢，南北空嗟髀消肉。", "羨公登亭如歷塊，睥睨乾坤輕一芥。", "春繁嫵媚發奇姿，秋凈孤髙見真態。", "固知靜者自超詣，世上憧憧良足隘。", "智愚何止三十里，咫尺須論百千界。", "四時秀色供盤礴，筆下雲烟醉中落。", "雕鎪苦欲覷天巧，造物有靈應作惡。", "蓬萊方壺或上下，紛紛陵谷今非昨。", "倘令夸子與霄遁，胸中賴有藏山壑。"]'),
('4c959cc1-ca7c-4501-b876-eaf14502c8b6','贈别竹西王彦升居士','李彌遜','宋','宋诗','song-poetry','','[]','參軍四壁生秋草，鬂毛不似心先老。',128,'全唐诗/poet.song.98000.json','["參軍四壁生秋草，鬂毛不似心先老。", "終隨烟霞學巢由，一室安能事除掃。", "竹西舊說青雲客，詩思長留意無極。", "塵埃不見襄陽山，賴有斯人道消息。", "赤心照日青眼明，與君一見輸生平。", "君去摩天學孤鳯，我今飲海盤長鯨。", "雲車劙兮風馬休，呼兒乞取千金裘。", "明朝有句道不得，黄葉滿庭無限秋。"]'),
('19f68dca-5366-41d9-90d5-5b2730d3767c','行路難','李彌遜','宋','宋诗','song-poetry','','[]','江心蟠石蒼虬立，山激江流浪頭急。',128,'全唐诗/poet.song.98000.json','["江心蟠石蒼虬立，山激江流浪頭急。", "風昏月暗魚龍愁，電掣雲奔鬼神入。", "船頭星斗天爲低，夜潮生寒洲渚移。", "鳴舷鼓枻驚楚子，危檣遠纜號吴兒。", "篙師咄咄自相語，明發扁舟繫何許。", "半月行江十日風，寸步家山隔秦楚。", "黄衫年少金雕鞍，日髙華屋春夢殘。", "插花走馬咸陽道，世上空嗟行路難。"]'),
('652692ec-5162-4de3-a604-1a336450b56a','舍弟以詩貸粟邵叔暘次其韻','李彌遜','宋','宋诗','song-poetry','','[]','於陵三咽不待糝，重義輕身誠果敢。',208,'全唐诗/poet.song.98000.json','["於陵三咽不待糝，重義輕身誠果敢。", "首陽一死甘如飴，未覺此身真壈坎。", "丈夫有志窮益堅，肯爲猩唇賤昌歜。", "髙門下筯羅甘珍，大臠觜拌不供啖。", "吾儕朝飯不謀夕，惟有生芻緣我斬。", "富當學禮貧忌測，莫遺覊愁到顔色。", "兩公雖槁道則腴，每食空多信何益。", "縱令日興費萬錢，大似鵷鶵見鴟嚇。", "我今藜藿還苦併，尚喜剛腸柰燒炙。", "自營半飽固已勞，忍取畿人重三尺。", "去年避賊奔如流，百區不易金一鈎。", "縣官布德速置郵，奉行一律亡劣優。", "但知捜粟逃身尤，吁嗟富民思故侯。"]'),
('bdea25e9-60ce-484a-9333-e9ea5db8f5fe','獨宿昭亭山寺','李彌遜','宋','宋诗','song-poetry','','[]','山寒六月飛霜雪，樓殿夜深鐘鼓歇。',64,'全唐诗/poet.song.98000.json','["山寒六月飛霜雪，樓殿夜深鐘鼓歇。", "琅玗無風萬戟閑，屋角明河挂天闕。", "龍牙七尺玉壺冰，炯炯神清夢不成。", "可憐幽絕無人共，臥看雲頭壁月生。"]'),
('62ac3a2f-a3f5-4f45-85ac-71f54e97cdd0','子美士曹送示梅花似表弟有詩因次其韻','李彌遜','宋','宋诗','song-poetry','','[]','春花先到詩翁家，融和入木生妍華。',144,'全唐诗/poet.song.98000.json','["春花先到詩翁家，融和入木生妍華。", "攀條不减隴頭贈，與我病眼增空花。", "輕綃襯雪香未透，月中妃子新來痩。", "意態輕盈總不如，孤芳雅合群花右。", "速令解盎傾彫胡，叩門換酒呼長鬚。", "對花劇飲百不問，此身如視秦人臞。", "一枝相惱已如許，況及秀發連根株。", "春工日夜正剪刻，東鄰□好公知無。", "會須空腹貯好語，醉中要看雲烟書。"]'),
('18a2f53a-ff05-428d-b4e4-839be06dfa93','丞廳後圃雙梅一枝發和似表弟韻','李彌遜','宋','宋诗','song-poetry','','[]','漫游蹤跡成浮家，一身四海驚年華。',144,'全唐诗/poet.song.98000.json','["漫游蹤跡成浮家，一身四海驚年華。", "不禁草木競時節，忽見霜幹排新花。", "曉雲生寒日未透，南枝半肥北枝痩。", "就中一枝最先發，浪蕊浮花敢居右。", "山翁涉世如狼胡，功名日遠霜凌鬚。", "與花同是江南客，一笑爲解東陽臞。", "吟哦遶樹正百匝，未放零落空殘株。", "春風雜花儘明媚，此君風味懸知無。", "雨中着子尚不惡，可堪老葉繙虫書。"]'),
('fd2770b3-a80c-447a-bb91-25d705ae639c','歲後三日與羅叔共二郡似表弟席上分梅花年後多韻得多字刻燭成','李彌遜','宋','宋诗','song-poetry','','[]','春風一夜如鳴鼉，殘香暗粉驚辭柯。',112,'全唐诗/poet.song.98000.json','["春風一夜如鳴鼉，殘香暗粉驚辭柯。", "新春三日駒隙過，花前百罸寧辭多。", "男兒莫遣兩鬢皤，舉觴不飲理則那。", "酒酣不用吳姬歌，短鬚尚足供吟哦。", "坐中鮑謝偕陰何，語如韶濩參鳴珂。", "鏗鏘入耳痊沉疴，豈獨使我衰顔酡。", "我今官閑得婆娑，遲明更上梅花坡。"]'),
('e92da199-a633-441b-8d10-62ec12beca92','春日同遊梅花坡分韻賦詩坡字','李彌遜','宋','宋诗','song-poetry','','[]','春江曉鼓收更鼉，筍輿催上西城坡。',160,'全唐诗/poet.song.98000.json','["春江曉鼓收更鼉，筍輿催上西城坡。", "嵩陽散人藍田吏，紫髯參軍三語羅。", "機雲兄弟更奇絕，杖藜雜沓行逶迤。", "孤芳冷蕊正明媚，卻笑桃李空繁多。", "卑枝横路靄香陣，遠樹山林揚素波。", "石腸冷淡老眼暗，對此不忍空樽犧。", "四賓袞袞飲翻河，扳花覆盞自起歌。", "語劇嗔眉動輕皺，酒薰笑臉生微渦。", "跳丸背我何太急，誰爲返旆追羲和。", "商量嫩蕊暫留住，後來載酒無蹉跎。"]'),
('d856e84e-a85b-4ebb-878d-78e9a54aff58','過魯公觀牡丹戲成小詩呈席上諸公','李彌遜','宋','宋诗','song-poetry','','[]','昨日花間風送雨，淚臉凝愁暗無語。',128,'全唐诗/poet.song.98000.json','["昨日花間風送雨，淚臉凝愁暗無語。", "今日花間天色明，向人艷冶百媚生。", "雨中多思晴亦好，日日看花被花惱。", "人間絕色比者誰，漢宫飛燕開元妃。", "輕顰淺笑各有態，淡粧濃抹俱相宜。", "傳聞姚魏多黄紫，醉紅不似當筵枝。", "移樽洗醆苦不早，明日春光暗中老。", "西齊居士心已灰，也向花前狂欲倒。"]'),
('14a72507-bbb6-43c2-9d82-f678bdb970a7','虞仲通判以溪聲名軒約同賦','李彌遜','宋','宋诗','song-poetry','','[]','山根出泉瀉鳴玉，上有蒼崖擎佛屋。',160,'全唐诗/poet.song.98000.json','["山根出泉瀉鳴玉，上有蒼崖擎佛屋。", "無風水石自撞觸，不盡潮音發寒谷。", "宰官不是雲間陸，舊識南泉生處熟。", "當軒大榜與名目，平地重翻偃溪曲。", "曲中時轉三妙語，一一聲音談佛祖。", "喧豗噫視十方鼓，萬壑風雷送烟雨。", "此聲不屬聞中取，六鑿相攘竟誰主。", "後來紛紛何足數，五乳峰頭曾賺舉。", "山翁有耳百不聞，團蒲曲几窮朝暮。", "何時沿溪掬寒綠，掃葉煎茶睡初足。"]'),
('740c6f78-6915-4896-91b2-d28f69785144','夜宿昭亭寺舍弟以公事歸城中與梅公澤邵公序昆仲待月山亭取酒共飲明日舍弟有詩次其韻','李彌遜','宋','宋诗','song-poetry','','[]','解衣夜泊靈山巔，胡床待月松風前。',160,'全唐诗/poet.song.98000.json','["解衣夜泊靈山巔，胡床待月松風前。", "已令圓頂具白氈，更促方屨收青編。", "茶甌過眼見樽俎，蔬筯放手羅廿羶。", "清遊逸興在一舉，騎鶴大勝揚州仙。", "吾家小弟困薄領，到處鳬鶩長摩肩。", "歸途遇酒成歎詠，飛奴持送空聯翩。", "絕知勝境外塵躅，誰可浪得麻姑鞭。", "詩梅易邵真二妙，手拈群書類蝸涎。", "拉枯拾芥真戲事，不待萬選知青錢。", "賸傾醇酎澆舌本，要取金印纍纍懸。"]'),
('fecb01dd-93fc-48aa-954e-52c5edf100c3','客誦故人劉立道梅花詩有懷用其韻以寄之','李彌遜','宋','宋诗','song-poetry','','[]','桑柘如錢柳如雪，南村北村欲蠶月。',128,'全唐诗/poet.song.98000.json','["桑柘如錢柳如雪，南村北村欲蠶月。", "老翁飯飽摩腹行，白鷗自隨閑喚鉄。", "扳花正恨顔色亁，哦公七言毛骨寒。", "惜花不似愛詩苦，即遣愁海回狂瀾。", "公今爲郎尚黑髮，仕路不應嗟歇滅。", "江頭官閑來雁多，莫使故人書斷絕。", "春風步馬芳蘭臯，思如哀鴻獨求曹。", "幾時懷抱相對盡，桂漿酌斗供詩豪。"]'),
('c281f387-54ff-4a87-9601-462f8f11e3fa','秋夜枕上偶成','李彌遜','宋','宋诗','song-poetry','','[]','七月西風捲殘暑，砌外蕉梢响寒雨。',64,'全唐诗/poet.song.98000.json','["七月西風捲殘暑，砌外蕉梢响寒雨。", "青蠅斂翼蜩收聲，樓上逢逢夜將午。", "徽絃信手酒自傾，一杯一杯宫羽成。", "醉頭着枕百事置，夢殘睡足天未明。"]'),
('4c0d7626-af2d-48f6-8d32-c3261529dede','趙彦術於姑熟倅廳作寄傲軒請予爲詩寄之','李彌遜','宋','宋诗','song-poetry','','[]','王孫是古豪而迂，五鼎不換一束書。',160,'全唐诗/poet.song.98000.json','["王孫是古豪而迂，五鼎不換一束書。", "江城别駕轅下駒，升斗未足回清臞。", "曉衙吏退誰與俱，傍砌燕雀來將雛。", "室中塵凝生白虛，竹色照座花連株。", "南窗曲肱凈籧篨，軒窗勇往羲皇初。", "淵明雖遠幾類拘，輕去彭澤思吾廬。", "人生泛如風中桴，況復蜕視千金軀。", "公家舍屋爲補苴，政成訟簡日有餘。", "斗酒近局聊相娯，三年官滿鵲棄居。", "後來好事猶今吾，至哉此樂陶不如。"]'),
('0a727192-0851-4544-aec8-818c6591cc42','邵文伯得玉蘭於昭亭持以見遺因求詩爲作長句','李彌遜','宋','宋诗','song-poetry','','[]','羲和呼龍曉耕烟，斗挹沆瀣膏瓊田。',240,'全唐诗/poet.song.98000.json','["羲和呼龍曉耕烟，斗挹沆瀣膏瓊田。", "青女剪刻了不睡，瑤草競秀爭春妍。", "凝冰作膚露作臉，蕙花蘭幹香蘅荃。", "仙人掌中太華小，上有玉井開叢蓮。", "雲璈舞鳯醉妃子，遺簪亂插春風前。", "蓂莢花含月皎皎，琪樹弄影霜鮮鮮。", "清氛皓態難比並，世上草木誰能肩。", "虞師老圃眼未識，名字不着三墳編。", "山翁何從得此種，一日萬口人爭傳。", "我慚形穢敢居側，熟視眩轉心茫然。", "搖聞嗇夫訪奇秀，忍使抱恨蓬蒿邉。", "天衢五城白銀闕，複道小苑通如纒。", "何人移植備採撥，珊瑚碧樹根株連。", "重瞳一顧雨露偏，薰爲叶氣被八埏。", "家家擊壌歌豐年，不但洗我沉疴痊。"]'),
('d75d101a-eb8b-43c0-9ac6-42a51fcb38a0','將至徽川道中作','李彌遜','宋','宋诗','song-poetry','','[]','平生愛山老山間，行山怕盡去復還。',96,'全唐诗/poet.song.98000.json','["平生愛山老山間，行山怕盡去復還。", "兹遊深入衆山囿，一日看盡平生山。", "頗聞黄山最奇秀，紫翠六六堆孱顔。", "端如啖蔗及佳境，快意不復嘲天慳。", "我生目力固有限，應接不暇愁躋扳。", "要令胸次洞表裏，掃盡礧塊羅烟鬟。"]'),
('587160e7-420c-4814-b047-d2d4f7e35657','山行遇雨','李彌遜','宋','宋诗','song-poetry','','[]','滄溟四乾青虬立，碧雲摩霄髙嶪岌。',64,'全唐诗/poet.song.98000.json','["滄溟四乾青虬立，碧雲摩霄髙嶪岌。", "六丁夜挽天河傾，石骨無塵露蒼濕。", "長風吹雨不成絲，飛鞚衝山带烟入。", "羲和回馭還青冥，布穀催耕喚春急。"]'),
('abfb684b-e29b-4204-a493-b2535577d159','黄山在歙郡之北雄麗傑出可與嵩少爭衡世傳黄帝與浮丘容成公鍊丹其下功成仙去南有紫陽蓊欎相望唐景雲中仙人許宣平舊隱也伯氏來倅之始鋤荒聚礫爲臺數仞揖二山之秀既成予自宣來乘髙四顧飄然有凌雲意思電旌風馭朝夕往來其間作歌以招之云','李彌遜','宋','宋诗','song-poetry','','[]','髯龍飛空去雲急，雨翁蹋雲挽龍入。',136,'全唐诗/poet.song.98000.json','["髯龍飛空去雲急，雨翁蹋雲挽龍入。", "猩啼鶴怨凝春愁，三十六峰黛鬟濕。", "紫陽照空天夜明，棲烟採玉唐宣平。", "碧桃自熟人自遠，千秋月露含凄清。", "璜臺十成架蘭芷，花風吹樓蔓香起。", "青霓叩閽帝下遊，挹斗扳箕荐瓊醴。", "南山北山朝莫青，雲關岫幌開鱗鱗，衆真胡爲駕凌冥。", "寄言流星盍歸只，宰官自是騎鯨李。"]'),
('f5b6d712-d394-43c1-829c-4136641837d8','夏日邀客飲月下偶作','李彌遜','宋','宋诗','song-poetry','','[]','晴空倒挂秋江平，仙人攜盤上青冥。',168,'全唐诗/poet.song.98000.json','["晴空倒挂秋江平，仙人攜盤上青冥。", "珊瑚無根倚霄漢，影落夜水魚龍驚。", "流金焦土天六月，腹欲生茵頭生蝇。", "恍然坐我風露下，濯以三峽吞層冰。", "稍收瓜李入飣餖，凍酎照盌玻璃明。", "吳歈始作蛙蝇閙，巴管一洗鸞鳯清。", "孤光當天萬象出，斥去不御悲長檠。", "人生動如參與商，短鬚數挽驚飛霜。", "但願月明酒如江，與君急管催羽觴。", "酒酣拔劍起爲壽，劍光稜稜入牛斗，不放浮雲變蒼狗。"]'),
('a905590a-39c7-4f37-9994-94d22baf2747','夏日登臺晚雲層疊若衆山狀伯氏令賦詩因成長韻','李彌遜','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','陽光潑血汗交頤，晚日政與長空宜。',256,'全唐诗/poet.song.98000.json','["陽光潑血汗交頤，晚日政與長空宜。", "海神遊戲出霮䨴，風伯退聽停嘘吁。", "初如炎官火傘動，漸若寒露冰壺欹。", "九烏堕翼天地暗，六鰲矯首山川隨。", "飛來一峰横突兀，競秀萬壑排參差。", "岱宗坡陀太華小，少室破碎終南低。", "深谷婉麗發春態，髙巖磊落呈秋姿。", "峰青盤螺綰新髻，水碧分暈浮修眉。", "鸞翔鳯翥露纖巧，虎踞龍蟠驚崛奇。", "觀臺彷彿隱仙聖，樓閣縹緲生蛟螭。", "誰於天宇弄顯晦，力與地險論髙卑。", "盪胸稜稜各騰踏，翻手冉冉爭奔馳。", "平生腳底識南北，此日眼界迷東西。", "身輿欲上白銀闕，風馭不假青雲梯。", "三薰三沐謝世事，一丘一壑真吾栖。", "捫參歷井不憚遠，直恐夜半潛推移。"]'),
('a6b91005-86e4-431c-971a-d9e851513ec6','夏日同伯氏畢裕之守一程國材遊天寧登西山國材有詩次其韻','李彌遜','宋','宋诗','song-poetry','','[]','遊輪走朱蓋飛碧，路如羊腸山虎脊。',320,'全唐诗/poet.song.98000.json','["遊輪走朱蓋飛碧，路如羊腸山虎脊。", "奇觀多似九牛毛，塵服輕於一狐腋。", "禪房借枕空函丈，野磴榰笻座盈尺。", "陰崖日淡春杲杲，老樹風悲秋索索。", "丈人適意屢傾蓋，舍者忘形或爭席。", "已澆茗盌攬文字，不捉冰紈凍絺綌。", "飲中得仙思季真，方外分曹笑無奕。", "棋鋒未接已爭遁，筆陣將收猶請益。", "一生苦心太多事，半日閑身要投隙。", "急呼隔水破烟艇，更着穿雲躡山屐。", "晴巒陰障淺深畫，斷渚連洲耦奇畫。", "愚公百念久灰冷，妄境多岐自冰釋。", "閉門終欲老石經，煮鼎無心轉金液。", "舁籃二子已能步，對影三人不邀客。", "蝇頭比富五頃田，蝸角猶寬一區宅。", "飽諳世態罷整冠，脱略塵緣等遺舄。", "已甘流落臥深林，肯作紛紜踏長陌。", "紫陽峨峨百步近，白水粼粼一溪隔。", "床頭吟蛩已催候，枝上鳴蜩行削迹。", "相期日日曉脂車，去待山頭霜月白。"]'),
('14c2b4eb-30f3-45d1-8969-48327780af7a','遊龍潭','李彌遜','宋','宋诗','song-poetry','','[]','秦山破碎天上來，女媧仙去空崔嵬。',96,'全唐诗/poet.song.98000.json','["秦山破碎天上來，女媧仙去空崔嵬。", "中懸鳴玉二千尺，下有百尺青銅開。", "居龍變化出嘘吸，雨暗雲昏鬼神入。", "我來坐石秋水閑，雲影扶疏落空濕。", "浮丘容成不可俟，摩挲青壁著名字。", "兩翁下遊會有時，訪我鍾陵五松寺。"]'),
('5fd4d400-8fa8-4714-9b7c-fd058cf6de97','風雁行','李彌遜','宋','宋诗','song-poetry','','[]','閩山蒼蒼江水長，鴻雁北去隨春陽。',64,'全唐诗/poet.song.98000.json','["閩山蒼蒼江水長，鴻雁北去隨春陽。", "天寒野暗烟樹濕，雨急風髙驚斷行。", "前飛一雁鳴且顧，後飛一雁悲獨翔。", "傷心極目暮雲碧，兄弟南北俱相望。"]'),
('2be80415-342b-48ea-b5e3-57815a4e5090','蹈元作詩謂僕不當以蓮爲嫵媚而有偶有現空相之語復次韻以効齊物之說','李彌遜','宋','宋诗','song-poetry','','[]','登天不登山，觀海不觀水。',136,'全唐诗/poet.song.98000.json','["登天不登山，觀海不觀水。", "認苗須認根，論士須論世。", "君以空說蓮，無乃涉瓜李。", "我以蓮喻色，亦墮綺語戲。", "二罪一狀領，政坐各有以。", "一以清淨觀，一以富艷棄。", "不知真色中，即是大空耳。", "物生天地間，各以形自媚。", "若云皆實相，斯理恐無謂。", "君詩如烏有，我詩類亡是。", "得失付之塞上翁，對花大嚼金壺空。"]'),
('167ca220-a8c2-413f-8c19-c97e60404dfa','僕和蹈元蓮竹之什意在譽竹於蓮有投鼠之嫌明復知縣有作姑兩可之他日蹈元邀客置酒花下予不得無愧復用前韻以謝花云','李彌遜','宋','宋诗','song-poetry','','[]','藍田官舍碧山裏，南北紅蕖照明水。',176,'全唐诗/poet.song.98000.json','["藍田官舍碧山裏，南北紅蕖照明水。", "公餘喚客坐晚凉，不獨桃源真避世。", "舉杯欲酌還自愁，退之慚花不御李。", "卻持巵酒起謝花，我亦前言聊一戲。", "就令嫵媚正不惡，更向鄭公觀所以。", "世情好惡苦不常，富貴相親貧賤棄。", "與花俱是天涯人，萬事要同風過耳。", "花聞我語爲觧顔，一笑凝然作川媚。", "主人有酒君但傾，對花不飲竟何謂。", "宰官况有弄丸手，坐觧兩家歸兩是。", "花神莫浪疑山翁，翁心壁月當寒空。"]'),
('8e2c79cb-b2a9-4c41-803c-84ed57ed234c','再和明復蹈元之什','李彌遜','宋','宋诗','song-poetry','','[]','湓江散吏來萬里，借屋僧房冷如水。',176,'全唐诗/poet.song.98000.json','["湓江散吏來萬里，借屋僧房冷如水。", "支頤一束儻會心，容膝數椽真傲世。", "大而無用澗底松，過者不顧道傍李。", "賣刀買犢愧老農，汲水埋盆作兒戲。", "畫墁求飽人共嗤，懷璧雖珍吾不以。", "宰公政明一善收，丞公聲同衆瑕棄。", "着酒時澆磊塊胸，傳歌爲洗淫哇耳。", "坐中冰雪回冬臞，句裏雲烟發春媚。", "我慚匪報正羞縮，君肯包荒過稱謂。", "葛藤更與話短長，菽麥安能辨非是。", "但聞古來說龎公，搬柴運水不談空。"]'),
('07bb47e3-51bf-4d12-bbb9-6e5cdb3a2fc4','會飲得助亭分韻得千字','李彌遜','宋','宋诗','song-poetry','','[]','長松下蔭八尺椽，四壁不礙萬里天。',64,'全唐诗/poet.song.98000.json','["長松下蔭八尺椽，四壁不礙萬里天。", "水邉笙簧成兩部，月裏山河收大千。", "山中宰相塵中仙，杯如流星酒如泉。", "饑蟬暝鳥莫浪語，淨掃綠苔共醉眠。"]'),
('3b1cf85a-981d-4a4d-b327-5e12fcc3219e','君用承事載酒筠谿上分韻得竹字','李彌遜','宋','宋诗','song-poetry','','[]','髙荷蓋水臨風曲，美人卻扇耀紅玉。',128,'全唐诗/poet.song.98000.json','["髙荷蓋水臨風曲，美人卻扇耀紅玉。", "溪翁愛之看不足，密竹陰中坐幽獨。", "南鄰新醅手自灑，貯以鴟夷轉山腹。", "折松掃雲謝羈束，近水亭臺晚香馥。", "峰巒中央帖寒玉，影落杯心臥山綠。", "長瓶縱横醆未覆，更遣長鬚隔簾贖。", "酒酣歌罷睡已熟，覺來星稀斗插屋。", "人間此景眼未觸，只欠桓伊弄霜竹。"]'),
('67ccb9d0-c2d5-4a72-ae02-762ed08230af','與何西仲秉燭飲梅下','李彌遜','宋','宋诗','song-poetry','','[]','山茶著包大如繭，初見寒梢一花展。',160,'全唐诗/poet.song.98000.json','["山茶著包大如繭，初見寒梢一花展。", "强將老眼趁年華，日日芒鞋踏苔蘚。", "花神似苦山翁催，不問春風有深淺。", "樹頭紛紛弄月明，冰雪瓊瑤亂裁剪。", "癡□公事無了時，與花拚作十日期。", "闌風伏雨恐相逼，夜傍花陰燒燭隨。", "攀條嚼蕊興不盡，滿把自摘香傳衣。", "星星霜鬢簪不得，小撚疏英翻酒巵。", "兒童莫作吳歈聲，山翁正與花神盟。", "生愁一片風飄零，留取北枝寬作程。"]'),
('d73c951e-2bf8-4ac8-b3f3-8bceef9bcefe','送鄒德久還鄉在福唐作','李彌遜','宋','宋诗','song-poetry','','[]','長松瑟瑟搖悲風，方床冷枕鳴秋蛩。',160,'全唐诗/poet.song.98000.json','["長松瑟瑟搖悲風，方床冷枕鳴秋蛩。", "短衾客子起孤悶，平明歸思如春鴻。", "我家君家各陽羨，夢寐不聽閩山鐘。", "自從敵馬飲江水，去住彼此隨飛蓬。", "那知萬里一樽酒，碧雲落日聊春容。", "野林秋淨山更遠，樓殿突兀藏丹楓。", "銀鈎玉筯光照座，髙歌大笑聲摩空。", "長亭著鞭莫太早，愁色正在登臨中。", "一身四海會面少，况我與子俱成翁。", "徑須留作千日醉，坐看春風舒小紅。"]'),
('f12c4117-e190-4a6b-adc5-26dc6f8a0833','諸公送行分韻得驅字','李彌遜','宋','宋诗','song-poetry','','[]','儒生自信一束書，持以遊世觸事迂。',192,'全唐诗/poet.song.98000.json','["儒生自信一束書，持以遊世觸事迂。", "十步倒行一步立，公家不辨私家臞。", "壯無早計老更拙，宜去不去饑所驅。", "春風力回俗士駕，政恐猿鶴譏逃逋。", "燈前酌酒賴公等，一笑未徹還送予。", "飛接雙翼送好語，似欲挽我聯冠裾。", "那知物理有不可，欲置萬里笞黔驢。", "人言此雲無此雨，安用吻舌勞分疏。", "筠山如盤溪如愚，區有瓜芋水有魚。", "頡羹赤腳踏長鬚，醉步密竹交相扶。", "絕知君家一事無，肯爲老翁聊巾車。", "古人命駕成斯須，已催小槽壓真珠。"]'),
('1e134a82-fdb1-4368-92c9-8d2d64149c36','春送楊彦侯赴試建陽用曾南豐湖水碧韻','李彌遜','宋','宋诗','song-poetry','','[]','人生不合留飛黄，驪駒夜發生悲凉。',112,'全唐诗/poet.song.98000.json','["人生不合留飛黄，驪駒夜發生悲凉。", "馬蹄着沙去莫挽，一日萬里風雲翔。", "月明霜枝挂秋香，桂宫髙架辛夷梁。", "長梯摘日豈憚遠，世上不數瓊瑤光。", "我今官閑賦江海，老驥識路何由驤。", "昻霄氣槩看公等，金印入手真毫芒。", "更謀濁酒盡清夜，晚鼓徑欲催行装。"]'),
('aa0461bf-5031-4993-88b9-8f08662da1ed','次韻碩夫池亭賞蓮','李彌遜','宋','宋诗','song-poetry','','[]','胡床麈尾揮長柄，風和入座花容靚。',96,'全唐诗/poet.song.98000.json','["胡床麈尾揮長柄，風和入座花容靚。", "乍開還合晚照中，修竹佳人倚春暝。", "此間此景樂最深，世路好惡君酌斟。", "下車何必笑馮婦，投杼未免疑曾參。", "江山信美來者稀，淵明獨與田父違。", "誰云寧食艾三斗，不如杯行莫停手。"]'),
('60849c9c-2417-4d4f-8fdb-2545e1dda7ba','再次前韻','李彌遜','宋','宋诗','song-poetry','','[]','玉井花開十丈柄，天真不比鈆華靚。',96,'全唐诗/poet.song.98000.json','["玉井花開十丈柄，天真不比鈆華靚。", "長梯摘實埋金沙，碧甃吹香徹朝暝。", "風篁爲我清夜吟，拍浮酒泉不用斟。", "酒酣喝月下寒綠，玻璃影底羅辰參。", "江妃水仙尚依稀，凌波挽客亦重違。", "得錢何須問升斗，爲君更試持螯手。"]'),
('69d362eb-bd9a-4f0c-ac5d-abfeeeb80b26','黎道人自長沙入閩觧石見之論易頗有所得自言居醴陵山中有田廬養魚種竹可以卒歲作取足庵義方堂優游其間藏書敎子甚樂也遽還求詩贈之','李彌遜','宋','宋诗','song-poetry','','[]','兩腳不踏咸陽塵，兩眼不逐瀟湘春。',64,'全唐诗/poet.song.98000.json','["兩腳不踏咸陽塵，兩眼不逐瀟湘春。", "胸中乾坤照萬古，奇偶縱横何足數。", "閉門有竹食有魚，遺子有田家有書。", "一生可了心自足，世上紛紛謾榮辱。"]'),
('8d78ed5c-3b46-47f8-8b2a-204335028a2b','次韻似表弟卜居惠山間','李彌遜','宋','宋诗','song-poetry','','[]','梁溪舊隱吾家紳，石苔猶鎖松間門。',229,'全唐诗/poet.song.98000.json','["梁溪舊隱吾家紳，石苔猶鎖松間門。", "向來兄弟寄觴詠，日月轉轂相朝昏。", "自君之别各千里，萬金誰與通寒溫。", "棣華春遲風雨書，雁字月冷蒹葭村。", "似聞徑作買山計，歸夢已泊松江垠。", "吾衰久矣尚能飯，荷插豈憚終歲勤。", "獨無頃田占負郭，坐食病粟慚君恩。", "平生一壑志願畢，不求華屋装泉石。", "僧窗到處即爲家，柏子烟中聽鼻息。", "子今白髪頭尚希，未至閿鄉老王室。", "背山築室不必多，待我來鳴去前□。", "野蠶成繭真自纒，黄蜂作脾爲誰力。", "肱嘗三折飽更事，肯信謀身有長策。", "君不見子猷借居種竹聊自娯，有屋大奇無亦得。"]'),
('b00bf141-0f08-418f-acc1-9ad3f7b61ee1','粹之載酒南山僕與子婿輩乘小舟烟雨中絕江而來飯罷復過東閣道舊論文頺然經醉歸時夜潮已平雖雲陰未觧而月白可鑒煙林水嶼盡在目中良久急雨繼作通夕不止欹臥紙帳中了不成寐因作','李彌遜','宋','宋诗','song-poetry','','[]','海神遊戲千林昏，近山楓櫟丹黄分。',128,'全唐诗/poet.song.98000.json','["海神遊戲千林昏，近山楓櫟丹黄分。", "船頭着處翠陰重，屐齒一過留苔痕。", "鄰翁酌我苦短晝，下夜爲尊起爲壽。", "公榮可飲次公狂，不假朱絲轉長袖。", "燈前白髪懷抱開，與子臭味今陳雷。", "隙居勿起故時念，一笑沙際邀春回。", "密雲不障霜月明，枯樹欲沒江潮平。", "歸來臥聽墻壁語，萬壑松風瀉簷聲。"]'),
('c00772ed-e779-4087-9ab5-af74f9c9de3a','次韻葉觀文送杏花','李彌遜','宋','宋诗','song-poetry','','[]','春風不與寒威爭，輕雷自轉驚群萌。',160,'全唐诗/poet.song.98000.json','["春風不與寒威爭，輕雷自轉驚群萌。", "紛紛桃李厭開謝，杏蕚一吐增雙明。", "吾儕小人不敢觸，走送夜閤浮香傾。", "平明七字爲題品，蠻觸不戰收降兵。", "哦詩正喜涵清冰，攀條已恨飛紅英。", "愛花不似愛詩苦，世上餘物俱無情。", "使君喚客有髙致，半道未許杯盤成。", "舁籃日月走臺皁，不用二字邀門生。", "長檠照席語傾座，一笑轉我蒼顔頳。", "更窮山水訪禪寂，欲去政恐譏兼幷。"]'),
('da3a45e8-524a-4fb4-bda3-78ef14f823f5','和表之清陰亭作','李彌遜','宋','宋诗','song-poetry','','[]','西山朝來多爽氣，露沐風梳發新翠。',128,'全唐诗/poet.song.98000.json','["西山朝來多爽氣，露沐風梳發新翠。", "洩雲無力占山腰，初日分光上山背。", "遠山蒼茫近山紫，四面鐘魚談佛事。", "人間那得山爲城，玉亰聯錦互相似。", "先生結廬待三顧，道合寧論入宫妒。", "肯爲閩山得得來，蠟屐深尋九霄路。", "詩成逸興横太清，平明更作支提行。", "會須佳處吞八九，歸去與君增眼明。"]'),
('5f3846e7-5a66-4723-838a-93f3932196db','季申樞密設醴具素以待諸客表之有詩次其韻','李彌遜','宋','宋诗','song-poetry','','[]','擊鮮舉白不厭深，髙燒銀燭花成陰。',64,'全唐诗/poet.song.98000.json','["擊鮮舉白不厭深，髙燒銀燭花成陰。", "不如伊蒲雜棃栗，數翁共話千古心。", "夜闌相對如夢寐，靜聽墻壁生潮音。", "我方逃禪君莫斟，歸來星稀月初沉。"]'),
('9f3e737c-3815-455d-98d4-d8c36516dae3','題葉子寧林巢','李彌遜','宋','宋诗','song-poetry','','[]','誰穿空翠開蜂房，尺欄寸徑一肘墻。',176,'全唐诗/poet.song.98000.json','["誰穿空翠開蜂房，尺欄寸徑一肘墻。", "主人官閑若避俗，北窗髙臥追羲皇。", "客來初騎果下馬，側身卻轉花邉廊。", "新成桃李礙倚杖，旋徹戶牖留飛觴。", "欲眠姑去甘晝寂，不醉無歸拚夜長。", "使君早有冲天志，略展風翰無地試。", "已知齊物觀世間，小卜一枝聊自戲。", "坐中香穗亂雲影，睡起花甘攪禪味。", "鷄蟲得失何足論，鵬鷃升沉了無意。", "昔人掩鼻恐不免，天與公才那可置。", "清霜萬里看横秋，莫作南柯始封計。"]'),
('64f8bf7f-59fd-4dc6-a729-c33875dbfeca','案上梅','李彌遜','宋','宋诗','song-poetry','','[]','横枝當案雪未融，夜窗印月影若空。',64,'全唐诗/poet.song.98000.json','["横枝當案雪未融，夜窗印月影若空。", "人憐太痩不奈冷，自抱幽獨無愁容。", "春風雜花豈不好，一笑難與孤芳同。", "寧來作伴管城子，靜炷沉水聽號松。"]'),
('b3e48a02-8460-45b6-a66e-195889e9f56f','送李仲和之泉南其子官所','李彌遜','宋','宋诗','song-poetry','','[]','吾宗達士人所嗤，官居自視如雞棲。',160,'全唐诗/poet.song.98000.json','["吾宗達士人所嗤，官居自視如雞棲。", "十年借屋作僧夢，魚鼓聲中長抱饑。", "撐腸但有黄卷語，壘磈盡掃胸中奇。", "一朝起就綵衣養，喜氣已覺生鬚眉。", "阿龍官清酷似父，五斗未足供朝糜。", "芝蘭正喜在階砌，詩禮自可娯庭闈。", "願言早試餐玉法，富貴似與長年期。", "我今衰白心更老，結習尚餘傷别離。", "薰風南浦欲分手，菡萏未折凌波姿。", "徑須痛飲破愁本，酒醆旋折長荷絲。"]'),
('e7ee0dee-b913-454a-812a-f7b0875052a6','寄題向伯恭侍郎企疏堂','李彌遜','宋','宋诗','song-poetry','','[]','太冲扶策招隱士，德璋移文謝逋客。',192,'全唐诗/poet.song.98000.json','["太冲扶策招隱士，德璋移文謝逋客。", "欲分勝地髙世流，未辨賢愚相什百。", "薌林居士人中珍，胸中不點元規塵。", "平生絕口向阿堵，能使地上流錢神。", "紫荷曉直動天語，晝日駢蕃不如雨。", "急流乃作尺蠖盤，唾手功名何足取。", "歸來結屋清江干，十十五五窗巖巒。", "北窗岸幘夏日靜，夜雨對客春杯寒。", "漢廷宫傅計不早，篤老辭榮身已槁。", "那知黑髪踐亨衢，脱身紛紜事幽討。", "華堂未用標新目，兩翁政自晞髙躅。", "更從碧眼問入廛，卻訪赤松求辟穀。"]'),
('d91eb815-7407-48c3-9f36-079ddd7d734b','送族甥遊學臨安','李彌遜','宋','宋诗','song-poetry','','[]','薰風未放槐花黄，舉子技癢撩枯腸。',160,'全唐诗/poet.song.98000.json','["薰風未放槐花黄，舉子技癢撩枯腸。", "短衾不眠中夜起，鷄鳴刷羽摩參商。", "山行未盡趁落日，夜榜欲去驚鳴榔。", "男兒胸中小天下，大笑鑿石分餘光。", "君今懷璧自荐達，筆端娓娓陳虞唐。", "明時三面網英俊，平地一日看騰驤。", "青錢淡墨何足慕，闊步直入鴛雛行。", "歸懸金印大如斗，里官負弩驅旗槍。", "向來絃歌久未効，即遣士氣俱軒昻。", "吾衰不能効犖确，尚能杖履攜壺漿。"]'),
('af99fc25-f644-4fd7-bb0d-7160ed162620','和董端明大野漁父圖  其一','李彌遜','宋','宋诗','song-poetry','','[]','一葉扁舟漾廣津，無心鷗鳥遠親人。',32,'全唐诗/poet.song.98000.json','["一葉扁舟漾廣津，無心鷗鳥遠親人。", "蘋蓼岸，静投綸，危坐初無一點塵。"]'),
('b7ef62ea-18b7-4466-8f2f-77230d97afec','和董端明大野漁父圖  其二','李彌遜','宋','宋诗','song-poetry','','[]','釣艇夷猶一葦横，烟波萬頃寄餘生。',32,'全唐诗/poet.song.98000.json','["釣艇夷猶一葦横，烟波萬頃寄餘生。", "春雨歇，暮霞明，零亂溪花墮玉英。"]'),
('ed1c3f3a-796e-407a-9751-15c421e753cc','和董端明大野漁父圖  其三','李彌遜','宋','宋诗','song-poetry','','[]','撇棹歸來起暮凉，樂哉誰復慕軒裳。',32,'全唐诗/poet.song.98000.json','["撇棹歸來起暮凉，樂哉誰復慕軒裳。", "横短笛，罷鳴榔，紅藕花繁作陣香。"]'),
('eceb3051-762e-40ac-94d2-51ab9a09a41d','和董端明大野漁父圖  其四','李彌遜','宋','宋诗','song-poetry','','[]','木落漁村載酒過，綠波萍藻鱖魚多。',32,'全唐诗/poet.song.98000.json','["木落漁村載酒過，綠波萍藻鱖魚多。", "拚醉飲，儘顔酡，不負平生笠與簔。"]'),
('c1a16a7a-13b4-4746-a862-b35613a29380','和董端明大野漁父圖  其五','李彌遜','宋','宋诗','song-poetry','','[]','玉樹瓊田瑩骨清，短篷飄洒動吟情。',32,'全唐诗/poet.song.98000.json','["玉樹瓊田瑩骨清，短篷飄洒動吟情。", "魚換酒，樂升平，聞道君王日聖明。"]'),
('afcaae0a-1735-4b63-8020-7a92d7861fa4','和董端明大野漁父圖  其六','李彌遜','宋','宋诗','song-poetry','','[]','臥月眠風樂有餘，蒹葭處處釣重湖。',32,'全唐诗/poet.song.98000.json','["臥月眠風樂有餘，蒹葭處處釣重湖。", "斟魯酒，鱠鱸魚，一片家風入畫圖。"]'),
('2f70f382-1fc5-41b2-8075-f6cbb09d07ec','春雪','李彌遜','宋','宋诗','song-poetry','','[]','繁雲初弄日，累靄漸韜霞。',288,'全唐诗/poet.song.98000.json','["繁雲初弄日，累靄漸韜霞。", "夜色連空迥，春英入望賒。", "白霓分羽衛，青女亂簪珈。", "栩栩思輕蝶，飛飛欲盡花。", "瓊瑰纔瑣屑，龍鳯忽交加。", "騁歲邀難駐，便輕去莫遮。", "似因風伯力，偏助水官夸。", "闊布漫天陣，低成匝地窪。", "升階方浸潤，投隙任欹斜。", "雜遝爭排拶，縱横類攫拏。", "怙陰方洶洶，畏日尚譁譁。", "遇坎寧辭險，投荒忽匿瑕。", "誰能問畛域，何處辨隆窊。", "眺遠眸增眩，驚深吻盡呀。", "勢包誇海若，功蓋補天媧。", "賦象隨形巧，嘘枯與物華。", "黏枝拳宿鷺，拆竹響翻鴉。", "逕没虫書蘚，灘平鳥篆沙。", "凍池靜鳬鶩，凍草伏麋麚。", "弱柳封腰束，停莎老髻丫。", "圓方雜圭璧，牝牡失驪騧。", "砌走馮夷蚌，簷垂白帝蛇。", "趨明驚吏愕，唱曉誤雞啞。", "表沴愁交積，占豐信有涯。"]'),
('ddb2a908-f621-4d69-a844-599aa36d630a','劉根道院','李彌遜','宋','宋诗','song-poetry','','[]','仙去久不返，遺宫仍倚嵩。',48,'全唐诗/poet.song.98000.json','["仙去久不返，遺宫仍倚嵩。", "終疑白雲屋，猶隱綠毛翁。", "山曉水聚樹，秋深霜影空。", "它年結廬地，千古想真風。"]'),
('b93cb857-e543-4015-857b-544b1cca3c8a','天封觀','李彌遜','宋','宋诗','song-poetry','','[]','搖落秋山路，烟留寶搆昏。',48,'全唐诗/poet.song.98000.json','["搖落秋山路，烟留寶搆昏。", "曾迴翠華步，不到紫虚門。", "可鑑豐碑壯，無知老柏尊。", "勒功當日事，寂寞更誰論。"]'),
('7d4b168a-6086-40c9-b631-31b0429271e9','和少章喜晴','李彌遜','宋','宋诗','song-poetry','','[]','日暮馬行疾，峰巒過眼頻。',48,'全唐诗/poet.song.98000.json','["日暮馬行疾，峰巒過眼頻。", "雨階長苦夜，晴谷似逢春。", "風月起歸恨，江天思故人。", "機心渾已盡，唯有白頭新。"]'),
('337b08b4-9c86-4bda-a041-435115b59a7f','又和少章别','李彌遜','宋','宋诗','song-poetry','','[]','非無山林意，去住亦隨緣。',48,'全唐诗/poet.song.98000.json','["非無山林意，去住亦隨緣。", "落日有歸翼，亂山猶着鞭。", "風簷依路濕，烟樹著行圓。", "清絕歸時思，新詩句句傳。"]'),
('9a96dead-67b8-464e-a2e2-fdfe0adc4d90','發光林寺','李彌遜','宋','宋诗','song-poetry','','[]','朝發光林寺，崎嶇渡復攀。',48,'全唐诗/poet.song.98000.json','["朝發光林寺，崎嶇渡復攀。", "摳衣緣翠濕，側足下蒼顔。", "急雨欲平澗，斷雲時見山。", "祗應超勝地，行路未嘗難。"]'),
('20e5b359-7159-49a8-9638-e0975b3658be','瓜步阻風作  其一','李彌遜','宋','宋诗','song-poetry','','[]','西風趣秋去，何日放船迴。',48,'全唐诗/poet.song.98000.json','["西風趣秋去，何日放船迴。", "不見澄江練，唯聞捲地雷。", "宦遊雙鬢改，飄泊寸心灰。", "落日乾坤裏，微吟酒一杯。"]'),
('b3fed784-f1e2-4645-9b28-db2c2f1f9143','瓜步阻風作  其二','李彌遜','宋','宋诗','song-poetry','','[]','牢落窮途暮，扁舟水四涯。',48,'全唐诗/poet.song.98000.json','["牢落窮途暮，扁舟水四涯。", "十年長作客，萬里得還家。", "雲散山排仗，潮生浪趁衙。", "殷勤謝風馬，爲挂一帆斜。"]'),
('947377a1-4234-4938-9e19-0a76d4cf1e7c','次韻賁遠歸田  其一','李彌遜','宋','宋诗','song-poetry','','[]','歸去田園好，春隨人意和。',48,'全唐诗/poet.song.98000.json','["歸去田園好，春隨人意和。", "竹根晴日臥，牛角晚風歌。", "漂梗空三逕，虚舟信一波。", "故人憐寂寞，千里問如何。"]'),
('4e2d4896-1935-4d5f-920c-19287af95021','次韻賁遠歸田  其二','李彌遜','宋','宋诗','song-poetry','','[]','歸去田園好，饑餐抵萬錢。',48,'全唐诗/poet.song.98000.json','["歸去田園好，饑餐抵萬錢。", "愁從身外散，樂向酒中全。", "蠶出柔桑綠，秧齊小麥鮮。", "一廛何所寄，華髪繞江天。"]'),
('7e703a0a-bded-4dbd-889c-2aec7b4c1ac8','次韻賁遠歸田  其三','李彌遜','宋','宋诗','song-poetry','','[]','歸去田園好，秋還橘柚鄉。',48,'全唐诗/poet.song.98000.json','["歸去田園好，秋還橘柚鄉。", "稻梳縈带水，茅枕束芻篁。", "絕迹公門步，薰心佛土香。", "此生真逆旅，無慮可消忘。"]'),
('4793e696-6892-4369-84a5-67ab9c388db0','次韻賁遠歸田  其四','李彌遜','宋','宋诗','song-poetry','','[]','歸去田園好，門羅樹外峰。',48,'全唐诗/poet.song.98000.json','["歸去田園好，門羅樹外峰。", "地偏群燕雀，江靜隱魚龍。", "愁覓鄰家酒，眠憎近寺鐘。", "一春强半雨，誰與問凶豐。"]'),
('45e1a4db-89ab-4aef-9b60-1e538772727b','久雨阻遊昭亭有作','李彌遜','宋','宋诗','song-poetry','','[]','浪迹隨方寄，窮途觸事諳。',48,'全唐诗/poet.song.98000.json','["浪迹隨方寄，窮途觸事諳。", "雨逢春甲子，江滿地東南。", "客鬢霜前落，詩情酒外酣。", "上方愁獨往，藜杖許同參。"]'),
('924b5589-1cd2-4ca0-b556-041429eaa802','琴溪','李彌遜','宋','宋诗','song-poetry','','[]','竹色千鐘靜，溪光一鑑開。',48,'全唐诗/poet.song.98000.json','["竹色千鐘靜，溪光一鑑開。", "巖隈宿風雨，人迹老莓苔。", "控鯉定何在，騎鯨今不來。", "空餘泉上月，與我共徘徊。"]'),
('873a5493-3f1f-4ada-905e-d722503ab7b3','秋霜閣','李彌遜','宋','宋诗','song-poetry','','[]','十月水西寺，興窮還爲留。',48,'全唐诗/poet.song.98000.json','["十月水西寺，興窮還爲留。", "淨坊深閉雨，虚閣暗藏秋。", "妄盡霜中葉，身閑水上鷗。", "知幾傷太白，五月念貂裘。"]'),
('4793f86d-c1cc-40dd-b9a0-3f8582ad987c','綠竹閣','李彌遜','宋','宋诗','song-poetry','','[]','草木盡改色，孤標綠正繁。',48,'全唐诗/poet.song.98000.json','["草木盡改色，孤標綠正繁。", "曳雲扶勁節，欹石護盤根。", "靜者宜投迹，髙人時避喧。", "歲寒松柏共，何必在梁園。"]'),
('76b11ba9-258a-4aad-8b0a-23ed96b834a6','春日雜詠  其一','李彌遜','宋','宋诗','song-poetry','','[]','春到陵陽市，人家泊翠微。',48,'全唐诗/poet.song.98000.json','["春到陵陽市，人家泊翠微。", "南烹甘入筯，北戶暖生衣。", "花暗昭亭寺，魚肥句水磯。", "樂遊須結社，倒著接䍦歸。"]'),
('631948b0-e7b2-40da-b09c-6c4dac007839','春日雜詠  其二','李彌遜','宋','宋诗','song-poetry','','[]','幽棲足春事，晴日若相催。',48,'全唐诗/poet.song.98000.json','["幽棲足春事，晴日若相催。", "屐齒穿沙稳，笻鬚礙竹回。", "風光初轉蕙，殘雪欲欺梅。", "自是經過少，柴門日日開。"]'),
('b5bb43a5-1f0b-4914-b19e-9b78b33f9681','春日雜詠  其三','李彌遜','宋','宋诗','song-poetry','','[]','漸欲抛書卷，行藏任轉蓬。',48,'全唐诗/poet.song.98000.json','["漸欲抛書卷，行藏任轉蓬。", "負暄攜稚子，抱熟覓鄰翁。", "接葉猶妨徑，拳芽未着叢。", "主林真好事，爲我結新紅。"]'),
('a210a75a-05cc-4242-9fb4-d1bbba3dd700','春日雜詠  其四','李彌遜','宋','宋诗','song-poetry','','[]','役役炎凉態，悠悠道路賒。',48,'全唐诗/poet.song.98000.json','["役役炎凉態，悠悠道路賒。", "情懷知老大，夢幻閲紛華。", "攪思雲邉樹，供愁雨外花。", "生涯書一束，到處即爲家。"]'),
('9399d073-d3e3-4107-b918-32304339b7b6','春日雜詠  其五','李彌遜','宋','宋诗','song-poetry','','[]','憶昨金門侍，晨參玉佩聲。',48,'全唐诗/poet.song.98000.json','["憶昨金門侍，晨參玉佩聲。", "觧纓青瑣闥，束載錦官城。", "日與長安遠，春隨上苑生。", "執鞭非所好，獨抱戀軒情。"]'),
('45443928-ae44-4cbe-935c-46b47739a37d','春日雜詠  其六','李彌遜','宋','宋诗','song-poetry','','[]','不作觚稜夢，長閑地角身。',48,'全唐诗/poet.song.98000.json','["不作觚稜夢，長閑地角身。", "南冠欲從楚，西笑敢懷秦。", "鴻雁猶千里，牛羊絕四鄰。", "門羅今可設，更恐白頭新。"]'),
('a9164afb-153f-49b9-8012-f47828f779e4','春日雜詠  其七','李彌遜','宋','宋诗','song-poetry','','[]','懶慢嵇中散，寬閑得自怡。',48,'全唐诗/poet.song.98000.json','["懶慢嵇中散，寬閑得自怡。", "抱衾長恨晚，倒屐不嫌遲。", "網日蛛絲掛，梳烟柳髪垂。", "朝來被花惱，浪走習家池。"]'),
('562f6e04-7241-4bf8-9377-7356701a7991','春日雜詠  其八','李彌遜','宋','宋诗','song-poetry','','[]','二月忽已破，一春强半過。',48,'全唐诗/poet.song.98000.json','["二月忽已破，一春强半過。", "提壺工喚客，布穀巧當歌。", "得酒先愁盡，惜花翻恨多。", "逢辰不爲樂，明日復如何。"]'),
('765debd8-7b1b-484e-9242-8bd0acb0cf57','春日雜詠  其九','李彌遜','宋','宋诗','song-poetry','','[]','軒冕真成寄，江山早見招。',48,'全唐诗/poet.song.98000.json','["軒冕真成寄，江山早見招。", "懶從春後覺，意别枕邉消。", "竹色侵書靜，松聲落耳搖。", "妄心朝霧薄，烏鵲莫相撩。"]'),
('7668924a-fbb0-4751-af08-acec43b6c3c7','天慶道士何丹林作亭竹間方成予名之以秀野因留小詩','李彌遜','宋','宋诗','song-poetry','','[]','斫竹通圭竇，開垣列畫圖。',48,'全唐诗/poet.song.98000.json','["斫竹通圭竇，開垣列畫圖。", "乾坤藏小有，日月近方壺。", "樹色雲邉斷，山形地外孤。", "時來騁遊目，更爲剪繁蕪。"]'),
('eab20567-3370-40bc-b6d3-45f51bb663a5','寄題徑川劉子先逸軒','李彌遜','宋','宋诗','song-poetry','','[]','古縣溪山裏，深軒城郭餘。',48,'全唐诗/poet.song.98000.json','["古縣溪山裏，深軒城郭餘。", "地清從近市，朋好亦多車。", "雲隱尋山屐，風繙插架書。", "會看迎鶴版，不獨愛吾廬。"]'),
('3dfa4042-87c3-4c23-8519-8254df945155','彦術權郡大夫相邀昭亭以病酒不果往得所示佳句輒次韻呈','李彌遜','宋','宋诗','song-poetry','','[]','五馬行春路，松行舊不斜。',48,'全唐诗/poet.song.98000.json','["五馬行春路，松行舊不斜。", "醉眠方夢草，遊騎想穿花。", "訪古千秋暗，逃禪百慮賒。", "歸來傳麗句，字字敵春華。"]'),
('43e9091f-d687-48c6-a138-45082715e74f','早入昭亭與同遊散步山中自樵徑至水濱路窮還僧舍飯','李彌遜','宋','宋诗','song-poetry','','[]','散策春崗曉，樵蘇一徑長。',48,'全唐诗/poet.song.98000.json','["散策春崗曉，樵蘇一徑長。", "鈎衣藤掛石，斷路水浮塘。", "山靜竹生韻，池清蘭自香。", "禪房得深憇，魚鼓正鳴廊。"]'),
('54629306-d5dd-4625-93b8-e18e58d63721','山中遇雨','李彌遜','宋','宋诗','song-poetry','','[]','卯酒催歸夢，僧房借枕頭。',48,'全唐诗/poet.song.98000.json','["卯酒催歸夢，僧房借枕頭。", "客愁三日雨，山意十分秋。", "鳴澗漲還落，凝雲去復留。", "陽烏肯回翼，髙處卜深遊。"]'),
('e0d532d5-9fd7-4111-8970-2c951711ed88','再遊龍潭','李彌遜','宋','宋诗','song-poetry','','[]','密霧開深徑，幽奇得重行。',48,'全唐诗/poet.song.98000.json','["密霧開深徑，幽奇得重行。", "水光沉樹色，人語亂泉聲。", "仙去山容寂，龍遊雨陣輕。", "誰能築雲室，千古共凄清。"]'),
('f8d2c767-7f2a-4763-8907-1fc390c4ee5c','次韻舍弟遊本覺寺','李彌遜','宋','宋诗','song-poetry','','[]','招提俯秋水，畫手借王維。',48,'全唐诗/poet.song.98000.json','["招提俯秋水，畫手借王維。", "霜磬遞風韻，曉林翻露姿。", "茶煙邀客竚，帆影喚舟移。", "他日成歸夢，來興楚子悲。"]'),
('aa3a0be5-1563-4162-ad6b-78009feb35c4','池亭待月  其一','李彌遜','宋','宋诗','song-poetry','','[]','輕雷不成雨，風砌旋搘床。',48,'全唐诗/poet.song.98000.json','["輕雷不成雨，風砌旋搘床。", "山亂雲行曲，樓髙月路長。", "柴門非故國，戎馬尚他鄉。", "笳鼓悲清暝，關河思不忘。"]'),
('ce852c1a-fddf-4b18-8475-cca26d3f3e15','池亭待月  其二','李彌遜','宋','宋诗','song-poetry','','[]','不寐池塘夜，蕭蕭夏木重。',48,'全唐诗/poet.song.98000.json','["不寐池塘夜，蕭蕭夏木重。", "亭虚風趁客，水净月隨儂。", "蛙喜鳴如吹，蟬饑語似蛩。", "一區真自足，何地肯相容。"]'),
('36ce3a0c-114d-4e52-952d-bda3f29c4a78','發桐廬','李彌遜','宋','宋诗','song-poetry','','[]','江盡溪流合，行舟落照催。',48,'全唐诗/poet.song.98000.json','["江盡溪流合，行舟落照催。", "櫂歌來月浦，帆影上風桅。", "路轉山容改，潮平水色回。", "兵戈滿天下，飄泊壯心摧。"]'),
('47813932-d7f1-4973-a06d-395264c7d62c','次韻學士兄桐廬道中','李彌遜','宋','宋诗','song-poetry','','[]','溪水抱山曲，輕舟趁落霞。',48,'全唐诗/poet.song.98000.json','["溪水抱山曲，輕舟趁落霞。", "烟塵多戰壘，冠盖半浮家。", "紫塞空歸翼，黄河絕去槎。", "從誰論此事，心折莫雲賒。"]'),
('5c45d214-9802-46ff-a353-8f5c00e78032','次韻舍弟野望','李彌遜','宋','宋诗','song-poetry','','[]','蒼崖望不極，林際起孤烟。',48,'全唐诗/poet.song.98000.json','["蒼崖望不極，林際起孤烟。", "漁笛蒹葭岸，農歌䆉稏田。", "青涵濠上水，碧鎖峽中天。", "客鬢愁邉改，秋風又一年。"]'),
('10c6cb5f-5695-4e14-a9f0-34a45a3179f2','秋晚十詠 倚杖','李彌遜','宋','宋诗','song-poetry','','[]','倚杖看修竹，晚林疏雨秋。',48,'全唐诗/poet.song.98000.json','["倚杖看修竹，晚林疏雨秋。", "砧聲村遠近，風力鳥沉浮。", "愁鬢老前白，閑心物外休。", "出門無伴侣，小立看汀鷗。"]'),
('db3f0846-d3ee-4d8f-9fb8-63d1c348ff0c','秋晚十詠 瞑坐','李彌遜','宋','宋诗','song-poetry','','[]','隱几北窗靜，柏煙生鼎遲。',48,'全唐诗/poet.song.98000.json','["隱几北窗靜，柏煙生鼎遲。", "雨焦寒入座，風竹暗侵籬。", "貝葉談無相，桃花現不疑。", "叩床呼稚子，憐到暮鐘時。"]'),
('0938643c-3081-40ac-a70b-1593a5c95242','秋晚十詠 散策','李彌遜','宋','宋诗','song-poetry','','[]','散策北崗路，牛羊歸徑深。',48,'全唐诗/poet.song.98000.json','["散策北崗路，牛羊歸徑深。", "水窮人小立，山靜客微吟。", "點點稻花雨，團團榕葉陰。", "田翁罷爭席，明日共幽尋。"]'),
('929246ff-73a5-45da-a816-1e6ec61a4a6b','飲酒','李彌遜','宋','宋诗','song-poetry','','[]','淵明不止酒，屈原長獨醒。',48,'全唐诗/poet.song.98000.json','["淵明不止酒，屈原長獨醒。", "一樽有妙理，二子未忘形。", "車上無垂墜，眼中誰白青。", "陶然醒醉外，物我兩冥冥。"]'),
('c28e0494-2bca-494f-b781-8dabd5f1d926','飲酒 多病','李彌遜','宋','宋诗','song-poetry','','[]','茗椀醒晝寢，粥盂供晚餐。',48,'全唐诗/poet.song.98000.json','["茗椀醒晝寢，粥盂供晚餐。", "支離慚受粟，拓落笑爲官。", "幡影伽藍古，鈴聲窣堵寒。", "病多閑步屐，猶可據征鞍。"]'),
('698eb488-c965-44c6-9e16-8affc66a61fd','飲酒 不寐','李彌遜','宋','宋诗','song-poetry','','[]','不寐苦長夜，起看天未明。',48,'全唐诗/poet.song.98000.json','["不寐苦長夜，起看天未明。", "疏星微占曉，宿霧冷遮晴。", "人逐秋風老，事隨朝日生。", "南飛多過雁，早寄靖邊聲。"]'),
('4b7f5894-71b6-46b0-a980-a07d37587f97','飲酒 晚望','李彌遜','宋','宋诗','song-poetry','','[]','寒日倚江閣，晚雲低可攀。',48,'全唐诗/poet.song.98000.json','["寒日倚江閣，晚雲低可攀。", "溪翁隨水上，田婦赴虛還。", "幻境夢占夢，畏塗山復山。", "乾坤有餘地，閑處着衰顔。"]'),
('32f78713-f235-4dff-a583-f8688c572f7b','飲酒 客至','李彌遜','宋','宋诗','song-poetry','','[]','客至旋盥櫛，出門驚兩翁。',48,'全唐诗/poet.song.98000.json','["客至旋盥櫛，出門驚兩翁。", "山川十年隔，風雨一軒同。", "人事等飄瓦，生涯各轉蓬。", "時危命如羽，憂樂酒盃中。"]'),
('c4c3f8a8-727b-4772-9859-ac76642884fd','飲酒 臨海觀望','李彌遜','宋','宋诗','song-poetry','','[]','指極分南北，觀瀾混濁清。',48,'全唐诗/poet.song.98000.json','["指極分南北，觀瀾混濁清。", "盪胸金餅上，覿面玉繩横。", "洲渚平漚發，風雲一噫生。", "神山端可往，九萬作寬程。"]'),
('19550b29-88e4-4b79-9732-9adc29c79855','飲酒 懷遠','李彌遜','宋','宋诗','song-poetry','','[]','去年别懷玉，山浄覺秋髙。',48,'全唐诗/poet.song.98000.json','["去年别懷玉，山浄覺秋髙。", "歲月頻思夢，江湖多怨濤。", "無書寄風翼，有鬢着霜毛。", "獨立寒汀暮，忘言正鬰陶。"]'),
('0385313f-237c-4b4b-a649-86f706807e44','寄題陳氏尚遐亭','李彌遜','宋','宋诗','song-poetry','','[]','結屋秋荷上，塵心想坐忘。',48,'全唐诗/poet.song.98000.json','["結屋秋荷上，塵心想坐忘。", "露凝公子犖，風曳野人章。", "浪蘂終無實，多花根不長。", "知君有情尚，千柄竚幽香。"]'),
('e60f832f-3178-42f5-aee1-84b5bebb6307','和尚書兄留題興福','李彌遜','宋','宋诗','song-poetry','','[]','殿閣群峰合，山根一水長。',48,'全唐诗/poet.song.98000.json','["殿閣群峰合，山根一水長。", "簷楹接雲樹，鐘磬雜風篁。", "客枕愁花雨，齋魚攪夢梁。", "籃輿隔溪路，目斷佛龕香。"]'),
('b8293835-499a-4bda-b8f9-d07b620f3a90','次韻學士兄偶成','李彌遜','宋','宋诗','song-poetry','','[]','炎凉豈天意，四序自乘除。',48,'全唐诗/poet.song.98000.json','["炎凉豈天意，四序自乘除。", "畏暑漸退舍，雄風時引裾。", "據鞍慚類馬，下榻喜迎徐。", "吏退青燈裏，猶能辨蠧魚。"]'),
('5d990c4b-339c-4484-84f0-42564caa6d1a','次韻曾德明司理留題西山兼簡蘇宰  其一','李彌遜','宋','宋诗','song-poetry','','[]','層軒無礙石，支徑曲穿林。',48,'全唐诗/poet.song.98000.json','["層軒無礙石，支徑曲穿林。", "竹密催山暮，松搖亂客吟。", "琴書虚室冷，鐘鼓凈坊深。", "誰謂溪坡遠，能來社與岑。"]'),
('23f398d1-28c8-4b58-9b9b-109403845558','次韻曾德明司理留題西山兼簡蘇宰  其二','李彌遜','宋','宋诗','song-poetry','','[]','手種南階竹，關情一紀中。',48,'全唐诗/poet.song.98000.json','["手種南階竹，關情一紀中。", "倦游憎眼白，便靜脱塵紅。", "放浪淵明酒，浮遊禦寇風。", "吳霜鬢如許，何處覓還童。"]'),
('f42222b9-4653-4650-9e34-3038b47f9962','大暑久不請謁登南樓望成父西庵慨然奉思因成小詩','李彌遜','宋','宋诗','song-poetry','','[]','南郭子綦隱，西郊杜老居。',48,'全唐诗/poet.song.98000.json','["南郭子綦隱，西郊杜老居。", "風流知異代，臭味本吾廬。", "髙閣深繙貝，虚堂靜散書。", "經旬想顔色，着雨問何如。"]'),
('245c403c-a7fe-4464-88cd-b825d0488e62','寄樞密富丈','李彌遜','宋','宋诗','song-poetry','','[]','誤入衆香國，山深人境移。',48,'全唐诗/poet.song.98000.json','["誤入衆香國，山深人境移。", "松筠秋色老，樓殿午雲低。", "東閣傳書密，西郊去路遲。", "須煩造化手，爲展菊花期。"]'),
('e8b865d4-8ce0-49ec-a2a2-d00af83473e7','夏日與妙現老堂二公晚步江臯露坐月下夜分乃歸老堂有詩次其韻  其一','李彌遜','宋','宋诗','song-poetry','','[]','步屧榕根晚，明河九面横。',48,'全唐诗/poet.song.98000.json','["步屧榕根晚，明河九面横。", "兩禪方外得，一笑坐中成。", "雲去天逾碧，星垂月自明。", "寒江正留客，倚杖看潮生。"]'),
('107aad1f-af03-4358-b045-b8893f6c2ea8','夏日與妙現老堂二公晚步江臯露坐月下夜分乃歸老堂有詩次其韻  其二','李彌遜','宋','宋诗','song-poetry','','[]','胡床興不淺，未肯庾公賢。',48,'全唐诗/poet.song.98000.json','["胡床興不淺，未肯庾公賢。", "山意知秋近，江聲到寺前。", "夜凉新病後，月色正愁邉。", "可惜江南夢，青燈照不眠。"]'),
('f56d00c3-bb92-424e-a4e1-b0da83acc9fa','葵藿傾太陽','李彌遜','宋','宋诗','song-poetry','','[]','葵藿比君子，卑棲亦自榮。',72,'全唐诗/poet.song.98000.json','["葵藿比君子，卑棲亦自榮。", "葉隨朱夏盛，心逐太陽傾。", "大象無私照，孤黄不並生。", "風稍輕轉影，雲日澹留明。", "連茹懷君志，同根念舊情。", "拾遺千古恨，難奪戀軒英。"]'),
('5125de8f-7340-4216-bd6f-fdec41abcb16','次韻蘇粹之發幹見贈  其一','李彌遜','宋','宋诗','song-poetry','','[]','頽齡知有幾，誰復問行藏。',48,'全唐诗/poet.song.98000.json','["頽齡知有幾，誰復問行藏。", "散策蒼林靜，抛書白晝長。", "相呼山鳥聚，自落澗花香。", "此地無車馬，真成物我忘。"]'),
('b391f794-1e2b-43c5-bf14-d1daad0f9fff','次韻蘇粹之發幹見贈  其二','李彌遜','宋','宋诗','song-poetry','','[]','漂泊音書斷，艱難會合遲。',48,'全唐诗/poet.song.98000.json','["漂泊音書斷，艱難會合遲。", "那知休老地，卻數别君時。", "歲晚商山寂，天寒楚水悲。", "無言一杯酒，懷抱各相知。"]'),
('6c3cd6be-a5f3-403c-bded-7ac9ba8e9cb4','次韻王才元少師見贈','李彌遜','宋','宋诗','song-poetry','','[]','清晝髙軒過，巖髙得共攀。',48,'全唐诗/poet.song.98000.json','["清晝髙軒過，巖髙得共攀。", "蝦鬚深梵閣，豹尾靜塵寰。", "詞吐三江水，胸開九夢山。", "杯行不知夜，留月伴公還。"]'),
('8d5713df-03f6-44f2-acf9-fdfdf965e439','遊雪峰將至大目溪','李彌遜','宋','宋诗','song-poetry','','[]','造物隨人意，輕帆百里間。',48,'全唐诗/poet.song.98000.json','["造物隨人意，輕帆百里間。", "舟痕風力健，客枕櫓聲閑。", "山合塵縱斷，秋髙爽氣還。", "望州相見處，驀直透三關。"]'),
('74447661-147c-48e6-afbf-d8c53b40b4fc','和韻仲宗天寧見懷月餘臥病横山得其詩頗動念所以末句見意','李彌遜','宋','宋诗','song-poetry','','[]','病逢木上坐，攜我曲欄行。',48,'全唐诗/poet.song.98000.json','["病逢木上坐，攜我曲欄行。", "遠水兼潮闊，層山带角横。", "秋隨北雁到，愁向暮蛩生。", "正怯騷人句，詩壇莫浪盟。"]'),
('86dff584-f032-43f8-b48a-589dc4a21a58','觀儺','李彌遜','宋','宋诗','song-poetry','','[]','寶歷迎新露莢殘，水晶宫殿曉光寒。',64,'全唐诗/poet.song.98000.json','["寶歷迎新露莢殘，水晶宫殿曉光寒。", "日陪僊仗溫風轉，雲護神驅瑞靄盤。", "葦戟載頒均帝祉，桃弧一射致民安。", "威容曾許雲中見，又對彤墀得細看。"]'),
('6b2c1ded-7797-4d1c-b90e-144dd036aaad','駕還觀燈','李彌遜','宋','宋诗','song-poetry','','[]','琳宇風微寶輅還，春隨人意卻餘寒。',64,'全唐诗/poet.song.98000.json','["琳宇風微寶輅還，春隨人意卻餘寒。", "金堤花擁華芝蓋，銀漢雲扶白玉盤。", "宴及臣鄰三事協，歡均區宇九夷安。", "年年端闕龍燈試，萬歲聲中拜舞看。"]'),
('a7f8d849-c01b-4f38-a437-58ea02e2bb7a','角樓錫宴','李彌遜','宋','宋诗','song-poetry','','[]','春風樓閣燕需頒，歌近雲霄挂魄寒。',64,'全唐诗/poet.song.98000.json','["春風樓閣燕需頒，歌近雲霄挂魄寒。", "翠羽釵光輝蠟炬，紫霞杯影動鵰盤。", "天心首慶三時樂，國步知同九鼎安。", "午夜燭龍明别觀，傳呼猶許萬民看。"]'),
('9c6e991b-8931-4961-abfa-e99762b8e942','次韻司業兄方池詠蓮','李彌遜','宋','宋诗','song-poetry','','[]','秋水芙蓉四檻凉，淨臨明鏡試晨粧。',48,'全唐诗/poet.song.98000.json','["秋水芙蓉四檻凉，淨臨明鏡試晨粧。", "露凝月面濃施粉，日照□□□□□。", "預覓籧篨□□地，臥看池頭日腳忙。"]'),
('9d7f3b8e-fc7c-49da-8588-37e9ac8b8543','次韻陳君實先生  其一','李彌遜','宋','宋诗','song-poetry','','[]','閱世端如木偶人，不須離妄始逢真。',64,'全唐诗/poet.song.98000.json','["閱世端如木偶人，不須離妄始逢真。", "功深夜鼎三時火，候轉秋河萬里銀。", "可笑侏儒空飽粟，猶憐痀僂解凝神。", "他時應見鞭鸞鳯，老去浮藜不夜辰。"]'),
('8bc0563e-930c-4116-b2ea-5d6d5abf40b8','次韻陳君實先生  其二','李彌遜','宋','宋诗','song-poetry','','[]','騎馬長安漫踽凉，幾番桃李艷晨粧。',64,'全唐诗/poet.song.98000.json','["騎馬長安漫踽凉，幾番桃李艷晨粧。", "目官厭閱是非海，心地不聞知見香。", "九轉未能超北陸，一廛終待老南塘。", "會令堅白消同異，世事秋棋玉石忙。"]'),
('4d09f237-2d37-47a0-a58c-28a10bd159d3','和少章罌粟湯','李彌遜','宋','宋诗','song-poetry','','[]','旋烹雪粒勝瓊漿，撲鼻香浮繞夜窗。',64,'全唐诗/poet.song.98000.json','["旋烹雪粒勝瓊漿，撲鼻香浮繞夜窗。", "甘比玉蓮開太液，色分秋練凈澄江。", "魔軍戰睡猶堅壁，筆陣催詩欲納降。", "已聽鏗鏘驚俚耳，强顔猶把寸莛撞。"]'),
('809f7844-2d97-4cbc-9979-ac977301a671','秋月迴文','李彌遜','宋','宋诗','song-poetry','','[]','霜盤玉隱倒團金，迥水秋天碧夜侵。',64,'全唐诗/poet.song.98000.json','["霜盤玉隱倒團金，迥水秋天碧夜侵。", "光掩半扉寒夜永，影分疏竹翠軒深。", "長空遠岫歸雲捲，古木髙風浥露沉。", "凉袂客愁應夢楚，長城曉角夜悲吟。"]'),
('e568bb15-06e2-4829-9418-97d30652f382','出汴過淮有作','李彌遜','宋','宋诗','song-poetry','','[]','十年猶愧飽侏儒，卻到淮山識舊途。',64,'全唐诗/poet.song.98000.json','["十年猶愧飽侏儒，卻到淮山識舊途。", "一櫂輕於堂上芥，此身閑似水中鳬。", "受風帆影隨南北，弄日雲容自有無。", "不用乘桴泛滄海，半生全欲老江湖。"]'),
('108aa569-bdd3-4e8c-9e08-b7aef7e87b09','次韻待制兄題孔園芍藥  其一','李彌遜','宋','宋诗','song-poetry','','[]','紅藥開時春可憐，爛雲明錦破晴烟。',64,'全唐诗/poet.song.98000.json','["紅藥開時春可憐，爛雲明錦破晴烟。", "雍容近侍千花右，綽約翻階四戶前。", "不分柳條開白眼，直愁榆葉散青錢。", "我來偶落東風後，只有鮫綃處處傳。"]'),
('6d9afee6-aaeb-4d8b-93c8-0a746668684f','次韻待制兄題孔園芍藥  其二','李彌遜','宋','宋诗','song-poetry','','[]','絕勝河陽滿縣香，淡粧濃抺巧相望。',64,'全唐诗/poet.song.98000.json','["絕勝河陽滿縣香，淡粧濃抺巧相望。", "七言遠逼能詩謝，萬朵今聞好事黄。", "繡幕羅幃雲冉冉，風裳水珮日央央。", "紫薇花底根株在，寂寞山城亦自芳。"]'),
('60d24d4e-2aa7-408f-bdfd-177db13897ac','將到金陵投宿烏江寺','李彌遜','宋','宋诗','song-poetry','','[]','閱世真成一夢闌，塵埃誰復共開顔。',64,'全唐诗/poet.song.98000.json','["閱世真成一夢闌，塵埃誰復共開顔。", "辛壬癸甲常爲客，南北東西只問山。", "縈樹遠雲髙作蓋，護田流水曲於環。", "秋風送我江邉寺，凖擬如今到處閑。"]'),
('d8e57780-4205-4a0a-bb4a-fb9a6156a5aa','晚泊江口令小舟汲江心水烹葉璵雲谷碎冰散步岸滸顧望躊躇飄然有物外趣因成小詩云','李彌遜','宋','宋诗','song-poetry','','[]','不到鍾山二十年，江邉獨立思茫然。',64,'全唐诗/poet.song.98000.json','["不到鍾山二十年，江邉獨立思茫然。", "故園如夢南歸客，明日好風東去船。", "白鷺一雙輕照水，青鴉萬點遠漫天。", "何須痛飲排孤悶，一酌清甘勝酒泉。"]'),
('a14c8d2e-e9a5-44e7-881c-8b8786a03515','守風瓜步戲成','李彌遜','宋','宋诗','song-poetry','','[]','古語行船遇打頭，此言端可作予羞。',64,'全唐诗/poet.song.98000.json','["古語行船遇打頭，此言端可作予羞。", "平生漫起江山興，勝處偶爲波浪留。", "敗肉腐魚三日醉，斷蘆衰柳十分秋。", "蔣陵秀色應凋盡，造物還能借便休。"]'),
('d69b5910-6852-4f1b-bce9-583679a60fcc','用陸元覲韻','李彌遜','宋','宋诗','song-poetry','','[]','自笑愚翁老一溪，鬢絲庭草共萋萋。',64,'全唐诗/poet.song.98000.json','["自笑愚翁老一溪，鬢絲庭草共萋萋。", "愁邉日永人思睡，花上春濃鶯亂啼。", "十事未陳身已遠，三鍾無補首空低。", "年來灰冷人間念，惟有葵心日日西。"]'),
('f06967ca-be4d-44b5-bfa8-d152222e8fc1','和舍弟簡公序','李彌遜','宋','宋诗','song-poetry','','[]','百計疏慵一味閑，杖藜無日不尋山。',64,'全唐诗/poet.song.98000.json','["百計疏慵一味閑，杖藜無日不尋山。", "着鞭每到羲皇上，扶履欣同季孟間。", "寸步思君勞遠夢，七言驚我動衰顔。", "定無戞玉醻人句，拙速應勝隔歲還。"]'),
('2670d83f-bb7d-477f-a07c-05c4b4ebd2f8','夏日宿廣敎寺風月清甚思李白敬亭詩有懷用似表弟韻','李彌遜','宋','宋诗','song-poetry','','[]','衆鳥髙飛雲去閑，相看只有敬亭山。',64,'全唐诗/poet.song.98000.json','["衆鳥髙飛雲去閑，相看只有敬亭山。", "孤標尚想風塵外，佳句長留天地間。", "影落金牛撩客恨，手摩玉兔練仙顔。", "故山風月非人世，何事騎鯨去不還。"]'),
('ec4ddd5d-e049-4705-881f-33ac0a209d35','與公序避暑石盎方晝欲寢聞林間鳥鳴甚樂因得小詩云','李彌遜','宋','宋诗','song-poetry','','[]','一林啼鳥不知名，應怪山翁此地行。',64,'全唐诗/poet.song.98000.json','["一林啼鳥不知名，應怪山翁此地行。", "化蝶與周俱是夢，游魚知我久忘情。", "胸中丘壑真餘事，世上功名畏後生。", "但得盈樽供自酌，何妨人境臥淵明。"]'),
('70d60cfb-7301-40ff-a980-c1f58fc4d9b0','胡文恭倅宛陵距今將百年其後來官是邦者三人至士曹公下車始訪遺跡得石刻扵城北會勝寺即龕至官舍新棟宇於其上命曰紹堂屬余爲詩因以貽之','李彌遜','宋','宋诗','song-poetry','','[]','前賢不復夢逢迎，晚歲於公識典刑。',64,'全唐诗/poet.song.98000.json','["前賢不復夢逢迎，晚歲於公識典刑。", "肯子規橅誇錦繡，傳家翰墨炳丹青。", "碑存峴首長懷惠，學富韋門總带經。", "會見卿材從楚往，芝蘭不獨秀階庭。"]'),
('751fad85-e1e4-435b-8f93-be92fcee634c','次韻暘叔見示伽陀','李彌遜','宋','宋诗','song-poetry','','[]','無形何用强安名，只麽騰騰信腳行。',64,'全唐诗/poet.song.98000.json','["無形何用强安名，只麽騰騰信腳行。", "一事到頭猶是幻，萬緣何處可留情。", "雲歸夜壑空難狀，月落秋江影自生。", "唯有龎家老居士，不將塵境礙虚明。"]'),
('510ced35-84c3-48d8-a2d5-8e908d6a7e7b','冬雪呈太守張嵇仲  其一','李彌遜','宋','宋诗','song-poetry','','[]','夜氣凝空作暮寒，平明積雪欲藏山。',64,'全唐诗/poet.song.98000.json','["夜氣凝空作暮寒，平明積雪欲藏山。", "定知連臘連三白，已喜先春見一斑。", "神力巧將人意改，物華陰逐歲功還。", "憂民太守鈴齋暇，想對壺觴正解顔。"]'),
('56df71d4-b18d-4275-9420-901153904def','冬雪呈太守張嵇仲  其二','李彌遜','宋','宋诗','song-poetry','','[]','控鶴緣雲上廣寒，四看明玉鏤群山。',64,'全唐诗/poet.song.98000.json','["控鶴緣雲上廣寒，四看明玉鏤群山。", "鋪簷漠漠魚鱗合，入壟離離虎脊斑。", "整馭炎官方退聽，將妃白帝肯言還。", "豐年預作田家喜，不獨三鍾慰病顔。"]'),
('abbaf894-1335-4667-a471-584de852db15','冬雪呈太守張嵇仲  其三','李彌遜','宋','宋诗','song-poetry','','[]','插簷冰筯長新寒，薄日欺雲到屋山。',64,'全唐诗/poet.song.98000.json','["插簷冰筯長新寒，薄日欺雲到屋山。", "見晛半消梅額粉，因風猶染鬢毛斑。", "書生閉戶眠仍稳，遊子扁舟興欲還。", "客裏情懷逢歲晚，麴生邀我一開顔。"]'),
('82fda929-74e3-4209-bcb0-d055c7247776','邵暘叔用寒字韻作詩見貽復次韻答之','李彌遜','宋','宋诗','song-poetry','','[]','世德蘭金久未寒，交情傾蓋有如山。',64,'全唐诗/poet.song.98000.json','["世德蘭金久未寒，交情傾蓋有如山。", "天衢尚斂摶風翼，澤國難留隐霧斑。", "夜棹月溪成莫逆，春輿蓮社訪無還。", "逢場戲事多應暇，詩酒頻過陋巷顔。"]'),
('ac951093-c966-4a63-8443-7991dd322b9e','次韻陸虞仲學士塗中詠雪  其一','李彌遜','宋','宋诗','song-poetry','','[]','可笑無氈老鄭虔，甘寒忍喜詠豐年。',64,'全唐诗/poet.song.98000.json','["可笑無氈老鄭虔，甘寒忍喜詠豐年。", "飛花穿樹春疑早，秀麥分岐瑞有先。", "白玉樓成迷萬井，青雲路繞認雙川。", "輕縑窘幅終難狀，卻借騷人好句傳。"]'),
('b3f9c6c8-b654-4bc4-ad91-903083530294','次韻陸虞仲學士塗中詠雪  其二','李彌遜','宋','宋诗','song-poetry','','[]','歲行去似客程兼，詩債新隨雪陣添。',64,'全唐诗/poet.song.98000.json','["歲行去似客程兼，詩債新隨雪陣添。", "唱絕郢人誇潔白，舞低趙女鬬輕纖。", "寒威瑩骨勝三沐，爽氣薰心解六黏。", "險語賡酬難自勉，旋乾吟筆盡更籖。"]'),
('10dd9c64-66c6-4b65-97ad-e57d994015bc','次韻似表弟喭梅之作','李彌遜','宋','宋诗','song-poetry','','[]','萬點隨風更是愁，從敎停雪破除休。',64,'全唐诗/poet.song.98000.json','["萬點隨風更是愁，從敎停雪破除休。", "蓬萊花使漫青眼，姑射神人新白頭。", "待價瓊環聊可擬，聞風桃李亦增羞。", "看殘紅紫冰霜後，一笑春前解百憂。"]'),
('a202b7e8-e6ae-4686-bf7b-51cc3f305e64','春近風日漸佳與似表弟開小戶縱步後庭','李彌遜','宋','宋诗','song-poetry','','[]','圍爐人散長寒煤，暖日還催墐戶開。',64,'全唐诗/poet.song.98000.json','["圍爐人散長寒煤，暖日還催墐戶開。", "春近郊原思夢蝶，雪殘池館見真梅。", "客愁宛轉凌雙鬢，歲律侵尋寄一杯。", "試繞小欄尋翠甲，履痕猶占舊蒼苔。"]'),
('91609c88-df21-46e7-b127-a8f094f20fd9','次韻邵暘叔秋日懷歸','李彌遜','宋','宋诗','song-poetry','','[]','天將物色助詩鳴，秋入吟肩句倍清。',64,'全唐诗/poet.song.98000.json','["天將物色助詩鳴，秋入吟肩句倍清。", "欲爲鱸蓴修故事，喜聞鴻雁寄先聲。", "脱身鞅掌謀須早，過眼紛華夢已成。", "他日柴桑許同社，爲君漉酒具南烹。"]'),
('796d7b16-22a0-496c-90f3-b785ba1ff36a','次韻王彦聲贈梅公擇','李彌遜','宋','宋诗','song-poetry','','[]','詩梅傲世獨深居，氣與孤雲共捲舒。',64,'全唐诗/poet.song.98000.json','["詩梅傲世獨深居，氣與孤雲共捲舒。", "客轍每逢樽有酒，劍歌休嘆食無魚。", "鯨波坐隔三山外，鵬翼終騰萬里餘。", "冠玉圍金真戲事，醉髯聊復一軒渠。"]'),
('1e000e1a-5f68-4425-b008-bf03476941fe','送王彦聲歸苕溪  其一','李彌遜','宋','宋诗','song-poetry','','[]','盛世英才偶未逢，寄身無地轉如蓬。',64,'全唐诗/poet.song.98000.json','["盛世英才偶未逢，寄身無地轉如蓬。", "詩親東野窮尤壯，賦擬相如老更工。", "鵰鶚不飛行奮迅，璠璵未獻要磨礲。", "會須自要唐衢薦，誰與吹嘘借便風。"]'),
('27fda825-4406-43a3-9ed2-27be0bf03276','送王彦聲歸苕溪  其二','李彌遜','宋','宋诗','song-poetry','','[]','相逢華髪兩星星，舊事邯鄲一夢驚。',64,'全唐诗/poet.song.98000.json','["相逢華髪兩星星，舊事邯鄲一夢驚。", "舌底雌黄諳世味，眼中青白見交情。", "餘杯更覓論文具，好樹休啼喚客聲。", "後夜扁舟苕霅路，半輪寒月一溪横。"]'),
('4203adea-3bd9-419d-92cb-ef67c7816771','奉陪趙彦術登疊嶂還飲陵峰梅竹間','李彌遜','宋','宋诗','song-poetry','','[]','春曉飛花一尺圍，旋看風力屑瓊瑰。',64,'全唐诗/poet.song.98000.json','["春曉飛花一尺圍，旋看風力屑瓊瑰。", "廣寒宫殿千門啟，群玉峰巒四面開。", "直節自强深笑竹，清姿堪竝絕知梅。", "使君賸有延枝意，收拾寒光上酒杯。"]'),
('ad90be23-ec32-4801-a5f6-4edd596108eb','似表弟之錢塘約歲前歸愆期不至以詩寄之','李彌遜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪泥斷路屋生雲，暗坐陵陽一月春。',64,'全唐诗/poet.song.98000.json','["雪泥斷路屋生雲，暗坐陵陽一月春。", "黄犬有知空寄恨，青氈無夢獨傷神。", "急行已負梅花約，漸老長思棣蕚親。", "盡吸西湖來着語，莫拚風月付勞薪。"]'),
('d4ffa2db-b035-4957-985a-c7e16d8c5a6e','復用前韻簡叔共文伯公序三友','李彌遜','宋','宋诗','song-poetry','','[]','老覺身名雨後雲，靜看人事臘前春。',64,'全唐诗/poet.song.98000.json','["老覺身名雨後雲，靜看人事臘前春。", "愁邉痛飲真長策，詩罷髙歌覺有神。", "遠想兩生如可作，晚從三子更相親。", "北山剩欲招逋客，未用皇皇歎積薪。"]'),
('24557402-e990-4e2f-9046-ac20cbd3b3c4','春雨不止復用前韻書懷呈諸友','李彌遜','宋','宋诗','song-poetry','','[]','時序驚人翻手雲，不禁風雨破除春。',64,'全唐诗/poet.song.98000.json','["時序驚人翻手雲，不禁風雨破除春。", "岸容故故留花使，夜色明明助稼神。", "異縣逢人思故舊，長年作客見疏親。", "窮途自喜多閑日，虚費公家十束薪。"]'),
('61cb2daf-a9fc-4ea5-b9e4-b43002eb4d1b','寄題陶氏一經堂','李彌遜','宋','宋诗','song-poetry','','[]','金牛勝氣未全無，朝挹江山近結廬。',64,'全唐诗/poet.song.98000.json','["金牛勝氣未全無，朝挹江山近結廬。", "避席青衿家有塾，下帷皓首腹多書。", "階庭早見芝蘭秀，門巷於今燕雀疏。", "傍舍不應多種柳，後來駟馬要回車。"]'),
('c509141c-9b87-4268-9022-dc5dd59739ae','送邵文伯歸溧陽','李彌遜','宋','宋诗','song-poetry','','[]','盍簪異縣亦三年，浮木逢龜信偶然。',64,'全唐诗/poet.song.98000.json','["盍簪異縣亦三年，浮木逢龜信偶然。", "忙裏詩筒長遣客，靜中酒戶不妨禪。", "酸寒溧尉君今似，枯槁湘原我自憐。", "别後彈冠應不免，着鞭莫遣祖生先。"]'),
('9c45ff43-eb30-43dc-93d1-5435f8db53df','僕與公采戶曹奉議有先世之契又舊從其伯仲遊今復相遇於此前日偶過西鄰不知嘗辱車馬承貺佳什次韻爲謝','李彌遜','宋','宋诗','song-poetry','','[]','縛柴窄窄晝常關，剝啄髯參興盡還。',64,'全唐诗/poet.song.98000.json','["縛柴窄窄晝常關，剝啄髯參興盡還。", "不聽髙譚如屑玉，强酬好句似登山。", "論交此地逢三益，識面他時熟兩難。", "更憶金蘭家世舊，公餘能復共開顔。"]'),
('2ecb2e7c-72ad-43a8-a166-7fa36d1857a6','次韻邦直通判少尹題普現堂見簡之作','李彌遜','宋','宋诗','song-poetry','','[]','飽知世路厭陳人，分得僧窗寄此身。',64,'全唐诗/poet.song.98000.json','["飽知世路厭陳人，分得僧窗寄此身。", "載月筍輿成獨往，緣雲藜杖與誰親。", "足間優鉢藏千界，掌上庵摩等一塵。", "賴得詩翁來着語，五松從此有知津。"]'),
('148bb751-9893-45b0-8d45-be395579db04','席上分韻賦梅花得知字','李彌遜','宋','宋诗','song-poetry','','[]','寒梅獨笑野人扉，只有春風許自知。',64,'全唐诗/poet.song.98000.json','["寒梅獨笑野人扉，只有春風許自知。", "蠟屐追芳輸我輩，着鞭持酒記他時。", "白霓行處玉妃從，明月光中寶璐垂。", "更與丁寧後來秀，醉中來折最髙枝。"]'),
('d8483727-cd0a-4c49-ba4e-c4aca9306f0d','雲門道中晚步','李彌遜','宋','宋诗','song-poetry','','[]','層林疊巘暗東西，山轉崗回路更迷。',64,'全唐诗/poet.song.98000.json','["層林疊巘暗東西，山轉崗回路更迷。", "望與游雲奔落日，步隨流水赴前溪。", "樵歸野燒孤煙盡，牛臥春犂小麥低。", "獨繞輞川圖畫裏，醉扶白叟杖青藜。"]'),
('f1b602a5-c61f-4f5c-ade4-f1382b761a45','渡横溪','李彌遜','宋','宋诗','song-poetry','','[]','百尺滄浪兩岸沙，肩輿徒涉步欹斜。',64,'全唐诗/poet.song.98000.json','["百尺滄浪兩岸沙，肩輿徒涉步欹斜。", "溪聲猶带夜來雨，山色漸分雲外霞。", "岸半斷林開鳥道，水邉疏竹近人家。", "塵埃何處尋真境，試逐寒流認落花。"]'),
('aab039b9-38a3-4fe9-a45a-d25e7d57e5ae','陪五馬諸公遊西山泛舟待月而歸偶作','李彌遜','宋','宋诗','song-poetry','','[]','鳥烏聲樂報新晴，起覓鄰翁作隊行。',64,'全唐诗/poet.song.98000.json','["鳥烏聲樂報新晴，起覓鄰翁作隊行。", "愛日葵心傾爛熳，尋春蝶夢去縱横。", "人歸髙屋山逾碧，船到平灘月已生。", "客裏不諳風景好，欲將此夕竝登瀛。"]'),
('920923ca-875c-467b-b1a4-118c76f04d8d','留題新安幕府聚秀軒','李彌遜','宋','宋诗','song-poetry','','[]','星聚群賢上幕賓，層軒髙敞枕溪漘。',64,'全唐诗/poet.song.98000.json','["星聚群賢上幕賓，層軒髙敞枕溪漘。", "一時盧駱王楊輩，望重東西南北人。", "句裏江山端有助，學餘民社政須親。", "青冥接跡他年事，晋地卿材半楚臣。"]'),
('bf33aabd-b078-489c-9083-921bbd43b5c0','次韻畢裕之喜雨','李彌遜','宋','宋诗','song-poetry','','[]','急雨翻盆破鬰蒸，疏簷冰簟正關情。',64,'全唐诗/poet.song.98000.json','["急雨翻盆破鬰蒸，疏簷冰簟正關情。", "維摩示疾原非病，庾信裁詩老更清。", "遊戲雲生春浪勢，吉祥風動夜潮聲。", "麥秋未飽千畦潤，更遣豐隆爲一行。"]'),
('7059250c-2120-4271-bf97-d382395373d2','曹溪道中呈何公顯','李彌遜','宋','宋诗','song-poetry','','[]','筍輿訪古出秋原，山網重重護石田。',64,'全唐诗/poet.song.98000.json','["筍輿訪古出秋原，山網重重護石田。", "水接桃花源上路，人行巫女峽中天。", "要令陶冶誇盤谷，何必丹青貌輞川。", "寄語能詩何水部，筆端應許見雲烟。"]'),
('eefe8a9a-4b25-4659-be32-28125508a32d','次韻子才曹溪道中','李彌遜','宋','宋诗','song-poetry','','[]','偶脱塵纓百慮寬，更窮目力快遐觀。',64,'全唐诗/poet.song.98000.json','["偶脱塵纓百慮寬，更窮目力快遐觀。", "旋謀濁酒招强伴，行拾落英供晚餐。", "樹擁山根張密幄，雲隨雨腳是驚湍。", "試追健筆難何似，倒策駑駘上石巒。"]'),
('74e6b13f-1019-4337-b7bb-568ba860f2d9','次韻舜選大夫客舍中秋','李彌遜','宋','宋诗','song-poetry','','[]','命駕星郎獨感時，興隨孤月到雲涯。',64,'全唐诗/poet.song.98000.json','["命駕星郎獨感時，興隨孤月到雲涯。", "當天飛鏡空撩恨，永夜明樓謾攪詩。", "後閣深藏桃葉女，前驅須趁菊花期。", "與君更卜東鄰醉，放盞車輪又北馳。"]'),
('5b132d2d-9781-44aa-ac7a-61babb1270c2','次韻國村送遊黄山之作  其一','李彌遜','宋','宋诗','song-poetry','','[]','雨足郊原長稻孫，竹輿去路踏秋芬。',64,'全唐诗/poet.song.98000.json','["雨足郊原長稻孫，竹輿去路踏秋芬。", "近村籬落低臨水，直面峰巒半出雲。", "晚徑無人重着履，夜堂有酒更論文。", "兹遊清絕羲皇上，少借風烟爲沐薰。"]'),
('380da1a0-2ab9-4c09-a4e0-5d75716fafc6','次韻國村送遊黄山之作  其二','李彌遜','宋','宋诗','song-poetry','','[]','雅道於今久寂寥，規橅君肯到祈招。',64,'全唐诗/poet.song.98000.json','["雅道於今久寂寥，規橅君肯到祈招。", "鯨牙浪闊傾三峽，鵬背雲髙負九霄。", "但覓圖書供閉戶，不憂勳業誤題橋。", "七言起我黄山興，若第詩功不愧蕭。"]'),
('d1eafcac-5942-49f7-9f74-e30c0441fd83','次韻子才湯泉出浴','李彌遜','宋','宋诗','song-poetry','','[]','泉出靈沙氣可蒸，滌除那復數冰清。',64,'全唐诗/poet.song.98000.json','["泉出靈沙氣可蒸，滌除那復數冰清。", "九陽晞髪塵纓淨，七日煉形僊羽輕。", "暖沃丹田催進火，陰消神谷助長生。", "雲龍儻借凌空便，徑謁南臺季偉兄。"]'),
('9c7e3b23-2c48-4acb-b82a-3df44788101e','偉長知縣奉議年兄作别十年邂逅於此復有數百里之隔以詩見寄輙次韻爲謝','李彌遜','宋','宋诗','song-poetry','','[]','對着青衫下帝宸，十年不與並爲仁。',64,'全唐诗/poet.song.98000.json','["對着青衫下帝宸，十年不與並爲仁。", "憐君臥困千金骨，笑我行摧四角輪。", "老眼相逢俱作客，新諸遠寄底驚人。", "書來更數無多語，賸欲招攜白水濱。"]'),
('25115bde-a47a-43b5-b6a8-30473ce0f574','東崗晚步','李彌遜','宋','宋诗','song-poetry','','[]','飯飽東崗晚杖藜，石梁横渡綠秧畦。',64,'全唐诗/poet.song.98000.json','["飯飽東崗晚杖藜，石梁横渡綠秧畦。", "深行徑險從牛後，小立臺髙出鳥棲。", "問舍誰人村遠近，喚船别浦水東西。", "自憐頭白江山裏，回首中原正鼓鼙。"]'),
('80505d23-9cad-4b55-b47b-3077b3184291','和似表弟次吳江','李彌遜','宋','宋诗','song-poetry','','[]','路入吳江眼倍明，長谼雨立萬□□。',64,'全唐诗/poet.song.98000.json','["路入吳江眼倍明，長谼雨立萬□□。", "仙翁曾下遼天鶴，詩老猶傳跨海鯨。", "夜榜風蒲嗟去國，秋山雲履趁尋盟。", "憑誰剪取半江水，要聽寒潮枕底鳴。"]'),
('10831eee-f83f-4bed-a09f-17efcacbf343','和小君遊靈隱寺','李彌遜','宋','宋诗','song-poetry','','[]','俗子叢中暫撥忙，團蒲中夜擬禪房。',64,'全唐诗/poet.song.98000.json','["俗子叢中暫撥忙，團蒲中夜擬禪房。", "瀾頭巖穴仙都邃，石上軒楹佛土香。", "宿雨生秋醒客夢，霽雲回日借山光。", "歸塗芳物酬佳興，白菊丹楓試晚粧。"]'),
('74c79529-508d-4b17-94fb-fffcedf5924a','次韻學士兄富陽道中','李彌遜','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江送客靜波瀾，路入回溪第一灣。',64,'全唐诗/poet.song.98000.json','["長江送客靜波瀾，路入回溪第一灣。", "石瀬横陳潮力減，風檣陡轉櫓聲閑。", "驅除方寸無窮事，領略平生未識山。", "自笑疏慵似中散，政宜拓落水雲間。"]'),
('21f9b757-f1c1-4146-b372-087c20ba5fd2','將至澤溪','李彌遜','宋','宋诗','song-poetry','','[]','護溪疊嶂隱長城，直下寒流泯泯清。',64,'全唐诗/poet.song.98000.json','["護溪疊嶂隱長城，直下寒流泯泯清。", "背水人家認雞犬，隔林佛屋聽鐘鯨。", "山根合處客帆過，日腳斷邉漁火明。", "投老一身無地着，欲憑雙槳寄浮生。"]'),
('f79e0ce5-fabb-4f37-a45a-c4bf987fd8fa','至玉山謁尚書兄以九日復告别途中寄之','李彌遜','宋','宋诗','song-poetry','','[]','小隱精廬占一丘，趁行覊雁遠相求。',64,'全唐诗/poet.song.98000.json','["小隱精廬占一丘，趁行覊雁遠相求。", "豺狼當道誰青眼，兄弟他方俱白頭。", "問舍終同茅屋老，榰車聊共菊花秋。", "碧雲落日又分手，路細山長人更愁。"]'),
('e3bbb5a8-cc4a-4db6-9f54-0f225f7520ee','和士特韻程進道舍人','李彌遜','宋','宋诗','song-poetry','','[]','旌旆光華走皁輿，斑衣星使奉安車。',64,'全唐诗/poet.song.98000.json','["旌旆光華走皁輿，斑衣星使奉安車。", "尊罍方薦龜蓮壽，雨露交馳鶴板書。", "三釡及親真可樂，一經教子未全疏。", "馬蹄又踏春風去，勳業君看縱壑魚。"]'),
('f013ca05-d410-46a2-bdc2-db059bceb27d','和李相園亭  其一','李彌遜','宋','宋诗','song-poetry','','[]','軒戶新成紫翠邉，花光竹色借廚烟。',64,'全唐诗/poet.song.98000.json','["軒戶新成紫翠邉，花光竹色借廚烟。", "詩人莫浪誇盤谷，畫手無工貌輞川。", "何必吾廬在丘壑，要令是處有林泉。", "此心正恐無人會，把酒南山一笛前。"]'),
('b36580ab-dc45-4249-a8ad-4bfc35e066ea','和李相園亭  其二','李彌遜','宋','宋诗','song-poetry','','[]','肯將戲事擾虚懷，草木知名一様裁。',64,'全唐诗/poet.song.98000.json','["肯將戲事擾虚懷，草木知名一様裁。", "不放寸陰隨手過，自開十畝待春來。", "花邉未許楚狂醉，江上應憐野老哀。", "賸欲着鞭陪勝賞，扶顛正急萬牛材。"]'),
('2b676b50-67ca-4bd6-ae6a-44cf06185a9b','訪雪峰真歇禪師','李彌遜','宋','宋诗','song-poetry','','[]','紅塵白髪不相投，來就僧房借板頭。',64,'全唐诗/poet.song.98000.json','["紅塵白髪不相投，來就僧房借板頭。", "大士法中龍象貴，老翁心外水雲浮。", "長蘆江靜千山月，枯木巖寒一葉秋。", "别後相逢重着語，牧童横笛倒騎牛。"]'),
('22b0846a-3ca0-46bc-9343-d90da5d21106','王巖起樂齋','李彌遜','宋','宋诗','song-poetry','','[]','漫浪行地一舟虚，神手逢場樂有餘。',64,'全唐诗/poet.song.98000.json','["漫浪行地一舟虚，神手逢場樂有餘。", "客裏縱令懷舊國，公家何必愛吾廬。", "飽知世事同分鹿，肯爲時名更羡魚。", "吏退晴窗春睡足，牙籖狼籍滿床書。"]'),
('f3673c2d-a90a-447a-8936-574142a897a3','次韻錢申伯山堂之詠','李彌遜','宋','宋诗','song-poetry','','[]','淨坊秋色老蒼官，簷額飛雲細可攀。',64,'全唐诗/poet.song.98000.json','["淨坊秋色老蒼官，簷額飛雲細可攀。", "客夢偶隨疏雨斷，僧游長带暮鐘還。", "似聞遺錫藏銀地，親見髙人住骨山。", "愁絕寒江歸去路，亂峰青處望雙鬟。"]'),
('40193f24-22d2-4522-ab8e-50da6ba646c0','和錢申伯遊東山聖泉','李彌遜','宋','宋诗','song-poetry','','[]','偶脱塵中一夢闌，欲窮幽事遍尋山。',64,'全唐诗/poet.song.98000.json','["偶脱塵中一夢闌，欲窮幽事遍尋山。", "靜憐人境雞虫擾，老愜僧窗枕簟閑。", "十里秋香隨屐齒，四更山月上簾顔。", "登臨物色催詩興，未信天於我輩慳。"]'),
('49c0657c-3dfd-4d42-80ea-7993c6dc8930','題汪祖義桂林堂','李彌遜','宋','宋诗','song-poetry','','[]','彼蒼曾不與人期，勝事由來德所基。',64,'全唐诗/poet.song.98000.json','["彼蒼曾不與人期，勝事由來德所基。", "閉戶一經真有子，傳家三世定逢時。", "摛詞自得江山助，種學寧求燕雀知。", "寄與諸郎飽黄卷，桂林還見長孫枝。"]'),
('e8f9f78e-70ae-47b6-9be6-70ba24f598a0','和判宗展鉢之作','李彌遜','宋','宋诗','song-poetry','','[]','公子曾修凈飯因，齋魚聲裏悟前身。',64,'全唐诗/poet.song.98000.json','["公子曾修凈飯因，齋魚聲裏悟前身。", "累觴肯緩持螯手，一鉢不勞行炙人。", "對鏡禪心秋澗月，放懷俗慮曉江塵。", "渺茫漫笑神仙事，何用金盤薦擗麟。"]'),
('d7fc57af-59d3-4c57-b9df-5245d7bd0b80','上巳日陪徽守遊白水寺繼登西山繼白堂晚飲','李彌遜','宋','宋诗','song-poetry','','[]','曉衢初日動遊人，疊嶂回溪綠黛新。',64,'全唐诗/poet.song.98000.json','["曉衢初日動遊人，疊嶂回溪綠黛新。", "自偃松篁如喚客，後開桃李尚留春。", "笑談懷遠西山上，觴詠追時白水濱。", "五馬行春從此始，更驅風伯淨車塵。"]'),
('a543e874-c57f-4200-9eb4-88c736774ce1','晚登昭真亭雲霧不見黄山因以述懷','李彌遜','宋','宋诗','song-poetry','','[]','莫放微雲點太清，欲將遊目泫孤亭。',64,'全唐诗/poet.song.98000.json','["莫放微雲點太清，欲將遊目泫孤亭。", "十年去國心長赤，一月看山眼未青。", "多病情懷千日酒，窮途生事五侯鯖。", "謾遊蹤跡隨方寄，更覺輕扵水上萍。"]'),
('a533f75c-ca62-4b22-8da1-76683d46c5ad','奉懷羅仲共叔共二友','李彌遜','宋','宋诗','song-poetry','','[]','征衫一着宛溪東，結友何人繼兩龔。',64,'全唐诗/poet.song.98000.json','["征衫一着宛溪東，結友何人繼兩龔。", "寸步相期偶胡越，尺書不斷見心胸。", "吟邉快覩推三語，吏退冥捜想二松。", "别後幷吞幾雲夢，錦嚢收拾付賓鴻。"]'),
('5171bce2-e237-4a47-a7e0-a1cb3fec55d7','夏日遊連江石門坐林下有虫咂膚視之僅可分有無疑蚋也以詩嘲之','李彌遜','宋','宋诗','song-poetry','','[]','么麽何從到上方，敢將唇吻犯堂堂。',64,'全唐诗/poet.song.98000.json','["么麽何從到上方，敢將唇吻犯堂堂。", "但知射影求陰中，可笑當年不自量。", "鱟目苦遭蚊喙聒，象蹄猶畏鼠牙傷。", "須臾性命隨翻手，蠻觸應難望故鄉。"]'),
('26cacd70-2e82-4c85-a1fb-19365676f5fe','次韻穎仲蘭室之什','李彌遜','宋','宋诗','song-poetry','','[]','黄卷青燈寄佛場，孤髙如在遠林芳。',64,'全唐诗/poet.song.98000.json','["黄卷青燈寄佛場，孤髙如在遠林芳。", "下帷誰識傳經董，載酒時過尚白揚。", "華髪同心猶有臭，青衿入室自知香。", "公卿本是階庭物，莫遣行藏異素王。"]'),
('18b8da6d-4466-4cb7-bd44-d189e80b8d5d','初到連江和林公曄先輩','李彌遜','宋','宋诗','song-poetry','','[]','投老身名信陸沉，欲將白髪寄搖岑。',64,'全唐诗/poet.song.98000.json','["投老身名信陸沉，欲將白髪寄搖岑。", "賦詩未敢施彭澤，抱甕真堪友漢陰。", "江面飛橋誇壯麗，山腰臥石閟幽深。", "公才清絕參奇觀，慰我長年去國心。"]'),
('5052a200-69b0-4ece-952c-0aa3edb2b779','次韻林公曄見贈','李彌遜','宋','宋诗','song-poetry','','[]','思君一日可當期，敢意瓊瑤手自貽。',64,'全唐诗/poet.song.98000.json','["思君一日可當期，敢意瓊瑤手自貽。", "華髪乍回千里夢，白眉重見十年知。", "驚人句好供行樂，遣客杯寬欲坐馳。", "肯斸雲根同我老，賸留觴詠醉花時。"]'),
('97402210-7cba-4370-a3ed-8eb6f6a5cceb','次韻陳穎仲晚步見山','李彌遜','宋','宋诗','song-poetry','','[]','青鞋布襪繞江湄，矯首山房送日西。',64,'全唐诗/poet.song.98000.json','["青鞋布襪繞江湄，矯首山房送日西。", "小榼留人燈下覓，短笻邀我醉中攜。", "峰巒過雨新塗澤，草木逢春自品題。", "投老歸來同逆旅，好於此地斸愚溪。"]'),
('6144d166-4e2d-49a6-9d04-5ce258973e97','和夷仲弟喜學士兄歸','李彌遜','宋','宋诗','song-poetry','','[]','烽火叢中别弟兄，獨看鄉月幾虧盈。',64,'全唐诗/poet.song.98000.json','["烽火叢中别弟兄，獨看鄉月幾虧盈。", "萬金信斷秋山寂，千里人歸春草榮。", "雨漲波紋催過艗，風翻葉幄避行旌。", "機雲入洛悲辛後，誰似張華倒屣迎。"]'),
('729d724e-214e-4208-9537-d43b1ff6c8cf','翁尉以詩送蓮幷酒','李彌遜','宋','宋诗','song-poetry','','[]','不復西河歎踽凉，真成仙吏隱襄陽。',64,'全唐诗/poet.song.98000.json','["不復西河歎踽凉，真成仙吏隱襄陽。", "一生可了酒供座，千頃平鋪花遶塘。", "皓腕折香遮老眼，長鬚洗杓荐新嘗。", "肯分臭味同衰朽，好語猶驚得夜光。"]'),
('fda8cf05-ee42-450f-8187-c004883ca13a','學士兄還鄉之始會賓親石門寺以病不能往公曄穎仲有詩次韻','李彌遜','宋','宋诗','song-poetry','','[]','群賢嘉會走輿臣，乍喜郎星照七閩。',64,'全唐诗/poet.song.98000.json','["群賢嘉會走輿臣，乍喜郎星照七閩。", "寺近南塘鍾秀麗，筵開晚水荐甘珍。", "放懷想盡百川飲，留客應生四角輪。", "我獨沉疴方面壁，愈風賴有兩騷人。"]'),
('b110ec9a-5552-454a-b423-e9600ef7d17f','次韻陳蹈元見和之作','李彌遜','宋','宋诗','song-poetry','','[]','漫逐江魚弔楚臣，風騷今見出吾閩。',64,'全唐诗/poet.song.98000.json','["漫逐江魚弔楚臣，風騷今見出吾閩。", "遺音思遠冰霜淡，味語功深膾炙珍。", "一壑我曹方税駕，九霄公等政推輪。", "屏除堆案癡兒事，肯着青鞋伴散人。"]'),
('9636278b-0ef1-4b3c-be36-6a5e1803e4be','奉酬龍興益老伽陀','李彌遜','宋','宋诗','song-poetry','','[]','居士心如出岫雲，逢場作戲不求真。',64,'全唐诗/poet.song.98000.json','["居士心如出岫雲，逢場作戲不求真。", "桃花自落非關雨，梅子半黄知是春。", "此外更無身外事，閑中那得箇中人。", "箭鋒相拄君休問，千里同風始見親。"]'),
('03a93254-0145-49c7-b229-b9d5ba9755d4','和陳穎仲題劉鞠祠','李彌遜','宋','宋诗','song-poetry','','[]','山遶平湖綠四邉，兩翁遺澤到今傳。',64,'全唐诗/poet.song.98000.json','["山遶平湖綠四邉，兩翁遺澤到今傳。", "蘋風引釣魚隨艇，穀雨催耕水拍田。", "敗壁丹青悲落日，荒庭紳笏想流年。", "桐鄉不廢春秋祀，簫鼓雞豚久更虔。"]'),
('f6cac475-e506-4b8e-8d78-0121a3df999c','和穎仲山行即事','李彌遜','宋','宋诗','song-poetry','','[]','平蕪新綠占封圻，横路游絲網落暉。',64,'全唐诗/poet.song.98000.json','["平蕪新綠占封圻，横路游絲網落暉。", "山徑人稀藏窈窕，禪扉春盡老芳菲。", "緩行照水知魚樂，隨意穿花見蝶飛。", "二子舁籃今夜月，龍鍾猶勝杖藜歸。"]'),
('716cfe73-4b18-496f-afcb-11126d564400','次韻隱者陳無隅  其一','李彌遜','宋','宋诗','song-poetry','','[]','柴門寂寂閉山光，客至供糜有二方。',64,'全唐诗/poet.song.98000.json','["柴門寂寂閉山光，客至供糜有二方。", "誰荐唐衢歸魏闕，肯令王適老閿鄉。", "藕塘待晚對幽壑，竹院消閑近寶坊。", "用捨由時姑袖手，豈無真樂在濠梁。"]'),
('47ae2f70-008c-45cb-a2cc-7b8e6cd3c12f','次韻隱者陳無隅  其二','李彌遜','宋','宋诗','song-poetry','','[]','歷井捫參踏蘚苔，山腰海角偶徘徊。',64,'全唐诗/poet.song.98000.json','["歷井捫參踏蘚苔，山腰海角偶徘徊。", "身從飄泊似浮水，眼見紛華等濕灰。", "共煮松風占乳信，試尋香雪探芳媒。", "笑談疑在蓬瀛上，下視雲中兩兩苔。"]'),
('8ade49b8-0485-45d6-9ee4-01a3e3fc2817','次韻李伯紀丞相遊賢沙鳯池之作  其一','李彌遜','宋','宋诗','song-poetry','','[]','騎鯨破曉上崔嵬，人識仙翁第一回。',64,'全唐诗/poet.song.98000.json','["騎鯨破曉上崔嵬，人識仙翁第一回。", "杖屨不應塵外去，旌麾早自日邉來。", "黑頭半爲憂時改，青眼唯逢勝地開。", "怪底尺書頻寄雁，向來交味比陳雷。"]'),
('df575066-ffac-419b-86a3-e50d275f5493','次韻李伯紀丞相遊賢沙鳯池之作  其二','李彌遜','宋','宋诗','song-poetry','','[]','幾日公來浴鳯池，蹇驢陪乘偶參差。',64,'全唐诗/poet.song.98000.json','["幾日公來浴鳯池，蹇驢陪乘偶參差。", "羈棲自笑臥盤谷，健句爭先誦渼陂。", "世路吹虀無念到，山遊啗蔗不言知。", "紬書倘遂雲根築，肯與酸寒鄭老期。"]'),
('a0e6486a-c49c-4654-8a5b-7910d7568d69','似表弟始歸寇退之後置酒會親族坐客即席賦詩次其韻','李彌遜','宋','宋诗','song-poetry','','[]','蓬轉生涯四十年，歸來華髪舊山川。',64,'全唐诗/poet.song.98000.json','["蓬轉生涯四十年，歸來華髪舊山川。", "驚魂僅免走三穴，情話喜同傾四筵。", "醉客毛吞憐海窄，詩翁刀奏失牛全。", "錦城不似還家樂，姑置行藏莫問天。"]'),
('81f58ba2-400a-4246-a4a1-29ff684ab528','病臥一春無復少況蹈元頋爲尋山之行以詩簡之','李彌遜','宋','宋诗','song-poetry','','[]','病與老期推復來，十分春事苦相催。',64,'全唐诗/poet.song.98000.json','["病與老期推復來，十分春事苦相催。", "干戈四海少閑地，寒暑一生能幾回。", "止酒尊罍成說食，空華風景亂真梅。", "晴明强理尋山屐，笑口逢君倘暫開。"]'),
('a0bcdc0f-dc54-4fa3-9c33-aa5232d438ee','復用前韻約蹈元顧','李彌遜','宋','宋诗','song-poetry','','[]','時序驚人咄咄來，榮枯畢竟爲誰催。',64,'全唐诗/poet.song.98000.json','["時序驚人咄咄來，榮枯畢竟爲誰催。", "風將滿地飛紅去，日擁半天髙綠回。", "頋我似嘗當道李，渴君如望隔林梅。", "一年春事無多子，喚取提壺觸處開。"]'),
('6d71310b-1911-4f19-87b7-e48c59ceaced','久陰聞督郵至縣奉簡蹈元','李彌遜','宋','宋诗','song-poetry','','[]','驚呼雞犬督郵來，想見文書手自催。',64,'全唐诗/poet.song.98000.json','["驚呼雞犬督郵來，想見文書手自催。", "鼓枻黄頭罷田去，傾嚢黔首入苗回。", "春盈半月傾盆盎，夜雹前時落李梅。", "已向茫頭望籠餅，陽烏幾日放天開。"]'),
('9c814e96-9dae-4365-9fca-638819578b2a','春雨久不止戲呈諸公','李彌遜','宋','宋诗','song-poetry','','[]','蕉上雨聲無盡來，龍疲應困阿香催。',64,'全唐诗/poet.song.98000.json','["蕉上雨聲無盡來，龍疲應困阿香催。", "竹萌出土嚢錐見，燕觜得泥風鷁回。", "料峭侵衣猶带臈，廉纖昏晝已如梅。", "愁邉酒醆都無力，更着濃陰撥不開。"]'),
('5ceb6c6c-5d1a-40c8-aa10-f3a24f48403f','遊石門用前韻促陳丞','李彌遜','宋','宋诗','song-poetry','','[]','昨夜濃陰潑墨來，比鄰折簡小奚催。',64,'全唐诗/poet.song.98000.json','["昨夜濃陰潑墨來，比鄰折簡小奚催。", "印窗寒月曉前白，尋壑春輿天際回。", "醆面綠浮新展葉，杖頭黄礙半肥梅。", "知君自掃松間徑，古錦何妨此地開。"]'),
('8b877036-b6a3-42eb-942c-d4dc225302e7','暇日遊石門用前韻','李彌遜','宋','宋诗','song-poetry','','[]','曉御欲隨風腳來，報晴烏鵲入簷催。',64,'全唐诗/poet.song.98000.json','["曉御欲隨風腳來，報晴烏鵲入簷催。", "松幢竹盖寶坊近，石壁雲關塵境回。", "山氣得春濃勝酒，花光带月冷過梅。", "卻收眼力尋歸路，惜取餘青莫浪開。"]'),
('ec18f9c1-8d5c-49f6-a939-9e2ab75e1202','西山獨步奉懷蹈元','李彌遜','宋','宋诗','song-poetry','','[]','擺脱微官萬里來，非關枝上子規催。',64,'全唐诗/poet.song.98000.json','["擺脱微官萬里來，非關枝上子規催。", "鏡中蒼鬢摘還滿，花上青春喚不回。", "我築一溪愚似柳，君工五字老扵梅。", "哦詩肯傍水旁徑，賸買長瓶爲子開。"]'),
('16d42153-f0a7-421e-9d57-325e46484121','山居寄友人','李彌遜','宋','宋诗','song-poetry','','[]','結廬人境經過少，晚起長遭稚子催。',64,'全唐诗/poet.song.98000.json','["結廬人境經過少，晚起長遭稚子催。", "閑處赤心憂國盡，病中白髪愛山回。", "林泉可使居無竹，風雨空嗟摽有梅。", "不遣飛奴頻過我，欲將懷抱向誰開。"]'),
('66b66f7b-2bcc-4838-9e37-0f1f064aa802','次韻似表弟春雨漫成','李彌遜','宋','宋诗','song-poetry','','[]','百念關身起蝟毛，雨聲偏近夜牀髙。',64,'全唐诗/poet.song.98000.json','["百念關身起蝟毛，雨聲偏近夜牀髙。", "正愁春事趁奔鹿，更覺歸心折大刀。", "擁鼻吟邉聊且遣，枕肱佳處亦時遭。", "麴生懷抱肯傾倒，一酌忘憂賴爾曹。"]'),
('66b7e28f-98ea-481b-b041-76c96bc0e992','近報陜右大捷又繼聞王師遂平建寇用髙字韻','李彌遜','宋','宋诗','song-poetry','','[]','南北軍書走羽毛，城頭喜見赤雲髙。',64,'全唐诗/poet.song.98000.json','["南北軍書走羽毛，城頭喜見赤雲髙。", "頗聞關隴盡歸馬，不獨甌閩行賣刀。", "壕吏捉人那復有，田翁泥飲不辭遭。", "會看四海收鼙鼓，郡邑官閑得坐曹。"]'),
('4df7dc64-7f81-4f98-8846-ff4dc318a6af','與似表弟遊石門懷蹈元時中用髙字韻','李彌遜','宋','宋诗','song-poetry','','[]','逼人塵事等牛毛，袖手端須着眼髙。',64,'全唐诗/poet.song.98000.json','["逼人塵事等牛毛，袖手端須着眼髙。", "策蹇倦追千里馬，荷鋤安用百金刀。", "病來避酒連三月，春半尋山等一遭。", "不見鞭鸞兩仙吏，秪應上界亦分曹。"]'),
('d573b5a5-06ee-4cc7-8dbc-52abfba5700a','歸自筠莊得似表弟晚步髙字韻繼和','李彌遜','宋','宋诗','song-poetry','','[]','一行作吏苦吹毛，小隱非關索價髙。',64,'全唐诗/poet.song.98000.json','["一行作吏苦吹毛，小隱非關索價髙。", "懶傍月邉持玉斧，靜看花上試霜刀。", "近人魚鳥曾相識，入眼溪山昔未遭。", "誰與着鞭春色裏，雁行風急正求曹。"]'),
('39a36053-0ec7-4322-88b0-5af2cbabc598','新晴再用似表弟髙字韻','李彌遜','宋','宋诗','song-poetry','','[]','疏林遠墅見秋毫，破曉陽烏羽翼髙。',64,'全唐诗/poet.song.98000.json','["疏林遠墅見秋毫，破曉陽烏羽翼髙。", "湖面平於開匣鏡，山稜光並發硎刀。", "閉門聽雨寧論日，散策尋岡莫數遭。", "世上幾人能避俗，簿書堆案想官曹。"]'),
('5e1d7262-4ae2-409c-b860-2a05cac438cb','筠莊李花正開雨不得往似表弟有詩次韻','李彌遜','宋','宋诗','song-poetry','','[]','經旬長雨暗春山，小白枝頭正可攀。',64,'全唐诗/poet.song.98000.json','["經旬長雨暗春山，小白枝頭正可攀。", "賸欲叩舷浮綠淨，未容着屐上蒼頑。", "題詩過我工排悶，載酒留人肯破慳。", "要及花時酬老大，筍輿從此不須閑。"]'),
('13a69661-980f-4a0e-9bae-f655854e5513','喜晴再用閑字韻','李彌遜','宋','宋诗','song-poetry','','[]','風掠游雲露遠山，長藤竟欲與君攀。',64,'全唐诗/poet.song.98000.json','["風掠游雲露遠山，長藤竟欲與君攀。", "花神解作瓊瑤報，野老心如鐵石頑。", "千樹暗春難比富，一枝照眼未應慳。", "不須更作含羞態，喚取張盧來共閑。"]'),
('a4d75ff4-6834-4bbc-ac3f-7ada33054f05','久雨似有晴意繼而復陰作望晴','李彌遜','宋','宋诗','song-poetry','','[]','一夜翻河落瓦溝，平明山靄欲全收。',64,'全唐诗/poet.song.98000.json','["一夜翻河落瓦溝，平明山靄欲全收。", "正疑礎潤雲生足，直怕天明日探頭。", "倐忽去來觀聚蟻，現前起滅悟浮漚。", "占晴不問黄衣使，已向鳥烏聲際求。"]'),
('89965cb3-c160-430c-9a8c-548fb6c08ed1','久雨  其一','李彌遜','宋','宋诗','song-poetry','','[]','詩肩不柰曉風酸，后土何時得暫乾。',64,'全唐诗/poet.song.98000.json','["詩肩不柰曉風酸，后土何時得暫乾。", "石鼎飯餘茶乳細，竹爐經罷柏烟殘。", "龍游未歇千山暗，豹隱方深一塢寒。", "白髪飄零江海上，朔雲收恨赴長安。"]'),
('c9fa91eb-d5d7-4ce5-8030-ced27d966dba','久雨  其二','李彌遜','宋','宋诗','song-poetry','','[]','榕根敗屋兩三椽，客徑無人老更便。',64,'全唐诗/poet.song.98000.json','["榕根敗屋兩三椽，客徑無人老更便。", "地近東南多澤國，雨逢甲子少豐年。", "徑須酣飲六十日，安用取禾三百廛。", "待得風頭風力□，梅花如雪月初圓。"]'),
('5eb7bc2e-e6b0-48be-87d7-dad41c5270ab','德甫知丞過筠莊谿亭爲待月之會戲呈席上諸友','李彌遜','宋','宋诗','song-poetry','','[]','載酒何人過子雲，傳呼雞犬亦驚奔。',64,'全唐诗/poet.song.98000.json','["載酒何人過子雲，傳呼雞犬亦驚奔。", "門無車馬苔侵徑，坐近池臺竹覆尊。", "好月邀人留晚照，疾雷催雨過前村。", "獨醒楚子真多事，共醉愚溪百尺渾。"]'),
('b5d856f1-645a-49f0-8891-0c4790a6de8d','待月久不至須臾雲破星露溪光發衆賓懽呼席上次德甫韻','李彌遜','宋','宋诗','song-poetry','','[]','待月新亭興已慵，眼花空亂燭花紅。',64,'全唐诗/poet.song.98000.json','["待月新亭興已慵，眼花空亂燭花紅。", "溪山路隔烟塵外，觴咏身疑夢寐中。", "卻暑已煩瞋恚雨，掃雲須賴吉祥風。", "水光已報冰輪信，一笑能令萬斛空。"]'),
('fb589b28-94d8-44eb-b945-4fab13f06af3','巖起錄云次韻張幹佳什輙和寄之以道山居之況','李彌遜','宋','宋诗','song-poetry','','[]','前山立玉水縈羅，逕竹當門一里過。',64,'全唐诗/poet.song.98000.json','["前山立玉水縈羅，逕竹當門一里過。", "管子與予成莫逆，麴生邀我到無何。", "老來鶴骨寒猶健，病起霜髭短更多。", "金印纍纍看公等，已甘一壑寄蹉跎。"]'),
('a39133e1-0c46-4819-bb8b-6a0fd4e911b6','次韻巖起曉晴','李彌遜','宋','宋诗','song-poetry','','[]','白衣蒼狗暗還明，造物何心聽改更。',64,'全唐诗/poet.song.98000.json','["白衣蒼狗暗還明，造物何心聽改更。", "雨足龜魚方得計，日髙蛙黽自消聲。", "浮溪荇带羅初展，粘壁虫書字不成。", "正喜太清無點綴，慘舒誰復較陰晴。"]'),
('6c1367fc-bdf8-4e88-9a8c-b0587afbd08f','次韻徐持志見寄','李彌遜','宋','宋诗','song-poetry','','[]','綉衣歸臥水雲鄉，湛輩猶懷峴首羊。',64,'全唐诗/poet.song.98000.json','["綉衣歸臥水雲鄉，湛輩猶懷峴首羊。", "似我鵠烏忘白黑，知君牝牡失驪黄。", "靜中禪縳應超脱，别後詞鋒底激昻。", "投老窮途各千里，不須留穎見錐嚢。"]'),
('611822af-b4da-41c8-8450-757f3377d680','德甫知丞大夫惠詩見招次韻','李彌遜','宋','宋诗','song-poetry','','[]','地勝官清人更幽，公田政足辦槽丘。',64,'全唐诗/poet.song.98000.json','["地勝官清人更幽，公田政足辦槽丘。", "吏情厭問可不可，世事但從浮自浮。", "綠盖紅粧供客笑，黄雞白酒爲君留。", "慣傾老瓦陪田父，髙會端如飫五侯。"]'),
('16eaf746-651a-48f5-ad56-78194ee174a9','筠莊亭軒皆以筠名學士兄有詩次韻','李彌遜','宋','宋诗','song-poetry','','[]','種竹營巢老自如，渭川端不羡商扵。',64,'全唐诗/poet.song.98000.json','["種竹營巢老自如，渭川端不羡商扵。", "松行外護遮凡木，蓮葉平鋪覆斷渠。", "我輩方宜置丘壑，此君可共樂琴書。", "軒亭處處成清閟，足了一生寧願餘。"]'),
('66fe9a90-0213-4add-948a-421180428ca0','次韻李丞相送行二首  其一','李彌遜','宋','宋诗','song-poetry','','[]','三年袖手臥江濱，着眼終成出世人。',64,'全唐诗/poet.song.98000.json','["三年袖手臥江濱，着眼終成出世人。", "筆下風雲作時雨，胸中丘壑作陽春。", "買山塵外曾相見，漉酒愁邉情更親。", "惜取風騷等閑句，他時密膝詠臣鄰。"]'),
('2b1e8389-58e0-4583-8b47-31c7ffd83d77','次韻李丞相送行二首  其二','李彌遜','宋','宋诗','song-poetry','','[]','山畔孤亭一水濱，歸來華髪已欺人。',64,'全唐诗/poet.song.98000.json','["山畔孤亭一水濱，歸來華髪已欺人。", "脱身異縣干戈地，得意吾廬筍蕨春。", "早着青衫成底事，慣遭白眼欲誰親。", "此君真有髙人節，肯與山翁作近鄰。"]'),
('6076155f-7987-406c-b234-f15b989ee961','自連江赴守鄱陽黄原道中作','李彌遜','宋','宋诗','song-poetry','','[]','海角三年一夢成，北來重聽偃溪聲。',64,'全唐诗/poet.song.98000.json','["海角三年一夢成，北來重聽偃溪聲。", "凝雲带雨留愁住，茂樹隨山送客行。", "秔稻沿崖畦上下，茅茨枕谷路縱横。", "莫從馬腹消雙髀，此地真堪老此生。"]'),
('259f422d-0de0-4d74-9ae8-8e445056dc02','鄱陽四望亭觀雪','李彌遜','宋','宋诗','song-poetry','','[]','瘴海三年雨不冰，喜看萬木變瓊英。',64,'全唐诗/poet.song.98000.json','["瘴海三年雨不冰，喜看萬木變瓊英。", "眼中何處分銀界，腳底從兹上玉京。", "歲序已於芒尾見，春風先向柳梢明。", "饑饞病守存餘習，欲和田家擊壌聲。"]'),
('8c647828-f13e-48de-9dd7-c34fb90a24e2','寄題福州程進道止戈堂二首  其一','李彌遜','宋','宋诗','song-poetry','','[]','不識威名擅漢廷，雲仍今復見材卿。',64,'全唐诗/poet.song.98000.json','["不識威名擅漢廷，雲仍今復見材卿。", "萬家桃李栽培盛，千里妖氛卻掃清。", "羽扇綸巾聊自適，風聲鶴唳已魂驚。", "向來雪鍔櫜藏地，賸築詩壇按酒兵。"]'),
('ef93ad50-a2fc-4ea1-8dd6-9dc9457b660a','寄題福州程進道止戈堂二首  其二','李彌遜','宋','宋诗','song-poetry','','[]','一麾局促楚江東，時喜鄰藩好信通。',64,'全唐诗/poet.song.98000.json','["一麾局促楚江東，時喜鄰藩好信通。", "坐厭文書朱墨裏，靜思談笑聖賢中。", "浮甌小試茶膏白，照眼分嘗荔子紅。", "想見髙堂分鳬鶩，競追樂事賞年豐。"]'),
('c2a04b83-ed5f-4fbe-a557-afdb52bf0dee','自鄱陽得請天台散吏解官就道恍然自適戲成','李彌遜','宋','宋诗','song-poetry','','[]','平明解印暮投館，公事已如風馬牛。',64,'全唐诗/poet.song.98000.json','["平明解印暮投館，公事已如風馬牛。", "報政僅堪書下下，結廬賸欲榜休休。", "無名花草香隨路，得計禽魚水滿溝。", "袖取向來朱墨手，按行松竹上滄洲。"]'),
('b1fec2e7-c6ea-43b1-9593-4735b9f8416e','題興敎寺','李彌遜','宋','宋诗','song-poetry','','[]','雲開岫幌隱禪扉，髙屋憑虚面翠微。',64,'全唐诗/poet.song.98000.json','["雲開岫幌隱禪扉，髙屋憑虚面翠微。", "午枕有香清蝶夢，晚林無路送鴻飛。", "一丘一壑真吾事，三沭三薰悟昨非。", "山意有情留倦客，樹頭誰道不如歸。"]'),
('e22a958a-28e8-40d4-95bc-bb4fe7ea82ae','送陳穎仲赴試省闈','李彌遜','宋','宋诗','song-poetry','','[]','木末揮斤玉未鐫，清姿直節已飄然。',64,'全唐诗/poet.song.98000.json','["木末揮斤玉未鐫，清姿直節已飄然。", "詩書插架嗤三萬，文字撐腸富五千。", "筆下行看吐黄絹，選中應喜探青錢。", "管城自有封侯相，得路功名且着鞭。"]'),
('ffe92dda-e230-4154-b081-15c017131c73','和劉待制','李彌遜','宋','宋诗','song-poetry','','[]','宦游蹤跡信輿臺，白首知非愧魯開。',64,'全唐诗/poet.song.98000.json','["宦游蹤跡信輿臺，白首知非愧魯開。", "詩卷雲烟舒復卷，吏行鳬鶩去還來。", "雨多風伯漫不省，春半花神小有才。", "誰爲癡兒無樂事，眼中秀句絕纖埃。"]'),
('7c3cb649-720c-405f-ad6f-c04b3b720af9','次韻尚書兄同游青原','李彌遜','宋','宋诗','song-poetry','','[]','暑風無力上襟裾，雁序衝烟入翠虚。',64,'全唐诗/poet.song.98000.json','["暑風無力上襟裾，雁序衝烟入翠虚。", "小憇凈蓮開梵境，偶聞密竹話真如。", "倦游政似知還翼，便靜聊同得計魚。", "不爲尋思問心法，是翁心外已無餘。"]'),
('5ae69485-0495-4029-8542-67e53dbf4cb6','次韻和韓知剛見貽之什','李彌遜','宋','宋诗','song-poetry','','[]','半生宦牒絆閑身，老惜跳丸過眼頻。',64,'全唐诗/poet.song.98000.json','["半生宦牒絆閑身，老惜跳丸過眼頻。", "獨笑真成當去客，相逢同是異鄉人。", "靜中着語已多事，熟處忘情久自親。", "他日君來序盤谷，巖花溪竹是知津。"]'),
('28656eec-8fc4-48da-8d55-4c981c9c8294','次韻羅偉正寺丞見遺之什','李彌遜','宋','宋诗','song-poetry','','[]','鵰鶚逢秋已恨遲，公才如此尚誰羈。',64,'全唐诗/poet.song.98000.json','["鵰鶚逢秋已恨遲，公才如此尚誰羈。", "江城樽俎未三月，世路干戈方百爲。", "去馬便如千里别，斷葭已作十分披。", "他年若下襄城路，鞭影應能指具茨。"]'),
('5f25814c-79be-4a87-8909-5b68fdf90b96','次韻劉寬夫春日有作','李彌遜','宋','宋诗','song-poetry','','[]','時序驚人翻手雲，一樽聊共駐青春。',64,'全唐诗/poet.song.98000.json','["時序驚人翻手雲，一樽聊共駐青春。", "惜花欄檻圍繒綺，留客杯盤煮荇蘋。", "愁外覓歡終淡薄，吟邉得酒更清新。", "休論二十年前事，目斷長安陌上塵。"]'),
('52baca11-5d84-4ba7-9741-333c2801bfbd','送似表弟還鄉','李彌遜','宋','宋诗','song-poetry','','[]','話别幾年一月留，離歌還起楚江樓。',64,'全唐诗/poet.song.98000.json','["話别幾年一月留，離歌還起楚江樓。", "往來笑子蟻旋磨，得失頋予魚中鈎。", "雍齒且侯真戲事，馮唐已老盍歸休。", "憑君爲掃筠莊榻，要着南來新白頭。"]'),
('abc99a50-53b0-42c4-ab2f-79e4f47b6e84','次韻曾微言見贈二首  其一','李彌遜','宋','宋诗','song-poetry','','[]','是邦誰及大夫賢，無地容才試十全。',64,'全唐诗/poet.song.98000.json','["是邦誰及大夫賢，無地容才試十全。", "側席賸聞求德友，深居那得隱臞仙。", "張羅永日無過轍，解榻何人許對眠。", "莫爲時危閑矍鑠，要看走馬勒燕然。"]'),
('b9d036cb-5e39-42b2-8b47-f219914cd48a','次韻曾微言見贈二首  其二','李彌遜','宋','宋诗','song-poetry','','[]','自分人非日九遷，一官民社敢妨賢。',64,'全唐诗/poet.song.98000.json','["自分人非日九遷，一官民社敢妨賢。", "脱塵未踏鄰虚地，通籍猶分小有天。", "餐玉近傳曾試法，買山取足不論錢。", "疏慵未似嵇中散，會有斜封落雁前。"]'),
('87a165bf-166b-4057-9700-d9796d61ad53','採蘋亭分韻得花字','李彌遜','宋','宋诗','song-poetry','','[]','樓頭鐘鼓曉催衙，吏散庭空日已斜。',64,'全唐诗/poet.song.98000.json','["樓頭鐘鼓曉催衙，吏散庭空日已斜。", "烽火望中常作客，簿書叢裏偶成家。", "陰陰密葉榴垂實，剪剪新荷藕結花。", "小立方塘一杯酒，又傳歸恨到天涯。"]'),
('bdc2b95f-ba0a-4199-b501-dc9efd019a7e','次韻行父舍人有感','李彌遜','宋','宋诗','song-poetry','','[]','飄飄文采照螭頭，袖手功名未肯休。',64,'全唐诗/poet.song.98000.json','["飄飄文采照螭頭，袖手功名未肯休。", "易水渡愁隨一騎，春風吹淚着雙眸。", "向來但遣淮陰將，異日寧論雍齒侯。", "應笑江南誇仲父，規模纔可限昇州。"]'),
('3f479826-f3a5-4989-934a-cc21965b6442','行父和篇頗有過情之語次韻自叙以謝','李彌遜','宋','宋诗','song-poetry','','[]','家在閩山最上頭，大書髙屋榜休休。',64,'全唐诗/poet.song.98000.json','["家在閩山最上頭，大書髙屋榜休休。", "按行松竹曾施屐，應接江山不運眸。", "漫道鶴書朝赴隴，真成蟻穴夢封侯。", "紫薇落筆非吾事，撫字猶堪老一州。"]'),
('8b729e56-95c4-4012-adb0-f904b43d718b','過吳江次韻行父之作','李彌遜','宋','宋诗','song-poetry','','[]','重來□□又成空，舊榜今無臥綵虹。',64,'全唐诗/poet.song.98000.json','["重來□□又成空，舊榜今無臥綵虹。", "故國平嗟□瓦礫，新亭猶見濕青紅。", "雁隨山遠情無□，□與天窮勢自通。", "盡道鱸魚寒不食，□□祗合在江東。"]'),
('fa2d70ed-b326-47d1-a5c3-76c75e71dc28','巖陵道中','李彌遜','宋','宋诗','song-poetry','','[]','禁路追隨又兩年，長竿那可使魚緣。',64,'全唐诗/poet.song.98000.json','["禁路追隨又兩年，長竿那可使魚緣。", "壯心未展傷遲暮，捷徑無工較後先。", "軟飽三杯當去客，横蒲十幅得風船。", "眼中有句無人道，誰與收歸古錦編。"]'),
('ce28e9a0-b924-477c-a47a-7252033a3152','舟中對月','李彌遜','宋','宋诗','song-poetry','','[]','悠悠乘墜寄舟車，與世真成一夢蘧。',64,'全唐诗/poet.song.98000.json','["悠悠乘墜寄舟車，與世真成一夢蘧。", "苦憶曉更鼉報鼓，喜逢秋遠雁横書。", "江山似與詩人助，水月應知靜者如。", "投老得歸隨處樂，獨醒尤笑楚三閭。"]'),
('cdb713d4-2ae4-4f01-8a3b-98ea15ffe70f','留别傅才儒','李彌遜','宋','宋诗','song-poetry','','[]','壯歲追隨鬢已蒼，誰將勳業問行藏。',64,'全唐诗/poet.song.98000.json','["壯歲追隨鬢已蒼，誰將勳業問行藏。", "憐公惜莫雞群鶴，頋我凌兢虎質羊。", "敗柳亦工喧暮雨，寒花直欲膩秋霜。", "更謀濁酒窮清夜，明日山深木葉黄。"]'),
('229ba752-69f9-4b7e-b615-99f7b0c64d88','凝碧晚望','李彌遜','宋','宋诗','song-poetry','','[]','秋來何必送將歸，落日髙臺意自悲。',64,'全唐诗/poet.song.98000.json','["秋來何必送將歸，落日髙臺意自悲。", "一壑未容追汗漫，三鍾猶得飽支離。", "黄花對客如相笑，白髪尋人似有期。", "時序不堪翻覆手，每逢佳處亦開眉。"]'),
('88aa8673-da98-4727-9fb7-7165ae13a56a','晚登齊雲閣','李彌遜','宋','宋诗','song-poetry','','[]','窈窕僧窗十肘長，解分眼界入他方。',64,'全唐诗/poet.song.98000.json','["窈窕僧窗十肘長，解分眼界入他方。", "塵襟偶脱公家亊，鼻觀重參佛土香。", "寒日半收山着色，晚風無力水磨光。", "幽尋已覺滄洲近，身外營營付一觴。"]'),
('1c6f831f-893b-46f0-bea3-0e7abf372e64','得仙亭','李彌遜','宋','宋诗','song-poetry','','[]','隔水樓臺聳佛宫，緣雲捫石得榰笻。',64,'全唐诗/poet.song.98000.json','["隔水樓臺聳佛宫，緣雲捫石得榰笻。", "布金地主空遺像，折桂仙翁失舊蹤。", "人去遠山留夕照，僧歸晚徑带殘鐘。", "眼中有句無人道，欲寄丹青恐未工。"]'),
('7f6e7d3a-66f2-4de6-a32a-0f5d30850d32','南樓','李彌遜','宋','宋诗','song-poetry','','[]','百尺危樓枕水濱，風烟入眼亂紛紛。',64,'全唐诗/poet.song.98000.json','["百尺危樓枕水濱，風烟入眼亂紛紛。", "趁虚漁唱來成市，入壠田歌去作群。", "閣雨雲深山着帽，駕潮風急浪翻雲。", "寄言殘夜明樓月，莫負胡床老使君。"]'),
('651572e1-da11-4e37-be55-3fce41676ede','晚飲東湖亭用碩夫韻','李彌遜','宋','宋诗','song-poetry','','[]','秋後髙荷與砌平，暫迴眼白爲君青。',64,'全唐诗/poet.song.99000.json','["秋後髙荷與砌平，暫迴眼白爲君青。", "哦詩太瘦真成癖，對酒清狂不礙醒。", "健筆縱横那可繼，醉歌悲壯亦堪聽。", "如何借得南烹手，更搗香橙爲荐腥。"]'),
('579314f4-677f-4f20-b1cf-6fbd37ce5e9e','次韻漳州鄧教授二首  其一','李彌遜','宋','宋诗','song-poetry','','[]','絳帳初開識馬融，尊罍聊共落新宫。',64,'全唐诗/poet.song.99000.json','["絳帳初開識馬融，尊罍聊共落新宫。", "三千避席方懷古，四十無氈獨見公。", "尺璧未磨終可荐，兼金久煉要加功。", "男兒事業真堪戲，莫把行藏問塞翁。"]'),
('1263c16c-c6ef-41b3-887d-4c19e0ac38d9','次韻漳州鄧教授二首  其二','李彌遜','宋','宋诗','song-poetry','','[]','十年猿鶴共蕭蕭，世亊驅人肯見饒。',64,'全唐诗/poet.song.99000.json','["十年猿鶴共蕭蕭，世亊驅人肯見饒。", "老態嶺雲風更急，壯心爐篆日還銷。", "催科政拙民猶病，禦侮才疏盗正驕。", "强拾陳言續清唱，卻慚横槊按戎昭。"]'),
('e0fe35fc-3919-4539-8095-933cdc8c91e8','秋日同劉方明遊石師巖','李彌遜','宋','宋诗','song-poetry','','[]','翠合峰巒萬葉稠，雲擎佛屋出巖幽。',64,'全唐诗/poet.song.99000.json','["翠合峰巒萬葉稠，雲擎佛屋出巖幽。", "秋光不到庭陰樹，曉日先明竹外樓。", "戶牖髙低分世界，川原遠近失汀洲。", "陽休示我真消息，更在靈山最上頭。"]'),
('ec8dc9f9-2988-4e11-a0f4-04b5efca83bc','南樓晚望','李彌遜','宋','宋诗','song-poetry','','[]','海角長安望爾賒，日邉雲影更横斜。',64,'全唐诗/poet.song.99000.json','["海角長安望爾賒，日邉雲影更横斜。", "身閑夢覺俱成蝶，眼病朝昏只見花。", "可但陶潛能避俗，不應范蠡便浮家。", "君恩未報驚華髪，目斷飛鴻水四涯。"]'),
('291325de-16d3-41f7-8842-52d090a7ee9d','次韻康平仲侍郎從丞相張公登倚雲亭  其一','李彌遜','宋','宋诗','song-poetry','','[]','皂蓋凌虛豈易陪，捫參那復欲髙哉。',64,'全唐诗/poet.song.99000.json','["皂蓋凌虛豈易陪，捫參那復欲髙哉。", "雲關□處塵蹤斷，松蓋陰中寶地開。", "戎幕寇平高臥鼓，賓筵詩罷細銜杯。", "笑談疑在青冥上，坐近中天兩兩台。"]'),
('a7216007-eb86-4853-970e-01ece1a84880','次韻康平仲侍郎從丞相張公登倚雲亭  其二','李彌遜','宋','宋诗','song-poetry','','[]','相君題品到林泉，大榜新書亦爛然。',64,'全唐诗/poet.song.99000.json','["相君題品到林泉，大榜新書亦爛然。", "雲護山根藏小魯，風攜人語動諸天。", "放懷對客忘青白，隨意傳觴任聖賢。", "誰謂甌閩甘遠俗，他時物物待陶甄。"]'),
('afda407a-3f7f-4e5e-a4de-c0e31a60a5ed','留題葉成父尚書山庵普光明堂','李彌遜','宋','宋诗','song-poetry','','[]','三生調御潮音會，樓閣隨方涌化城。',64,'全唐诗/poet.song.99000.json','["三生調御潮音會，樓閣隨方涌化城。", "鳥樹有聲皆念法，雲山多態摠忘情。", "禪翁自得逃禪樂，俗客猶沾避俗名。", "但了心源秋月净，刹塵何地不光明。"]'),
('5b337212-1c5a-4689-9b16-b9b251cf6347','成父居士於普光明堂之東别建大閣榜曰妙嚴將家焉閣成李子過而賦之','李彌遜','宋','宋诗','song-poetry','','[]','新成髙屋礙雲嵐，下視諸方落二三。',64,'全唐诗/poet.song.99000.json','["新成髙屋礙雲嵐，下視諸方落二三。", "妙喜不從他界斷，德雲今向别峰參。", "按家便可超塵染，喚客何妨到酒酣。", "居士飽知名閣意，爲言童子不須南。"]'),
('8a01f789-4d44-4905-904b-9b58553f0ee8','次韻葉成父尚書見留之什','李彌遜','宋','宋诗','song-poetry','','[]','山外孤雲出寸岑，營巢其下一枝深。',64,'全唐诗/poet.song.99000.json','["山外孤雲出寸岑，營巢其下一枝深。", "久從泛宅浮家伴，未遂穿雲渡水心。", "百里躋攀方着屐，十年交舊欲分襟。", "西風落日非無恨，歸臥桑榆惜寸陰。"]'),
('8692b125-4e17-4f17-abbf-b1b9e7da4dc7','與老禪諸上人同遊鼓山靈源洞','李彌遜','宋','宋诗','song-poetry','','[]','茶甌喚起清晝眠，澗松巖竹談幽禪。',64,'全唐诗/poet.song.99000.json','["茶甌喚起清晝眠，澗松巖竹談幽禪。", "秋曦忽隨壯士臂，暮景已入詩人肩。", "塵緣咄咄魚吞餌，勝事堂堂駒着鞭。", "屐齒欲回還小立，隔溪明滅見江船。"]'),
('15bf478c-f317-43ac-965d-5794a0d40a46','庚申季冬立春日還鄉公曄置酒孟園從容道舊有詩次韻','李彌遜','宋','宋诗','song-poetry','','[]','孟園花色璨瓊瑰，倦客隨春此地回。',64,'全唐诗/poet.song.99000.json','["孟園花色璨瓊瑰，倦客隨春此地回。", "靜院茶甌浮積雪，深堂香鴨亂真梅。", "得閑苦厭紛紜事，畏病難禁瀲灔杯。", "但掃晴窗鋪大字，更將老眼爲君來。"]'),
('c3820ebf-5bcc-47d1-bc0d-ab214ceab221','初歸筠荘蘇粹之以詩見貽次韻答之  其一','李彌遜','宋','宋诗','song-poetry','','[]','八尺茅茨老竹林，細償南北故園心。',64,'全唐诗/poet.song.99000.json','["八尺茅茨老竹林，細償南北故園心。", "一溪止水清涵月，三日行雲薄釀霖。", "歸計欲成猶恨晚，醉愁無賴正傷今。", "喚回柏子香中夢，屋角秋聲亂翠陰。"]'),
('ea3bee65-a523-40c6-9ece-ba726306d7ed','初歸筠荘蘇粹之以詩見貽次韻答之  其二','李彌遜','宋','宋诗','song-poetry','','[]','他年同上楚江樓，花遶春城小謝州。',64,'全唐诗/poet.song.99000.json','["他年同上楚江樓，花遶春城小謝州。", "翻手雨雲人事改，跳九日月歲光流。", "霜空暮落能鳴雁，秋水風移不繫舟。", "偶築一丘鄰勝隱，杖笻衝雨亦來游。"]'),
('c230279d-2075-4272-b4dd-b73a18581a2c','和明甫南山用粹之韻','李彌遜','宋','宋诗','song-poetry','','[]','尋源探穴上林丘，宛似愚溪柳柳州。',64,'全唐诗/poet.song.99000.json','["尋源探穴上林丘，宛似愚溪柳柳州。", "樹擁千頭爭地出，江分一股抱山流。", "陰堂閣雨雲生屋，晚浦收潮草泛舟。", "幽興未窮留眼力，將鶵結友更深游。"]'),
('3e45a8cb-3c23-4f33-96c3-d99e41050d3b','新成茅廬獨宿西山','李彌遜','宋','宋诗','song-poetry','','[]','幕上寧容燕作巢，土階竹屋近誅茅。',64,'全唐诗/poet.song.99000.json','["幕上寧容燕作巢，土階竹屋近誅茅。", "深行樂地思招隱，早悟危機欲絕交。", "溪響隔溪來枕面，月光先月到林梢。", "爲官拓落真吾事，何用紛紛更解嘲。"]'),
('8a353346-2e27-4606-9f2f-ddec670904ed','再用前韻','李彌遜','宋','宋诗','song-poetry','','[]','半生來去隔年巢，垂老朝昏一把茅。',64,'全唐诗/poet.song.99000.json','["半生來去隔年巢，垂老朝昏一把茅。", "白酒黄雞時喚客，碧梧翠竹舊論交。", "身閑野雁無行跡，妄盡霜林只戰梢。", "賸欲細談真子喻，誰能戲作少年嘲。"]'),
('23854e59-e0d5-4688-ac1c-223ed538103f','次韻公曄席上見贈即席和之','李彌遜','宋','宋诗','song-poetry','','[]','酒邉着語見真情，收拾應須遣六丁。',64,'全唐诗/poet.song.99000.json','["酒邉着語見真情，收拾應須遣六丁。", "戢戢甕頭堪一醉，栖栖澤畔忍長醒。", "湯盂茗椀香中泛，藥圃蔬畦燭下經。", "漏盡卻隨江月去，舞鷗迎我過寒汀。"]'),
('7c959cde-a130-453b-aa7d-6e2ec03fb955','與公曄飲西山坐上再和前韻','李彌遜','宋','宋诗','song-poetry','','[]','了無一物可當情，休數行年問丙丁。',64,'全唐诗/poet.song.99000.json','["了無一物可當情，休數行年問丙丁。", "世事於今渾似夢，醉魂從此不須醒。", "江流带月分清濁，星漢無雲見緯經。", "酒盡更謀須稚子，坐聽潮落響霜汀。"]'),
('1a57bb74-ef14-48fd-a1c9-85b34ce57572','南山送客席上次明甫韻','李彌遜','宋','宋诗','song-poetry','','[]','江北江南可避喧，已甘丘壑寄餘年。',64,'全唐诗/poet.song.99000.json','["江北江南可避喧，已甘丘壑寄餘年。", "筠梢松蓋一區宅，蓮葉菱花二頃田。", "秋到登山更臨水，夜歸騎馬似乘船。", "醉中不必分乘墜，世事從頭一夢然。"]'),
('84635032-6b16-4900-b6b3-a68903b0f09d','次韻向伯恭侍郎','李彌遜','宋','宋诗','song-poetry','','[]','世外營居絕點埃，到身無地展全才。',64,'全唐诗/poet.song.99000.json','["世外營居絕點埃，到身無地展全才。", "行藏曾許當年共，翰墨能從異縣來。", "海上梅花迎歲落，江頭桂子得秋開。", "一樽風月何時對，白髪思君首重回。"]'),
('49040b53-0453-4a6f-b39a-82f9c805a0e2','月夜攜家筠荘露坐池上分韻得誰字','李彌遜','宋','宋诗','song-poetry','','[]','累石驪泉十丈圍，週遭種柳未成絲。',64,'全唐诗/poet.song.99000.json','["累石驪泉十丈圍，週遭種柳未成絲。", "溪童掬水得明月，山客掃花安屈巵。", "一榼團欒兒女語，四更歷落斗牛垂。", "攔街白叟笑相問，倒着接䍦歌者誰。"]'),
('8cb57472-98d4-4e41-bbc0-defa71208d20','池上對月','李彌遜','宋','宋诗','song-poetry','','[]','捲蘆吹散一空雲，天面明金掛側盆。',64,'全唐诗/poet.song.99000.json','["捲蘆吹散一空雲，天面明金掛側盆。", "竹柏疏陰浮藻荇，山河清影落乾坤。", "習家池上酒初漉，越女溪邉花正繁。", "我醉欲眠歸未得，紛紛身外不須論。"]'),
('ac14a518-72da-4e82-bb89-0a6e4e731fa1','夏日小集池上次韻明甫之作','李彌遜','宋','宋诗','song-poetry','','[]','生怕微雲點太清，籜龍莫作斷腸聲。',64,'全唐诗/poet.song.99000.json','["生怕微雲點太清，籜龍莫作斷腸聲。", "餘霞到晚銖衣薄，滿月當空玉斧成。", "已結松筠爲老伴，不緣蛙黽喚愁生。", "但令有酒邀田父，矍鑠何須更一行。"]'),
('74130acf-9312-4d1d-aa90-a385988f1ee6','苦早','李彌遜','宋','宋诗','song-poetry','','[]','單練直似御重袍，碧盌冰漿飲尚豪。',64,'全唐诗/poet.song.99000.json','["單練直似御重袍，碧盌冰漿飲尚豪。", "滿載驪珠思薏苡，堆盤馬乳說蒲萄。", "輕雷破遠喧鼉鼓，小雨遮空簇蝟毛。", "誰挽天河洗炎酷，冷雲凉月助風騷。"]'),
('2f0e45bb-613d-42e3-9934-02ae939c6614','贈碩夫','李彌遜','宋','宋诗','song-poetry','','[]','此君風致似吾儂，來伴筠翁晚徑笻。',64,'全唐诗/poet.song.99000.json','["此君風致似吾儂，來伴筠翁晚徑笻。", "世味每於談際斷，詩情尤向飲邉濃。", "溪山寄語能相覓，猿鶴論交肯見從。", "共斸雲根結茅屋，自鋤菜甲爲君供。"]'),
('b08125bb-2769-4448-97c1-59799f925a9d','池亭獨坐','李彌遜','宋','宋诗','song-poetry','','[]','物華苒苒競芳新，六月紅渠自作春。',64,'全唐诗/poet.song.99000.json','["物華苒苒競芳新，六月紅渠自作春。", "走馬看花傳好句，長梯摘實賴幽人。", "雨餘門巷無留客，月上池臺絕過塵。", "爲約龜魚共清賞，酒香花氣兩相親。"]'),
('a58f1792-cbdf-4a0f-b2bd-9848f5caefd5','山遊遇雨','李彌遜','宋','宋诗','song-poetry','','[]','杖藜尋勝復中休，不比紅塵走燕騮。',64,'全唐诗/poet.song.99000.json','["杖藜尋勝復中休，不比紅塵走燕騮。", "幽趣未窮隨雨斷，髙情無盡與雲浮。", "冥冥深樹秋猶暗，獵獵新蒲暖更柔。", "老去行藏甘一壑，不須重廣畔牢愁。"]'),
('e6f2c20f-6b1f-4e37-b7a7-a366bb3e87cb','送碩夫赴試禮部','李彌遜','宋','宋诗','song-poetry','','[]','詞壘新收汗馬勞，衝寒意氣九疑髙。',64,'全唐诗/poet.song.99000.json','["詞壘新收汗馬勞，衝寒意氣九疑髙。", "上書北闕真餘事，拄頰西山須汝曹。", "世慮薰心工製錦，時名唾手看連鼇。", "哦君賸欲傳衣句，爲解千牛綠綺袍。"]'),
('c0701ce4-55bc-4a2e-be11-1141ed7fb24e','送舟過南山用琴韻  其一','李彌遜','宋','宋诗','song-poetry','','[]','喚起騎鯨玉樹埋，江邉琢語亦佳哉。',64,'全唐诗/poet.song.99000.json','["喚起騎鯨玉樹埋，江邉琢語亦佳哉。", "眼看雲起山容改，坐覺春隨花信來。", "隔水村深尋徑入，繫船門窄待僧開。", "箇中有句無人道，更遣豐隆着雨催。"]'),
('19db5b3b-bc24-42d7-a546-a86d64c6542d','送舟過南山用琴韻  其二','李彌遜','宋','宋诗','song-poetry','','[]','雪濤一葦意雄誇，慣與灘頭雁聚沙。',64,'全唐诗/poet.song.99000.json','["雪濤一葦意雄誇，慣與灘頭雁聚沙。", "年後臘前梅喚客，山南水北竹爲家。", "蓬蒿影裏開三徑，笳鼓聲中聽兩衙。", "去住了無忻厭賞，暮年心迹晚林鴉。"]'),
('6f9085e3-36e8-4aae-8840-6b1083586329','次韻陳泰定見贈  其一','李彌遜','宋','宋诗','song-poetry','','[]','月魄哉生望已幾，豪華未厭老相隨。',64,'全唐诗/poet.song.99000.json','["月魄哉生望已幾，豪華未厭老相隨。", "放疏世故開黄卷，銷盡塵心對紫芝。", "急雨知寒催葉落，斷雲乘晚截山低。", "小槽早作酬春計，又是梅花結蘂時。"]'),
('107b33ca-4195-448a-acb1-22e8b7ce7660','次韻陳泰定見贈  其二','李彌遜','宋','宋诗','song-poetry','','[]','偶語無人且復吞，晝晴饒睡憇榕根。',64,'全唐诗/poet.song.99000.json','["偶語無人且復吞，晝晴饒睡憇榕根。", "鳥鳴幽谷何妨靜，花發深林只自繁。", "逸思共憐居有竹，清陰誰伴酒盈尊。", "非關興盡回船急，剝啄那知客至門。"]'),
('5e3c51e6-8569-4128-a221-36b1fb457c4f','次韻葉碩夫南歸見貽  其一','李彌遜','宋','宋诗','song-poetry','','[]','未掛丹題雁塔中，重來溪上覓筠翁。',64,'全唐诗/poet.song.99000.json','["未掛丹題雁塔中，重來溪上覓筠翁。", "相期老眼横搖碧，莫着征衫走軟紅。", "得失漫嗟蟬翼重，才名合見馬群空。", "三年小試驚人手，未信朱衣也不公。"]'),
('d41bcb9c-1fda-41a9-a34d-cd458a38aa25','次韻葉碩夫南歸見貽  其二','李彌遜','宋','宋诗','song-poetry','','[]','飛花無數上衣裾，孤悶須憑酒破除。',64,'全唐诗/poet.song.99000.json','["飛花無數上衣裾，孤悶須憑酒破除。", "翻手作雲傷往事，轉頭如夢欲捐書。", "但知甘苦同薇蕨，不問辛勤有屋廬。", "後日錦衣行晝里，肯來盤谷飯溪魚。"]'),
('4a3cf51f-de34-4bca-b3a9-c0509f1182c2','用碩夫韻述懷  其一','李彌遜','宋','宋诗','song-poetry','','[]','少年正墮塵網中，晚歲臭味商山翁。',64,'全唐诗/poet.song.99000.json','["少年正墮塵網中，晚歲臭味商山翁。", "避喧苦厭俗眼白，得酒徑借衰顔紅。", "半生事業一經足，是處生涯四壁空。", "故人白髪音書斷，傾蓋交情獨見公。"]'),
('bc9c5d97-409d-4e84-bf67-c17d21ad3ab1','用碩夫韻述懷  其二','李彌遜','宋','宋诗','song-poetry','','[]','黄塵工染寒士裾，造物不與相乘除。',64,'全唐诗/poet.song.99000.json','["黄塵工染寒士裾，造物不與相乘除。", "君愁盡寫杜陵句，我老欲作嵇康書。", "何門真是萬人敵，近事不聞三頋廬。", "端知駑馬戀棧豆，水激自有溟南魚。"]'),
('77076633-3599-488d-9389-db802653ba56','再用碩夫韻  其一','李彌遜','宋','宋诗','song-poetry','','[]','一丘一壑半生中，旁舍小兒見老翁。',64,'全唐诗/poet.song.99000.json','["一丘一壑半生中，旁舍小兒見老翁。", "歸來賦就晚逕綠，醉時歌罷春燈紅。", "壯心欲盡孤雲薄，昨夢不留寒月空。", "茗盌粥盂能事畢，四三朝暮付狙公。"]'),
('30c1fdba-50d7-4be0-8c55-2e6c4506e944','再用碩夫韻  其二','李彌遜','宋','宋诗','song-poetry','','[]','北窗欹臥風引裾，靜看燕雀沿階除。',64,'全唐诗/poet.song.99000.json','["北窗欹臥風引裾，靜看燕雀沿階除。", "攀緣已斷螘旋磨，結習尚存魚蠧書。", "一區未辦揚雄宅，駟馬不過淵明廬。", "蒼松翠竹湖邉趣，至樂豈在真知魚。"]'),
('9e227953-7101-471b-b23b-c46f9f94c277','筠磯待月','李彌遜','宋','宋诗','song-poetry','','[]','偶坐松根送落暉，竹風零露濕人衣。',64,'全唐诗/poet.song.99000.json','["偶坐松根送落暉，竹風零露濕人衣。", "亂螢點水只自照，宿鳥赴林猶並飛。", "玉塔微瀾秋月吐，澄江净練夜潮歸。", "好山不負平生約，故傍吾廬翠作圍。"]'),
('59277c37-e8e7-46c6-9576-65f1ee145657','次韻林明甫言志','李彌遜','宋','宋诗','song-poetry','','[]','老竹抽萌便出林，焉知來者不如今。',64,'全唐诗/poet.song.99000.json','["老竹抽萌便出林，焉知來者不如今。", "但看杞梓終成棟，不信潢汙解作霖。", "久客謾撩蘇子恨，中流應動祖生心。", "乘桴從我君休嘆，政恐功名苦見侵。"]'),
('900fb184-ad88-43b9-b047-8afa87825ac1','同蘇阮二公晚春遊西溪  其一','李彌遜','宋','宋诗','song-poetry','','[]','力破愁城覓醉鄉，蘇鳬阮屐共行藏。',64,'全唐诗/poet.song.99000.json','["力破愁城覓醉鄉，蘇鳬阮屐共行藏。", "觧吟疏影思和靖，忍見夭紅似洛陽。", "禪客緩催梅子熟，騷人正咏牡丹芳。", "酬花但促傳杯手，冰炭君休置我腸。"]'),
('6a1a7b01-f1b1-419d-9917-871f4da0f0b6','同蘇阮二公晚春遊西溪  其二','李彌遜','宋','宋诗','song-poetry','','[]','喚客班荆雜亂言，雀羅成日罷張門。',64,'全唐诗/poet.song.99000.json','["喚客班荆雜亂言，雀羅成日罷張門。", "自緣貧病無過轍，可是疏慵不出村。", "阮子何人對青白，韋郎幾日寄寒溫。", "北枝留得瑤香在，更約文尊此地論。"]'),
('d24cda98-1708-4dd9-a9f8-18bdd05fa9b9','再用粹中韻各賦牡丹梅花  其一','李彌遜','宋','宋诗','song-poetry','','[]','曾倚沉香作好粧，竹籬茅屋肯深藏。',64,'全唐诗/poet.song.99000.json','["曾倚沉香作好粧，竹籬茅屋肯深藏。", "天寒翠袖留空谷，歲晚長眉閉上陽。", "投轄尚能來好事，着鞭應恐並餘芳。", "廣平賦罷詩肩瘦，不爲梅花惱石腸。"]'),
('26c43860-c1fd-4c66-aeba-f3a7aaa15ca8','再用粹中韻各賦牡丹梅花  其二','李彌遜','宋','宋诗','song-poetry','','[]','寒花入眼亂紛紛，髙臥袁安雪塞門。',64,'全唐诗/poet.song.99000.json','["寒花入眼亂紛紛，髙臥袁安雪塞門。", "春透交枝才照座，風搖斷蕚已飄村。", "返魂香細寧辭折，自暖杯深不待温。", "爲約竹君同我老，交情此外更誰論。"]'),
('f6a7d426-b273-41e8-94d9-20e10c912721','題子陽監丞見一庵','李彌遜','宋','宋诗','song-poetry','','[]','雲間幽好許誰參，十畝林園擁舍南。',64,'全唐诗/poet.song.99000.json','["雲間幽好許誰參，十畝林園擁舍南。", "隱几獻花真不二，舉杯邀月但成三。", "着鞭有路非吾樂，彈鋏無求只自甘。", "吾亦營巢老深竹，肯分華榜共名庵。"]'),
('a1810bdb-4f8c-4cad-b238-bb14bac72a0f','樸上人訪筠翁於筠溪草堂袖詩爲贈雨中告别將有雁蕩之行屢挽不肯留索詩甚急以偈送之','李彌遜','宋','宋诗','song-poetry','','[]','一壑翛然聽雨眠，君來着語破雲烟。',64,'全唐诗/poet.song.99000.json','["一壑翛然聽雨眠，君來着語破雲烟。", "肯隨鷗狎清江上，欲趁鴻飛白日邉。", "童子不應多一指，學人正自少三拳。", "急行啗蔗逢佳境，春笋出林啼杜鵑。"]'),
('99e57d8a-c0a8-4ea7-8c1d-b12ca3e90566','仲宗訪我筠溪出陪富文粹之遊天宫詩見索屬和次韻','李彌遜','宋','宋诗','song-poetry','','[]','作伴僊翁覓轉春，净坊俱現宰官身。',64,'全唐诗/poet.song.99000.json','["作伴僊翁覓轉春，净坊俱現宰官身。", "蘭亭夢想如三月，蓮社追遊少一人。", "雨磴勞君鳴屐齒，風軒爲我掃衣塵。", "應憐野老聞韶後，旋束蔬腸學練津。"]'),
('de2b67b5-c6c1-4532-82bb-fcbf68e8a6f6','山門晚歸','李彌遜','宋','宋诗','song-poetry','','[]','毗耶香飯壑源春，午枕聊分百億身。',64,'全唐诗/poet.song.99000.json','["毗耶香飯壑源春，午枕聊分百億身。", "旋落澗泉髙下語，自鳴山鳥送迎人。", "雲山往歲真成癖，觴咏一時俱絕塵。", "已辦歸途踏山暝，試捫髙壁上星津。"]'),
('e8bed04f-9198-4741-a468-ecc742423695','仲宗許過我甚久一見便有去意戲用春字韻留之','李彌遜','宋','宋诗','song-poetry','','[]','麥秋數盡稻花春，六尺茅茨百懶身。',64,'全唐诗/poet.song.99000.json','["麥秋數盡稻花春，六尺茅茨百懶身。", "散策崎嶇聊永日，繫舟剝啄定幽人。", "關心有念真形役，過眼無根俱客塵。", "肯着青鞋從我老，阿香徑遣斷歸輪。"]'),
('79606ebe-8a1e-42ee-9c52-dad0b86b1510','與粹之遊支提九日仲宗以詩酒見寄次韻答之','李彌遜','宋','宋诗','song-poetry','','[]','蛇徑回環織女機，足間欹石礙雲飛。',64,'全唐诗/poet.song.99000.json','["蛇徑回環織女機，足間欹石礙雲飛。", "西風短髪欺烏帽，落日清尊走白衣。", "病眼逢山寒水净，妄心更事遠烟微。", "掃除磊磈装懷地，爲載千巖萬壑歸。"]'),
('bc175e3e-1c1d-46d1-8bf2-e760e8cfd67b','次韻葉成甫有懷見寄','李彌遜','宋','宋诗','song-poetry','','[]','來轅去棹亦勞勞，晚歲丘園避俗陶。',64,'全唐诗/poet.song.99000.json','["來轅去棹亦勞勞，晚歲丘園避俗陶。", "問事不知三語掾，閲人無意九方臯。", "交論金石窮猶見，詩得江山老更豪。", "清夢摠能追蠟屐，雨聲偏傍夜牀髙。"]'),
('20bacf8a-e019-4471-80a0-979fece666ea','丞相張公築室湘江之上若欲遠人間事盡心於山水之樂以奉壽母而末章以忠孝詔諸來者寓意深矣索詩寄之  其一','李彌遜','宋','宋诗','song-poetry','','[]','蕙櫋蘭橑濕青紅，衡嶽湘江一望通。',64,'全唐诗/poet.song.99000.json','["蕙櫋蘭橑濕青紅，衡嶽湘江一望通。", "曉日雲烟隨几杖，春風花草近房櫳。", "赤松未結忘機伴，綠野聊從避俗翁。", "更欲將心何處盡，山河全露妙明中。"]'),
('13f2be48-9a08-4800-b3be-855354fb3a84','丞相張公築室湘江之上若欲遠人間事盡心於山水之樂以奉壽母而末章以忠孝詔諸來者寓意深矣索詩寄之  其二','李彌遜','宋','宋诗','song-poetry','','[]','庭前蘭玉走斑衣，堂上塤箎樂壽巵。',64,'全唐诗/poet.song.99000.json','["庭前蘭玉走斑衣，堂上塤箎樂壽巵。", "永晝牙籖紛簡帙，深庭豹尾臥旌旗。", "笑談自有江山助，勳業從來草木知。", "許國尚餘忠鯁在，此心還與歲寒期。"]'),
('1f17a4c4-295f-434b-b7fc-fa71fb7c8637','次韻平仲侍郎移居見簡','李彌遜','宋','宋诗','song-poetry','','[]','不寄斜封歲已餘，那聞異縣更移居。',64,'全唐诗/poet.song.99000.json','["不寄斜封歲已餘，那聞異縣更移居。", "覊懷易動野馬也，歸夢自成胡蝶與。", "有宅一區如子少，受薪十束見予疏。", "搖知富有千頭橘，奉乞當年種樹書。"]'),
('e44ff0a6-27b0-4fdb-85c1-8af52e1f03ce','和平仲侍郎再用移居韻','李彌遜','宋','宋诗','song-poetry','','[]','雲屋潭潭百尺餘，入簾燕雀賀新居。',64,'全唐诗/poet.song.99000.json','["雲屋潭潭百尺餘，入簾燕雀賀新居。", "人皆役役何爲者，君獨欣欣而樂與。", "巵酒覓懽那得再，筒詩傳恨未全疏。", "絕交定笑嵇中散，雁足來時肯繫書。"]'),
('715fd0a5-14e0-4971-b57f-20f598a96941','題明叔郎中海月吹笛圖','李彌遜','宋','宋诗','song-poetry','','[]','天上星郎騎省孫，興隨孤月到無垠。',64,'全唐诗/poet.song.99000.json','["天上星郎騎省孫，興隨孤月到無垠。", "浮槎夜入魚龍宅，横竹秋生海嶽雲。", "控鯉丹成終獨往，騎鯨仙去杳難群。", "紛紛世上知君少，畫茟猶能續異聞。"]'),
('e51e6fff-6407-4441-9994-667dbc22fbbf','次韻林褎然知縣留題筠荘因寄之  其一','李彌遜','宋','宋诗','song-poetry','','[]','何人着腳傍巖幽，好事無過竹務猷。',64,'全唐诗/poet.song.99000.json','["何人着腳傍巖幽，好事無過竹務猷。", "妙語徑追盤谷序，輕舟獨信剡溪流。", "牛刀小試知多暇，鶴板遲來坐不謀。", "欲寄一行安否問，朔風覊雁正淹留。"]'),
('1e3890b4-11c7-4241-b606-74d69d462d09','次韻林褎然知縣留題筠荘因寄之  其二','李彌遜','宋','宋诗','song-poetry','','[]','世路人心比太行，此君真可共徜徉。',64,'全唐诗/poet.song.99000.json','["世路人心比太行，此君真可共徜徉。", "霜凝勁節明朝塢，月落寒梢散夜堂。", "可但七人供笑詠，要令千畝作陰凉。", "只愁捲地西風裏，幽夢圓時與子妨。"]'),
('c996f54b-463e-4f76-9471-970397535e2e','未明出東門將入聖泉戲呈住山蒙庵老人','李彌遜','宋','宋诗','song-poetry','','[]','覿面峰巒碧障天，東方精色破昏烟。',64,'全唐诗/poet.song.99000.json','["覿面峰巒碧障天，東方精色破昏烟。", "草頭露下元無雨，衣角風生徑欲仙。", "行樹排宵髙展畫，孤雲掛壑薄披綿。", "寸田暫喜捐塵慮，不着蒙庵一縷禪。"]'),
('75d5bcc8-c7d1-4fc3-b761-c13aa91bf640','和淵老妙現之什','李彌遜','宋','宋诗','song-poetry','','[]','乾坤渺渺一浮尊，萬象分明水四濱。',64,'全唐诗/poet.song.99000.json','["乾坤渺渺一浮尊，萬象分明水四濱。", "虎脊横空山作隊，魚鱗倒影海成紋。", "老僧詩罷閑欹竹，幽士餘齋正臥雲。", "妙現鏡中無一事，世間從此罷揮斤。"]'),
('00f6fa9a-dfd8-402d-9e79-8b0bd46c6979','送蕭德洪赴試建安','李彌遜','宋','宋诗','song-poetry','','[]','鴻鵠不作三年飛，乘秋逸興髙九疑。',64,'全唐诗/poet.song.99000.json','["鴻鵠不作三年飛，乘秋逸興髙九疑。", "去尋巖桂香中路，趁得御柳風前期。", "青錢立登天上選，黄絹共賞人間辭。", "漢庭第一公家事，平步凌雲要及時。"]'),
('70600efc-48b2-4bd5-8e30-bc107ad11abc','和仲宗判監','李彌遜','宋','宋诗','song-poetry','','[]','與世浮沉半醉醒，結廬人境晝常扃。',64,'全唐诗/poet.song.99000.json','["與世浮沉半醉醒，結廬人境晝常扃。", "微吟松竹風無定，着色峰巒雨乍經。", "方簟北窗身是夢，瘦藤斜照影隨形。", "豈無曳尾泥中計，政恐腸刳不自靈。"]'),
('96ac45ab-cea1-471c-b2ee-fed353d8037c','次韻天寧通老見貽','李彌遜','宋','宋诗','song-poetry','','[]','病餘真是獨醒人，還在僧窗自在身。',64,'全唐诗/poet.song.99000.json','["病餘真是獨醒人，還在僧窗自在身。", "竹杖芒鞋尋勝趣，齋盂禪板悟前因。", "江山臭味如相覓，猿鶴家風願卜鄰。", "更有髙人來着語，交游不怕白頭新。"]'),
('1e418d29-8d0d-43f6-8f17-39abb5317a34','題福唐郡園清閟亭','李彌遜','宋','宋诗','song-poetry','','[]','公餘自種南階竹，好事風流今未聞。',64,'全唐诗/poet.song.99000.json','["公餘自種南階竹，好事風流今未聞。", "但得七人來結友，何須千畝比封君。", "風梢不定微藏日，雨葉初乾薄带雲。", "自是甘棠人愛惜，不憂寒谷遇樵斤。"]'),
('2c673818-3044-40ea-8c18-0dec1c396eef','題薛直老府園萬象亭','李彌遜','宋','宋诗','song-poetry','','[]','斷取方壺壯郡壕，鈎連野色上亭臯。',64,'全唐诗/poet.song.99000.json','["斷取方壺壯郡壕，鈎連野色上亭臯。", "星移日轉天容麗，江净山明地軸髙。", "下榻筵賓供歗咏，凝香罷寢助風騷。", "使君八九吞雲夢，小展風烟遺我曹。"]'),
('d021c406-59f8-4662-b063-d09c93494b3a','次韻薛帥萬象亭','李彌遜','宋','宋诗','song-poetry','','[]','山上非烟靄四隅，山前稉稻綠成區。',64,'全唐诗/poet.song.99000.json','["山上非烟靄四隅，山前稉稻綠成區。", "留雲有計低簷額，得月從多徹戶樞。", "直是春臺熙遠族，聊爲夏屋試宏圖。", "公來日出千林迥，卻笑新亭咏小湖。"]'),
('95f20be9-5901-4549-bdd3-f75534d7bfaf','次韻道夫待制萬象亭','李彌遜','宋','宋诗','song-poetry','','[]','不見三秋若望霓，寒亭今得共攀躋。',64,'全唐诗/poet.song.99000.json','["不見三秋若望霓，寒亭今得共攀躋。", "眼中遠樹兩行直，腳底孤烟百尺低。", "幻出璜臺輝舊觀，旋安銀榜快新題。", "細聽屋角風雲聚，誰謂天髙不可梯。"]'),
('9c593bf1-b5cd-4450-9847-0a868f42ecff','次韻季申樞密萬象亭','李彌遜','宋','宋诗','song-poetry','','[]','丈人手筆與僊通，點化虚無若轉蓬。',64,'全唐诗/poet.song.99000.json','["丈人手筆與僊通，點化虚無若轉蓬。", "妙寄千言千嶂外，全收萬象一簷中。", "深堂細篆觀澄水，落日危欄數去鴻。", "更壓小槽囊古錦，共臨髙處待春風。"]'),
('1c717c36-1557-46a3-87f1-9700f0ef7ebf','送趙二十一觀察蜀中迎親','李彌遜','宋','宋诗','song-poetry','','[]','得意那知行路難，板輿行處蜀江邉。',64,'全唐诗/poet.song.99000.json','["得意那知行路難，板輿行處蜀江邉。", "慈顔未拜心先往，樂事乍聞人共傳。", "新製衣裳文錦縀，重頒雨露間花牋。", "回思三十年中恨，長願兒生有母憐。"]'),
('bcb0357e-3e5b-45bc-b959-783590a16051','次韻趙道夫待制放魚之作','李彌遜','宋','宋诗','song-poetry','','[]','出門忽見鯉城市，脱爾寧捐一粒貲。',64,'全唐诗/poet.song.99000.json','["出門忽見鯉城市，脱爾寧捐一粒貲。", "就使烹鮮真可口，誰能結網更臨池。", "斜風送浪回頳尾，淺水平沙走素鰭。", "勿謂寰中底么魔，三生恩怨不能欺。"]'),
('bc4875d3-126c-4b24-960f-b3b6d24d8ac9','題張仲宗鷗盟軒','李彌遜','宋','宋诗','song-poetry','','[]','寄語沙頭不下鷗，詩翁新葺面江樓。',64,'全唐诗/poet.song.99000.json','["寄語沙頭不下鷗，詩翁新葺面江樓。", "早知世事翻覆手，更覺人生起滅漚。", "念盡不應書咄咄，身閑何用榜休休。", "徑須来結忘機伴，春水浮天不繫舟。"]'),
('26a6781d-2a64-4537-a05e-0f54ecab4020','陪大慈老登古院','李彌遜','宋','宋诗','song-poetry','','[]','林影横榰折腳床，禪翁喚我坐斜陽。',64,'全唐诗/poet.song.99000.json','["林影横榰折腳床，禪翁喚我坐斜陽。", "諸天共說無生話，萬壑同薰不盡香。", "茗椀泛雲醒遠目，藜羹煑玉閙枯腸。", "逢人若問峰頭事，翠竹陰中菊正黄。"]'),
('e199aaa9-9e9f-41ae-b67e-74ba3ad5bc9d','次韻粹之通判九日之作','李彌遜','宋','宋诗','song-poetry','','[]','柏子香中閉净坊，爲君着屐弄秋陽。',64,'全唐诗/poet.song.99000.json','["柏子香中閉净坊，爲君着屐弄秋陽。", "老來見事如無事，節裏隨鄉且入鄉。", "但可炊糜傾兔褐，何妨撚菊泛鵝黄。", "九仙坐想群賢集，不數龍山事渺茫。"]'),
('af5450ac-2b82-4d79-9d9a-08e60aad329f','仲宗過筠荘作詩見招且有借庵之意次其韻','李彌遜','宋','宋诗','song-poetry','','[]','横山留我正青眼，不是歸心久更微。',64,'全唐诗/poet.song.99000.json','["横山留我正青眼，不是歸心久更微。", "病後團蒲隨地隐，望中落木故園稀。", "一區已辦雲爲蓋，四壁但從山作圍。", "不厭是中無一物，徑來相就老禪扉。"]'),
('76e78f09-8f3d-4784-8491-af137140e599','病後戲呈謨老禪師','李彌遜','宋','宋诗','song-poetry','','[]','霜髭病起若相侵，銷盡平生未了心。',64,'全唐诗/poet.song.99000.json','["霜髭病起若相侵，銷盡平生未了心。", "一事關身俱是夢，萬緣彈指已非今。", "月林清影元無定，山路幽香不可尋。", "喚取湯休共清夜，靜聽簾雨寫鳴琴。"]'),
('2c4e8676-7aa3-446d-9dcd-c31ad87cd52e','送仲宗之建安','李彌遜','宋','宋诗','song-poetry','','[]','老翁更事幾河沙，苦愛溪頭管物華。',64,'全唐诗/poet.song.99000.json','["老翁更事幾河沙，苦愛溪頭管物華。", "種竹成林心未足，買船載月思無涯。", "黄鶯喚友非多事，白鷺窺魚更可嗟。", "念子藍舁晚山裏，可能來共拾餘霞。"]'),
('75beed02-f2b4-4919-9b73-7688de401bdf','比見帥憲禱雨甚虔枕上聞簷聲爲之不寐因成','李彌遜','宋','宋诗','song-poetry','','[]','兩公精意與神交，平地能令水滿篙。',64,'全唐诗/poet.song.99000.json','["兩公精意與神交，平地能令水滿篙。", "雲氣遠收晴嶂合，雨聲偏傍夜床髙。", "轆轤未暇分甘井，舴艋應知避怒濤。", "願受一廛須及早，秋成猶得飽兒曹。"]'),
('93e1a7e7-4562-4955-a9db-824892f0003a','次韻譚彦成學士早春  其一','李彌遜','宋','宋诗','song-poetry','','[]','花蕾催紅欲囀鶯，新愁偏傍鬢毛生。',32,'全唐诗/poet.song.99000.json','["花蕾催紅欲囀鶯，新愁偏傍鬢毛生。", "猶憐稚子能賒酒，爛醉春盤碧澗羹。"]'),
('31272fd6-e8a8-4933-b732-1ff10deb4770','次韻譚彦成學士早春  其二','李彌遜','宋','宋诗','song-poetry','','[]','幽棲不寄絕交書，車馬從喧賣酒壚。',32,'全唐诗/poet.song.99000.json','["幽棲不寄絕交書，車馬從喧賣酒壚。", "臥轉午陰春睡足，卻尋峰樹數花鬚。"]'),
('5ce6eae6-867b-41a5-a9e2-6aaa087afb10','次韻譚彦成學士早春  其三','李彌遜','宋','宋诗','song-poetry','','[]','十二樓臺白玉成，雲車翻日上觚稜。',32,'全唐诗/poet.song.99000.json','["十二樓臺白玉成，雲車翻日上觚稜。", "太平何許同民樂，天闕雙龍護一燈。"]'),
('a21a974f-5035-49b5-a8c2-039764ad2dfa','次韻譚彦成學士早春  其四','李彌遜','宋','宋诗','song-poetry','','[]','渺渺家山水四涯，秋風曾憶醉黄華。',32,'全唐诗/poet.song.99000.json','["渺渺家山水四涯，秋風曾憶醉黄華。", "馬頭不識南塘路，又看咸陽二月花。"]'),
('855e0e08-cffc-46f1-81fe-4ef87c15de6d','次韻譚彦成學士早春  其五','李彌遜','宋','宋诗','song-poetry','','[]','風絮縈寒晝擁爐，枝頭猶得暗香餘。',32,'全唐诗/poet.song.99000.json','["風絮縈寒晝擁爐，枝頭猶得暗香餘。", "折來不擬供尊俎，靜對翛然一榻書。"]'),
('5fa01762-7a1f-4ebd-a564-434da334a6e4','方池獨步','李彌遜','宋','宋诗','song-poetry','','[]','度柳穿莎一徑通，曲堤初詠舞雩風。',32,'全唐诗/poet.song.99000.json','["度柳穿莎一徑通，曲堤初詠舞雩風。", "我來似與春期約，南陌東畦到處紅。"]'),
('3ce9c9b8-d8b0-4d17-b013-9996d055749e','六六軒','李彌遜','宋','宋诗','song-poetry','','[]','秋雨已分千壑間，午天初放一軒晴。',32,'全唐诗/poet.song.99000.json','["秋雨已分千壑間，午天初放一軒晴。", "撥開三十六峰翠，爲洗老人雙眼明。"]'),
('0bec9e18-f44d-457b-b085-6317609507fc','可師止庵','李彌遜','宋','宋诗','song-poetry','','[]','踏盡東西散勝巖，卻提隻履過江南。',32,'全唐诗/poet.song.99000.json','["踏盡東西散勝巖，卻提隻履過江南。", "遠人若觧真常位，不礙攜庵到處參。"]'),
('6b49c656-87b0-4562-94e6-5f26df6590ee','面壁庵','李彌遜','宋','宋诗','song-poetry','','[]','敗壁縱横銷翠煙，巖花猶落舊庵前。',32,'全唐诗/poet.song.99000.json','["敗壁縱横銷翠煙，巖花猶落舊庵前。", "從來說法無人會，寂寂空山謾九年。"]'),
('5c2956d7-1ab2-4179-a430-aa31bf685c1c','宿光林懷少章','李彌遜','宋','宋诗','song-poetry','','[]','煙斷伽藍欲報昏，竹梢風雨亂紛紛。',32,'全唐诗/poet.song.99000.json','["煙斷伽藍欲報昏，竹梢風雨亂紛紛。", "懸知借枕山腰舍，魂夢已隨超化雲。"]'),
('b3e52c6a-c2da-4f6a-bbc1-1e78fb0893b8','己亥季秋至凈居思大智者道場因瞻二士相三日會天大雨不得探險絕而以詩記之  其一','李彌遜','宋','宋诗','song-poetry','','[]','三蘇巖壑連雲秀，二士門庭匝地新。',32,'全唐诗/poet.song.99000.json','["三蘇巖壑連雲秀，二士門庭匝地新。", "带雨山光無限思，一時分付鏡中人。"]'),
('fb858bc5-7968-4a9a-90c2-a393d60af15c','己亥季秋至凈居思大智者道場因瞻二士相三日會天大雨不得探險絕而以詩記之  其二','李彌遜','宋','宋诗','song-poetry','','[]','香斷寒爐古廟空，金毛一去了無蹤。',32,'全唐诗/poet.song.99000.json','["香斷寒爐古廟空，金毛一去了無蹤。", "分明曾得真消息，猶有參天十萬松。"]'),
('d21c3ab3-67be-4e9a-9246-bf736b49f201','己亥季秋至凈居思大智者道場因瞻二士相三日會天大雨不得探險絕而以詩記之  其三','李彌遜','宋','宋诗','song-poetry','','[]','雨華隨步到天關，遠目纔分繚繞山。',32,'全唐诗/poet.song.99000.json','["雨華隨步到天關，遠目纔分繚繞山。", "風馬不馳前景斷，更於何地覓無還。"]'),
('090ec477-df5c-40bd-8b4c-2ed48b2e3192','己亥季秋至凈居思大智者道場因瞻二士相三日會天大雨不得探險絕而以詩記之  其四','李彌遜','宋','宋诗','song-poetry','','[]','白霧蒼烟暗九秋，殷牀金吼抱山樓。',32,'全唐诗/poet.song.99000.json','["白霧蒼烟暗九秋，殷牀金吼抱山樓。", "爲霖未必渾三日，似有閑雲伴我留。"]'),
('144c572c-dee2-405c-977f-179aa4af2965','儀真道中  其一','李彌遜','宋','宋诗','song-poetry','','[]','過盡長淮未見山，倦尋殘夢獨凭欄。',32,'全唐诗/poet.song.99000.json','["過盡長淮未見山，倦尋殘夢獨凭欄。", "風烟漸欲回春眼，不似蔣陵江上看。"]'),
('71151786-b40b-463c-b272-0c9d49d85238','儀真道中  其二','李彌遜','宋','宋诗','song-poetry','','[]','長天漠漠水連空，雲淡風微兩兩紅。',32,'全唐诗/poet.song.99000.json','["長天漠漠水連空，雲淡風微兩兩紅。", "南北不知緣底事，一生半落往來中。"]'),
('7b122122-bd61-4314-b463-6acddfeb2a39','儀真道中  其三','李彌遜','宋','宋诗','song-poetry','','[]','旋搗香秔炊玉粒，飽肥鮮鯽鱠銀絲。',32,'全唐诗/poet.song.99000.json','["旋搗香秔炊玉粒，飽肥鮮鯽鱠銀絲。", "他年虛費太官粟，到得江頭已恨遲。"]'),
('91eaae01-fa9b-4a89-b59e-abad07cbfe38','留題鑑遠樓  其一','李彌遜','宋','宋诗','song-poetry','','[]','表裏江山面面來，秋風此日偶徘徊。',32,'全唐诗/poet.song.99000.json','["表裏江山面面來，秋風此日偶徘徊。", "塵埃閲盡心如鑑，一到江樓眼爲開。"]'),
('0d00fa5d-4010-437e-a902-4eb9fdd18113','留題鑑遠樓  其二','李彌遜','宋','宋诗','song-poetry','','[]','憑虛瞰碧與雲浮，只有閑身盡日留。',32,'全唐诗/poet.song.99000.json','["憑虛瞰碧與雲浮，只有閑身盡日留。", "更擬夢回還獨上，來看殘夜水明樓。"]'),
('9de27113-5ef2-4412-8dd7-317a26f0c863','留題鑑遠樓  其三','李彌遜','宋','宋诗','song-poetry','','[]','霜天曉日鑑中新，眼力由來未見真。',32,'全唐诗/poet.song.99000.json','["霜天曉日鑑中新，眼力由來未見真。", "萬古茫茫一塵跡，碧山無際水無垠。"]'),
('b8fc8de5-7438-4e13-962e-f65a84e659fd','舟師謁祠回天風已霽信若有感姑以二絕道其事  其一','李彌遜','宋','宋诗','song-poetry','','[]','長蘆山下隱龍宫，瀝酒船迴落照中。',32,'全唐诗/poet.song.99000.json','["長蘆山下隱龍宫，瀝酒船迴落照中。", "已有龜紋爲傳卜，不勞烏尾更占風。"]'),
('41a1d78a-ee37-4059-9e2c-0e407c44c9ef','舟師謁祠回天風已霽信若有感姑以二絕道其事  其二','李彌遜','宋','宋诗','song-poetry','','[]','水底明河碧浸星，琉璃不動一江平。',32,'全唐诗/poet.song.99000.json','["水底明河碧浸星，琉璃不動一江平。", "横鋪十幅指東去，坐看曉帆千里輕。"]'),
('33456674-e492-43b8-b72e-aa6bea774132','渡江  其一','李彌遜','宋','宋诗','song-poetry','','[]','沿江山斷水如天，横絕奔流一葉船。',32,'全唐诗/poet.song.99000.json','["沿江山斷水如天，横絕奔流一葉船。", "身世自知同幻夢，不應對此重茫然。"]'),
('0564f66a-b215-4198-89f3-06e3968e4dbe','渡江  其二','李彌遜','宋','宋诗','song-poetry','','[]','山形虎脊髙低去，帆影魚鱗遠近來。',32,'全唐诗/poet.song.99000.json','["山形虎脊髙低去，帆影魚鱗遠近來。", "已到江南望江北，更留青眼爲誰開。"]'),
('81ba607f-2ee6-42e9-b55e-70c975033f6d','過嶽冠山  其一','李彌遜','宋','宋诗','song-poetry','','[]','嶽冠山下月黄昏，石立波吞勢莫分。',32,'全唐诗/poet.song.99000.json','["嶽冠山下月黄昏，石立波吞勢莫分。", "回首風前魂欲斷，東西南北水連雲。"]'),
('2da101e4-ab35-474f-8362-a251f68f782a','過嶽冠山  其二','李彌遜','宋','宋诗','song-poetry','','[]','駕潮風急浪翻磯，舟子操舟不自持。',32,'全唐诗/poet.song.99000.json','["駕潮風急浪翻磯，舟子操舟不自持。", "若使畏塗知勇退，世間何處更乘危。"]'),
('623338c3-9d36-4f3e-b737-81d8dadf2c5b','秋晚即事  其一','李彌遜','宋','宋诗','song-poetry','','[]','一水縈回兩岸鷗，翩翩無數近行舟。',32,'全唐诗/poet.song.99000.json','["一水縈回兩岸鷗，翩翩無數近行舟。", "十年不見渾如舊，有意隨人天際浮。"]'),
('dd7939ff-51c9-4774-b3f6-31ef138b6006','秋晚即事  其二','李彌遜','宋','宋诗','song-poetry','','[]','華髪鬅鬙一榻書，舟移斜日似籧篨。',32,'全唐诗/poet.song.99000.json','["華髪鬅鬙一榻書，舟移斜日似籧篨。", "似聞載酒江邉寺，更倒青錢留白魚。"]'),
('e6166ffb-cf17-4d15-9766-1aba9bce443f','秋晚即事  其三','李彌遜','宋','宋诗','song-poetry','','[]','霜樹今無一葉留，日邉雲暗使人愁。',32,'全唐诗/poet.song.99000.json','["霜樹今無一葉留，日邉雲暗使人愁。", "獨憐揚子灣頭岸，猶有黄花戀晚秋。"]'),
