('ba586421-1fef-4738-b47d-9ba42addced2','次韻郎中弟見寄  其五','李彌遜','宋','宋诗','song-poetry','','[]','驥子摛詞苦未工，粉袍勍敵氣如虹。',32,'全唐诗/poet.song.99000.json','["驥子摛詞苦未工，粉袍勍敵氣如虹。", "欲收一戰追諸父，政恐神錐未易同。"]'),
('74860919-d590-4d10-bbf3-a80dec764f2c','次韻郎中弟見寄  其六','李彌遜','宋','宋诗','song-poetry','','[]','青春不與老相期，歸雁聲中數别離。',32,'全唐诗/poet.song.99000.json','["青春不與老相期，歸雁聲中數别離。", "折柳西城真旦暮，鏡中白髪已如斯。"]'),
('22531f44-41b0-4bea-87c8-30f1e20b801f','次韻郎中弟見寄  其七','李彌遜','宋','宋诗','song-poetry','','[]','窮秋璧月才圓後，猶憶桑弧初掛年。',32,'全唐诗/poet.song.99000.json','["窮秋璧月才圓後，猶憶桑弧初掛年。", "千里一尊懽稚子，祝君從我傲壺天。"]'),
('8deeaf3e-2c47-4c47-a80f-4ec6980891ce','次韻郎中弟見寄  其八','李彌遜','宋','宋诗','song-poetry','','[]','西林葉幄已藏鴉，若比蝸牛信可誇。',32,'全唐诗/poet.song.99000.json','["西林葉幄已藏鴉，若比蝸牛信可誇。", "更約此君成莫逆，北窗髙臥看紛華。"]'),
('8ca0d054-cafc-4280-a7e6-429ef6dcb356','次韻郎中弟見寄  其九','李彌遜','宋','宋诗','song-poetry','','[]','浮木隨流誰見招，春江無盡水雲搖。',32,'全唐诗/poet.song.99000.json','["浮木隨流誰見招，春江無盡水雲搖。", "只今瘴海投閑地，魑魅爲鄰盗正驕。"]'),
('4f34bbff-19d4-49b9-ae65-8dd813427c6c','次韻郎中弟見寄  其一○','李彌遜','宋','宋诗','song-poetry','','[]','季子論才到履駒，十年不調可憐渠。',32,'全唐诗/poet.song.99000.json','["季子論才到履駒，十年不調可憐渠。", "自聞馬祖今非佛，不似潛夫但著書。"]'),
('c03dd0b7-0125-4d9a-96ef-e1e49c6d05fc','題福州與春亭','李彌遜','宋','宋诗','song-poetry','','[]','史君同樂在春亭，吏退心田水様清。',32,'全唐诗/poet.song.99000.json','["史君同樂在春亭，吏退心田水様清。", "恰似春風吹百卉，白紅無數不知名。"]'),
('4ff6cbfe-f6de-47a0-ba4f-15969bcf2897','次韻趙表之道中見梅之作  其一','李彌遜','宋','宋诗','song-poetry','','[]','近水疏籬竹半侵，枝南枝北弄晴陰。',32,'全唐诗/poet.song.99000.json','["近水疏籬竹半侵，枝南枝北弄晴陰。", "不因老眼分明見，辜負凌寒一寸心。"]'),
('4b5c118f-7cd7-457f-82ff-e3a5268094df','次韻趙表之道中見梅之作  其二','李彌遜','宋','宋诗','song-poetry','','[]','不是先争特特開，只緣沙際欲春迴。',32,'全唐诗/poet.song.99000.json','["不是先争特特開，只緣沙際欲春迴。", "行人浪起空華想，一夜歸心着夢催。"]'),
('321c1ca7-227a-45d5-bfab-9402059fbf90','智道者入閩作大緣事一住數年將歸以偈送之','李彌遜','宋','宋诗','song-poetry','','[]','道者南行作勝緣，下窮有際上諸天。',32,'全唐诗/poet.song.99000.json','["道者南行作勝緣，下窮有際上諸天。", "卻來踏着銅峰路，可費虚抛買屐錢。"]'),
('77d2cf0d-847b-459d-9187-4997233fbbd5','送玿公長老赴南劍光孝之請','李彌遜','宋','宋诗','song-poetry','','[]','好手逢場了不同，五家宗外立家風。',32,'全唐诗/poet.song.99000.json','["好手逢場了不同，五家宗外立家風。", "玿師一句當機語，不道楊岐栗棘逢。"]'),
('58026fd6-4078-40ee-a254-50c68db37ea8','嗣知客遠訪筠溪留旬餘將歸以偈送之','李彌遜','宋','宋诗','song-poetry','','[]','剝啄君來破鬰陶，解包相對煑溪毛。',32,'全唐诗/poet.song.99000.json','["剝啄君來破鬰陶，解包相對煑溪毛。", "一坡脩竹無窮意，可但靈雲只見桃。"]'),
('2f94e8d4-efca-4c8c-bba0-59c48a0fb4b3','出山','李彌遜','宋','宋诗','song-poetry','','[]','白霧蒼烟晝不分，竹風梢雨亂紛紛。',32,'全唐诗/poet.song.99000.json','["白霧蒼烟晝不分，竹風梢雨亂紛紛。", "杖藜來往成何事，添我胸中一壑雲。"]'),
('d9a2c4ad-cd1c-4ee3-95c2-01c6fda635a6','筠荘落成分韻得意字','李彌遜','宋','宋诗','song-poetry','','[]','離離頷下髭，短白不可薙。',96,'全唐诗/poet.song.99000.json','["離離頷下髭，短白不可薙。", "焉能老行路，結屋聊自芘。", "溪横衆山繞，左右松竹翳。", "山華如幽人，獨秀不取媚。", "客來飲以漓，累觴亦復醉。", "欲眠子姑去，自占十畝翠。", "不爲溝壑憂，不作子孫計。", "旁觀大笑之，不解箇中意。"]'),
('2722dec2-31a8-4f20-b815-949ffdce692c','楊貫之提舉挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','當年接翼上天池，舊事空存雁塔題。',32,'全唐诗/poet.song.99000.json','["當年接翼上天池，舊事空存雁塔題。", "豈有新詩來渭北，謾令後學仰關西。"]'),
('be1db7ea-123d-4a24-8669-74fd5602d07a','楊貫之提舉挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','錦衣人逐驚漚散，丹旐歌隨落照低。',32,'全唐诗/poet.song.99000.json','["錦衣人逐驚漚散，丹旐歌隨落照低。", "它日扁舟江上路，酸風吹淚過姑溪。"]'),
('c14f9db6-ac6c-438e-a9a9-66cdd90bb332','龍學許公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','粹德山藏玉，高標木秀林。',48,'全唐诗/poet.song.99000.json','["粹德山藏玉，高標木秀林。", "三朝侍楓禁，列郡憇棠陰。", "文翰家聲在，規模國計深。", "盖棺頭正黑，空負濟時心。"]'),
('8167da4c-d329-48cc-9ec1-fe0ce4849b0c','龍學許公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','晚起故園興，柴車歸鹿門。',48,'全唐诗/poet.song.99000.json','["晚起故園興，柴車歸鹿門。", "營家無立壁，愛客不空尊。", "喪亂長纓絕，悲凉舊劍存。", "不堪聽楚些，無處可招魂。"]'),
('0fb40cb7-c782-42c2-90d7-fb525577815d','碩人趙氏挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','毓秀名臣裔，來賓上相家。',48,'全唐诗/poet.song.99000.json','["毓秀名臣裔，來賓上相家。", "浮漚輕富貴，朽木視鈆華。", "曉日俄晞露，春風自笑花。", "仙蹤今不返，望斷五雲車。"]'),
('54832fa8-24cd-45fe-be41-a19e6213ac1d','碩人趙氏挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','命服從夫貴，遺經易子成。',48,'全唐诗/poet.song.99000.json','["命服從夫貴，遺經易子成。", "蘋蘩無失職，琴瑟自和鳴。", "已嘆歸同穴，猶悲夢兩楹。", "旁觀灑清淚，雙旐出寒城。"]'),
('1c0e6f2b-f348-45ba-9bdd-3ea41f5c6fe2','晉康郡侯碩人曾氏挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','閥閲榮誇俗，閨房秀出群。',48,'全唐诗/poet.song.99000.json','["閥閲榮誇俗，閨房秀出群。", "得賢推淑女，有子賴嚴君。", "臺柏憂時譽，庭蘭奕世聞。", "高名寫彤管，異代仰清氛。"]'),
('184d4f66-e724-4c95-baa5-d1d11bf0bd57','晉康郡侯碩人曾氏挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','身備難幷福，心明最上宗。',48,'全唐诗/poet.song.99000.json','["身備難幷福，心明最上宗。", "夜臺亡宿恨，旦宅漫遺蹤。", "塵暗魚機帳，雲低馬鬛封。", "酸風一襟涙，哀入暮山松。"]'),
('700e5dc6-b66c-48a9-bd5a-6090de3a0607','忠顯劉公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','活人憂國見平生，晚節臨危志益明。',64,'全唐诗/poet.song.99000.json','["活人憂國見平生，晚節臨危志益明。", "漢仗塵深遠宫闕，胡裘風急半公卿。", "千人致招竟不起，萬戶封侯卻似烹。", "暮晉朝梁真可忍，紛紛螻蟻尚偷生。"]'),
('abad250f-9d5e-4c98-91c2-720ad623b70d','忠顯劉公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','禍基媒孽自燕秦，抗議如公有幾人。',64,'全唐诗/poet.song.99000.json','["禍基媒孽自燕秦，抗議如公有幾人。", "軍旅未聞焉用試，豺狼不噬豈宜親。", "求魚緣木謾蠧國，曲突徙薪翻殞身。", "才大言深古難用，忠良千載恨常新。"]'),
('cfb7ba74-bcbf-4c18-9586-2cc4892a4ca6','張柔直知郡挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','世路狐狸正急賢，並遊長恐着鞭先。',64,'全唐诗/poet.song.99000.json','["世路狐狸正急賢，並遊長恐着鞭先。", "龔黄政術江湖上，賈馬聲名雨露邊。", "白髪空違三釡養，青衿獨抱一經傳。", "傷心才大難爲用，不爲酸風亦泫然。"]'),
('528578c4-d07d-4631-9ab6-efcacbf277ea','張柔直知郡挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','金蘭臭味百年期，生死那知歘兩岐。',64,'全唐诗/poet.song.99000.json','["金蘭臭味百年期，生死那知歘兩岐。", "路斷束芻難寄恨，封成掛劍謾傳悲。", "向來不誦凌雲賦，此日休歌薤露詩。", "自愧千秋負良友，剩留清淚與君垂。"]'),
('c0777223-b94a-421b-8b05-0b3ddac8efec','故相少師李公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','天意康時難，賢生蓋世雄。',48,'全唐诗/poet.song.99000.json','["天意康時難，賢生蓋世雄。", "風流晉人上，事業舜歌中。", "許國回天力，懷君貫日忠。", "平生英爽氣，凛凛未成空。"]'),
('39865c42-033b-4a07-9fc0-235101222408','故相少師李公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','國步乘陽九，胡塵暗上京。',48,'全唐诗/poet.song.99000.json','["國步乘陽九，胡塵暗上京。", "支傾隆大厦，卻敵隱長城。", "草木知春澤，狐狸絕夜鳴。", "雲臺瞻袞繡，千古繼哀榮。"]'),
('49d156a7-6c20-4b36-bb45-87a5bd637253','故相少師李公挽詩  其三','李彌遜','宋','宋诗','song-poetry','','[]','去國頭方黑，傷時鬢易絲。',48,'全唐诗/poet.song.99000.json','["去國頭方黑，傷時鬢易絲。", "徙薪謀獨騐，擊楫志空悲。", "尚想嘉猷告，曾聞大政諮。", "兩楹歌昨夢，忍誦憗遺詩。"]'),
('0596bf5c-474f-4b40-a498-a153ce2d2c66','故相少師李公挽詩  其四','李彌遜','宋','宋诗','song-poetry','','[]','白髪陳雷舊，交情貴不渝。',48,'全唐诗/poet.song.99000.json','["白髪陳雷舊，交情貴不渝。", "詩牋留曉炬，書雁聚春蘆。", "憂國言猶在，知心道已孤。", "江臯一襟涙，不復見夷吾。"]'),
('53972ef8-275b-4719-9e2d-5e5f0e1497f9','門下大資顔公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','洙泗流風遠，儀型世有人。',48,'全唐诗/poet.song.99000.json','["洙泗流風遠，儀型世有人。", "一經窺聖域，三返得賢臣。", "勳業艱難際，聲名寂寞濱。", "赤松歸有伴，此道獨知津。"]'),
('5e550c7e-6adf-4523-9802-258bef95a3d0','門下大資顔公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','不作鸞臺夢，來尋鳳沼春。',48,'全唐诗/poet.song.99000.json','["不作鸞臺夢，來尋鳳沼春。", "劬勞知永慕，壽考見深仁。", "示疾元非病，離人已反真。", "生綃寫遺恨，猶露袞衣身。"]'),
('84faf4e4-e0c3-4817-b9c6-f4446ecc15de','門下大資顔公挽詩  其三','李彌遜','宋','宋诗','song-poetry','','[]','東郡連牆日，行藏二紀餘。',48,'全唐诗/poet.song.99000.json','["東郡連牆日，行藏二紀餘。", "空留冡上劍，不見枕中書。", "山黑佳城閟，堂陰旦宅虛。", "悲心寄松檟，哀韻擁輀車。"]'),
('fb90a875-e782-45e8-b9c4-9f49558d8aba','寶學連公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','男兒死爾未應悲，可惜胸中尚有奇。',64,'全唐诗/poet.song.99000.json','["男兒死爾未應悲，可惜胸中尚有奇。", "絕域英聲宜早歲，楚庭高議補明時。", "壮懷自感中流楫，舊愛今存峴首碑。", "天獨不能遺此老，蓋棺兩鬢未全絲。"]'),
('bb6d3568-d3a4-41ce-9e4e-113ba6cf8056','寶學連公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','弱冠論交老更堅，平生風義想前賢。',64,'全唐诗/poet.song.99000.json','["弱冠論交老更堅，平生風義想前賢。", "銀峰告政一千里，雁塔聯名四十年。", "漫許赤心酬雨露，終成白髪傲林泉。", "酸風送子寒山暮，鳴壑搖松亦泫然。"]'),
('5eb71533-576c-434b-9db9-00f49cf6f474','鄭尚明學士挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','人物羲皇上，塵中無此流。',48,'全唐诗/poet.song.99000.json','["人物羲皇上，塵中無此流。", "高談悲管晏，老手命曹劉。", "室有芝蘭棄，家餘鐘鼎收。", "平生斷金約，墮涙蓋棺休。"]'),
('3f503323-2803-4499-a987-2a1cb29e63a5','鄭尚明學士挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','四十才名重，歸來白髪侵。',48,'全唐诗/poet.song.99000.json','["四十才名重，歸來白髪侵。", "一官駒在谷，有子鶴鳴陰。", "賸著潛夫論，今亡子敬琴。", "送車知幾兩，松壑助哀音。"]'),
('ef55564c-2a9b-492d-931c-d1a75891f18f','陳氏太君挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','淑德嬪賢裔，宜家有令人。',48,'全唐诗/poet.song.99000.json','["淑德嬪賢裔，宜家有令人。", "蘋蘩寒更潔，繭績老猶親。", "月館虛陶客，雲阡失孟鄰。", "悲風獵丹旐，行路亦霑巾。"]'),
('9166ec5f-bb99-4472-849f-e09185187f1f','陳氏太君挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','之子榮親志，長纓萬里歸。',48,'全唐诗/poet.song.99000.json','["之子榮親志，長纓萬里歸。", "如何晝錦地，不見老萊衣。", "誰謂松難老，俄成露易晞。", "平生三釡樂，空使寸心違。"]'),
('3e676276-a9e1-4f9b-af1d-1f7c409077ac','知郡鄭公挽詩','李彌遜','宋','宋诗','song-poetry','','[]','拾芥聲名早歲馳，白頭有藴未全施。',64,'全唐诗/poet.song.99000.json','["拾芥聲名早歲馳，白頭有藴未全施。", "向來茂草無留訟，是處甘棠有去思。", "才術舊聞優少贛，交游賸欲賴當時。", "誰知沱水歌來暮，翻作西城薤露詩。"]'),
('f4e429e1-da3a-4574-a7ec-95d22d435e6c','彭府君夫人羅氏挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','擢秀芝蘭畹，來嬪詩禮庭。',48,'全唐诗/poet.song.99000.json','["擢秀芝蘭畹，來嬪詩禮庭。", "好羞貧更潔，壽髪短猶青。", "秦號封方寵，蓬瀛駕不停。", "天風助哀怨，吹雨濕丹銘。"]'),
('0ff8d85d-99ed-4d58-be90-9721341ad09c','彭府君夫人羅氏挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','始訝生兒異，那知有母賢。',48,'全唐诗/poet.song.99000.json','["始訝生兒異，那知有母賢。", "客無三至感，家獨一經傳。", "恨鎖魚機帳，悲纒馬鬛阡。", "他年陳五鼎，清晝下雲軿。"]'),
('f9e42f68-1093-4b94-b282-f4e493e168d1','郭君建挽詩','李彌遜','宋','宋诗','song-poetry','','[]','藹藹聲華萬耳聞，可憑詩禮大於門。',64,'全唐诗/poet.song.99000.json','["藹藹聲華萬耳聞，可憑詩禮大於門。", "浮雲終負三餘學，流水難追九逝魂。", "朝有青衿懷舊德，室惟黄卷富諸昆。", "生平不對論文酒，空使清鈆比涙痕。"]'),
('4dd41016-527d-4fd6-868b-cf386d7f2615','蔡子應郎中挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','獨秀聲名楚水東，妙年騰達俊游中。',64,'全唐诗/poet.song.99000.json','["獨秀聲名楚水東，妙年騰達俊游中。", "文昌寓直風雲近，神武歸來猿鶴同。", "居士人非禪板寂，少微星暗寶函空。", "知心不必悲生死，欲向何方覓是翁。"]'),
('a5323237-e8ea-4ab2-9688-a3e616278556','蔡子應郎中挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','三生曾結在家因，半世相從漸老身。',64,'全唐诗/poet.song.99000.json','["三生曾結在家因，半世相從漸老身。", "曲几團蒲分夜靜，斜風細字寄情親。", "伯牛命矣元非病，桑戶嗟來已反真。", "我亦無心趁哀樂，每懷前事一傷神。"]'),
('0082e09c-a524-4f13-be4d-c31cf507ddaf','宫使待制舍人趙公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','秀出青徐野，風移鄒魯鄉。',48,'全唐诗/poet.song.99000.json','["秀出青徐野，風移鄒魯鄉。", "家聲齊丙魏，人物到軒黄。", "漫士從三已，危機付兩忘。", "並遊無此老，誰與共行藏。"]'),
('a7ea5d4d-aeee-456d-9780-e069ebf813b1','宫使待制舍人趙公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','曲突深時慮，長裾鄙世流。',48,'全唐诗/poet.song.99000.json','["曲突深時慮，長裾鄙世流。", "無書來北闕，有意在東周。", "曠遠嵇中散，疏慵馬少游。", "長松想風表，千古閟山丘。"]'),
('3fbe855b-38fa-4ebc-940a-99cfa2654f97','宫使待制舍人趙公挽詩  其三','李彌遜','宋','宋诗','song-poetry','','[]','憶昨司青瑣，公時對紫薇。',48,'全唐诗/poet.song.99000.json','["憶昨司青瑣，公時對紫薇。", "午軒評諫草，曉殿綴朝衣。", "金石平生契，人琴此日非。", "白頭情易感，無涙與君揮。"]'),
('48f8f8d9-1579-4000-9939-794f1acc62b0','彦節判宗觀察挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','國步增磐石，維城協夢熊。',48,'全唐诗/poet.song.99000.json','["國步增磐石，維城協夢熊。", "風神龍種異，才格馬群空。", "家訓惟知白，官箴祇自公。", "拊棺傷有德，天意或難窮。"]'),
('0539ef57-a13b-454f-82f1-cbaefcd0c28b','彦節判宗觀察挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','儉素師寒雋，謙冲識老成。',48,'全唐诗/poet.song.99000.json','["儉素師寒雋，謙冲識老成。", "養親公族化，取友士林傾。", "賀屨填門近，靈輀赴壠輕。", "悲歡反覆手，揮涙濕銘旌。"]'),
('2e791f52-3555-41a8-99e1-a5b999d64741','許子儒寺丞挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','陰德仙官裔，殊勳輔相家。',48,'全唐诗/poet.song.99000.json','["陰德仙官裔，殊勳輔相家。", "山川鍾秀麗，人物見雄夸。", "小試丞卿月，卑棲屬使華。", "蓋棺何太早，行路亦興嗟。"]'),
('444e1de0-5feb-44d5-b725-b4bd85908479','許子儒寺丞挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','壮歲天衢上，舂容伯仲間。',48,'全唐诗/poet.song.99000.json','["壮歲天衢上，舂容伯仲間。", "握蘭同省戶，持櫜假朝班。", "投老歸鄉縣，從君臥故山。", "並游零落盡，回首一潸潸。"]'),
('0764e987-b270-4f1e-92c4-51a2085de803','知郡韓公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','夫君抱清節，獨秀不求知。',48,'全唐诗/poet.song.99000.json','["夫君抱清節，獨秀不求知。", "晉鄙多薰德，閿鄉早出奇。", "功名天靳惜，正直自扶持。", "賴有仁風在，朱轓兩郡遺。"]'),
('d6f1f43e-0798-495d-8176-e76ad0ba4fca','知郡韓公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','雁塔聯名舊，鹽車得路先。',48,'全唐诗/poet.song.99000.json','["雁塔聯名舊，鹽車得路先。", "凌雲曾誦賦，縱壑願推賢。", "繼剖龍溪竹，同歸象骨田。", "傷心老盤谷，誰與序山川。"]'),
('24f08e25-7e0d-42bd-a1a7-98e6be72647a','翊善余公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','弱冠聲名翰墨場，一官小試活人方。',64,'全唐诗/poet.song.99000.json','["弱冠聲名翰墨場，一官小試活人方。", "二王賓客推清介，半刺規模與善良。", "可但仁風薰晉鄙，猶憐奇節老閿鄉。", "康寧壽考猶餘事，蘭玉階亭久更芳。"]'),
('c2b4bbc7-c92f-4ec4-9fe9-b297f759492b','翊善余公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','白髪歸來一笑同，舊遊長憶魯山東。',64,'全唐诗/poet.song.99000.json','["白髪歸來一笑同，舊遊長憶魯山東。", "松楸地接螺江上，兄弟名聯雁塔中。", "問舍蝸牛聊老□，□書蠆尾不憂窮。", "清芬千古無遺恨，空使餘哀入暮風。"]'),
('86b8cc40-f8c5-4cb4-b538-da3545837bdb','節使少師王公挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','家聲許史舊，弱冠近天墀。',48,'全唐诗/poet.song.99000.json','["家聲許史舊，弱冠近天墀。", "權出諸公右，官嫌二品卑。", "多知緣好古，得句舊能詩。", "自怪文開後，風流有此兒。"]'),
('9b536f9f-9149-42f5-a346-09be15fbb896','節使少師王公挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','晚歲閩江上，來從竹下賢。',48,'全唐诗/poet.song.99000.json','["晚歲閩江上，來從竹下賢。", "肯爲文字飲，時訪祖師禪。", "念舊藏遺墨，忘形出近編。", "忍傾一巵酒，揮涙對新阡。"]'),
('a5983df3-79fb-48a3-b71b-a96d90e34f69','李德脩提舉挽詩','李彌遜','宋','宋诗','song-poetry','','[]','仙李盤根遠更芳，妙齡雙桂看翺翔。',64,'全唐诗/poet.song.99000.json','["仙李盤根遠更芳，妙齡雙桂看翺翔。", "繡衣俗美澄清効，墨綬民安愷悌方。", "東閤揮金歡上客，春田種玉燕諸郎。", "年高七十通朝貴，賸馥猶令畢萬昌。"]'),
('7cf56292-35cc-4ca5-a01d-3475ea95ef68','范參議宜人高氏挽詩  其一','李彌遜','宋','宋诗','song-poetry','','[]','毓秀勳庸後，來嬪詩禮家。',48,'全唐诗/poet.song.99000.json','["毓秀勳庸後，來嬪詩禮家。", "浮雲輕富貴，朽木視鉛華。", "晚日俄晞露，春風自笑花。", "平生偕老志，愁絕五雲車。"]'),
('df5770c0-9a3f-437a-810b-e6098aa021a7','范參議宜人高氏挽詩  其二','李彌遜','宋','宋诗','song-poetry','','[]','蘭玉無偏愛，衾裯不忍欺。',48,'全唐诗/poet.song.99000.json','["蘭玉無偏愛，衾裯不忍欺。", "甘辛同逆旅，生死獨先知。", "馬鬛苔封合，魚機寶帳遺。", "酸風入松檟，空作暮山悲。"]'),
('58a14da1-a759-4252-806e-68d486a13f88','盧橘','李彌遜','宋','宋诗','song-poetry','','[]','皮似稗柿鬆而剝，核如龍眼味甘鮮。',32,'全唐诗/poet.song.99000.json','["皮似稗柿鬆而剝，核如龍眼味甘鮮。", "滿盤的皪如金彈，叢之分嘗憶去年。"]'),
('74b11781-6b1f-4b57-8c7b-f242b2b92633','降虎峰慧慈塔','李彌遜','宋','宋诗','song-poetry','','[]','喚起田公趁曉耕，香雲已带瀉簷聲。',32,'全唐诗/poet.song.99000.json','["喚起田公趁曉耕，香雲已带瀉簷聲。", "如何乞取摩空手，爲挽天河洗甲兵。"]'),
('b6b39588-3e1e-4d1e-8477-4dd6d4a4efcd','小雲堂','李彌遜','宋','宋诗','song-poetry','','[]','老子何因一念差，肯將簪紱換袈裟。',64,'全唐诗/poet.song.99000.json','["老子何因一念差，肯將簪紱換袈裟。", "同參尚有滿路在，異世猶將遜老誇。", "結習未忘能作舞，因緣那得見拈花。", "卻修凈業尋來路，澹泊如今居士家。"]'),
('b46570e5-faeb-49a0-833a-8889009ffe8f','偈','李彌遜','宋','宋诗','song-poetry','','[]','漫說從來牧護，今日分明呈露。',28,'全唐诗/poet.song.99000.json','["漫說從來牧護，今日分明呈露。", "虛空拶倒須彌，說甚向上一路。"]'),
('566a1b75-79bf-4c5b-aaf9-a23b0c3cb05b','白馬寺','李彌遜','宋','宋诗','song-poetry','','[]','飛鳴屋上烏，入我夢中聽。',48,'全唐诗/poet.song.99000.json','["飛鳴屋上烏，入我夢中聽。", "遲明月未昃，平曉風更靜。", "游雲四山幕，止水萬象鏡。", "身如走空虛，南北了不定。"]'),
('d0022312-b9cb-47b5-8dfd-368f690e6a7b','和祝鎰韻','李彌正','宋','宋诗','song-poetry','','[]','勞車發危坂，倦艘失飛湍。',144,'全唐诗/poet.song.99000.json','["勞車發危坂，倦艘失飛湍。", "滔滔褦襶子，疾走殊未闌。", "鶴仙擺名宦，結廬松江干。", "笑拍萍風浮，瞬視草露漙。", "圖川不愧輞，序谷寧先盤。", "門豈俗駕拒，室無哀箏彈。", "按行松菊間，澹然有餘觀。", "蓮巢衆香聚，浮天百憂寬。", "秋光斂洲渚，暮翠籠峰巒。", "我來挾良朋，道故盟未寒。", "練顔仰孤標，耐久同蒼官。", "終當役薪水，刀圭卻衰殘。"]'),
('adcc3556-df70-4e5b-8df9-d2218cf49a12','謁蘇仙祠','羅汝楫','宋','宋诗','song-poetry','','[]','絳節回白馬，青書收赤龍。',96,'全唐诗/poet.song.99000.json','["絳節回白馬，青書收赤龍。", "仙人在何計，煙霞鎖晴峰。", "荒祠冠其嶺，千古凜靈蹤。", "粉堵塵網懸，石凹苔錢重。", "我來款遺像，再拜虔且恭。", "檀煙洩雲白，茗粥浮新濃。", "世事非所期，真遊誓相從。", "雲軺幾時來，微風韻寒松。"]'),
('3e8adeed-588e-42fa-bd5c-a4aeb0727df2','遊破山興福寺','莫儔','宋','宋诗','song-poetry','','[]','久聞勝地有蓮宮，乘興來遊杖瘦筇。',64,'全唐诗/poet.song.99000.json','["久聞勝地有蓮宮，乘興來遊杖瘦筇。", "庭老樛枝翠瓔珞，地生並蒂玉芙蓉。", "飛仙何意來題柱，開澗當年想鬬龍。", "歸騎回看樓閣處，雲深隱隱度疏鐘。"]'),
('33147072-6c41-4e42-a274-b715774b649a','題驂鸞閣','莫儔','宋','宋诗','song-poetry','','[]','群山带雨陰雲重，滄海連天水氣昏。',32,'全唐诗/poet.song.99000.json','["群山带雨陰雲重，滄海連天水氣昏。", "遙想真人乘鐵舸，往來三島鬼神奔。"]'),
('20f35b83-7e7e-41fd-9e97-153cac023dc9','靈巖禪寺','王大寶','宋','宋诗','song-poetry','','[]','雁蕩聞名久，靈巖舍道邊。',48,'全唐诗/poet.song.99000.json','["雁蕩聞名久，靈巖舍道邊。", "諸峰皆列岫，一柱獨擎天。", "卓筆豈容有，展旗非偶然。", "眼前無障礙，自是洞中仙。"]'),
('899271b4-99af-42ab-bfe6-1fd3784b228c','偈','釋達珠','宋','宋诗','song-poetry','','[]','聖賢不分，古今惟一。',46,'全唐诗/poet.song.99000.json','["聖賢不分，古今惟一。", "可謂火就燥，水流濕。", "鑿井而飲，耕田而食。", "東村王老去不歸，紛紛黄葉空狼籍。"]'),
('e12abe91-7dd9-4208-8413-2ba472fbff2a','偈','釋法淳','宋','宋诗','song-poetry','','[]','半夜逾城景象虛，雪山深處觜盧都。',32,'全唐诗/poet.song.99000.json','["半夜逾城景象虛，雪山深處觜盧都。", "直饒一見明星悟，已是當時不丈夫。"]'),
('f7b6dea0-e8ec-43cb-877c-8a186d35579f','偈','釋慧光','宋','宋诗','song-poetry','','[]','不用求真，何須息見，倒騎牛兮入佛殿。',34,'全唐诗/poet.song.99000.json','["不用求真，何須息見，倒騎牛兮入佛殿。", "羌笛一聲天地空，不知誰識瞿曇面。"]'),
('14ebf810-752a-4f1d-99f6-3fc389477c25','頌古三首  其一','釋欽','宋','宋诗','song-poetry','','[]','喚作如如已變名，廓然無聖豈容情。',32,'全唐诗/poet.song.99000.json','["喚作如如已變名，廓然無聖豈容情。", "其間妙叶皆同類，不有玄暉辨濁清。"]'),
('59abcda2-845b-453b-b92a-7b27d03c064c','頌古三首  其二','釋欽','宋','宋诗','song-poetry','','[]','八字打開，十分漏泄。',37,'全唐诗/poet.song.99000.json','["八字打開，十分漏泄。", "孤危不立道方高，伎倆更無隨意說。", "別別，南斗七兮北斗八。"]'),
('7b1e965d-1115-4211-8490-0a3af18709c1','頌古三首  其三','釋欽','宋','宋诗','song-poetry','','[]','有句無句，明來暗去。',80,'全唐诗/poet.song.99000.json','["有句無句，明來暗去。", "活捉生擒，捷書露布。", "如藤倚樹，物以類聚。", "海外人參，蜀中附子。", "樹倒藤枯，切忌名模。", "句歸何所，蘇嚧蘇嚧。", "呵呵大笑，破鏡不照。", "大地茫茫，一任𨁝跳。"]'),
('291fa1f3-9d57-418e-ad55-a9810bb81344','偈三首  其一','釋道昌','宋','宋诗','song-poetry','','[]','道不屬知，不屬不知。',78,'全唐诗/poet.song.99000.json','["道不屬知，不屬不知。", "知是妄覺，不知是無記。", "若真達不疑之道，礙他銅盤不打老鼠。", "所以抽身入，還從屋裏來。", "報教臺凳穩，聊且勸三杯。", "兄呼弟喚殷勤處，留得兒孫辨劫灰。"]'),
('f36bb63e-6694-4d47-8cdf-edcaa3bffc55','偈三首  其二','釋道昌','宋','宋诗','song-poetry','','[]','未透祖師關，千難與萬難。',57,'全唐诗/poet.song.99000.json','["未透祖師關，千難與萬難。", "既透祖師關，千難與萬難。", "未透時難即且置，既透了因甚麽卻難。", "放下笊籬雖得價，動他杓柄大無端。"]'),
('3af17ba2-3e4a-41d6-bb0a-3c27c1bf5041','偈三首  其三','釋道昌','宋','宋诗','song-poetry','','[]','與我相似，共爾無緣。',36,'全唐诗/poet.song.99000.json','["與我相似，共爾無緣。", "打翻藥銚，傾出爐煙。", "還丹一粒分明在，流落人間是幾年。"]'),
('cb5b2e8b-95bd-4a1c-92f6-5fcb6493adf4','頌古四首  其一','釋道昌','宋','宋诗','song-poetry','','[]','慣使渡頭船，如今不記年。',24,'全唐诗/poet.song.99000.json','["慣使渡頭船，如今不記年。", "愛他風浪惡，方是趁粗錢。"]'),
('778cb27f-ca4b-472d-95a3-9e5595a341d1','頌古四首  其二','釋道昌','宋','宋诗','song-poetry','','[]','千佛居何處，題詩黄鶴樓。',24,'全唐诗/poet.song.99000.json','["千佛居何處，題詩黄鶴樓。", "感恩幷積恨，終日在眉頭。"]'),
('90825340-89ce-4a8b-92b9-b0f077d19db5','頌古四首  其三','釋道昌','宋','宋诗','song-poetry','','[]','光非照境境非存，光境俱忘復是痕。',32,'全唐诗/poet.song.99000.json','["光非照境境非存，光境俱忘復是痕。", "百鳥不來春已老，落華流水繞江村。"]'),
('3608905f-6176-47de-a0fc-5f4ce7f38116','頌古四首  其四','釋道昌','宋','宋诗','song-poetry','','[]','慣行私路，乍赴公筵。',36,'全唐诗/poet.song.99000.json','["慣行私路，乍赴公筵。", "幞頭腳短，腰带夸圓。", "不是伴郎來勸酒，誤他年少覓青氈。"]'),
('d3933d06-6a03-4b03-92ae-2a4b839cfe23','送僧','釋道昌','宋','宋诗','song-poetry','','[]','掃盡諸方路布禪，到頭窼臼落雁邊。',32,'全唐诗/poet.song.99000.json','["掃盡諸方路布禪，到頭窼臼落雁邊。", "臺盤角畔重拈起，萬里神光頂後全。"]'),
('56495112-7d2b-4635-9985-e18e406a50d3','自贊','釋道昌','宋','宋诗','song-poetry','','[]','丹青寫出，剩卻一箇。',36,'全唐诗/poet.song.99000.json','["丹青寫出，剩卻一箇。", "竇入布衫，著著便破。", "土面灰頭那畔行，水墨觀音解推磨。"]'),
('ce1da2f5-27e7-46b4-a4f3-90f91a0f36e3','頌古五十七首  其一','釋道昌','宋','宋诗','song-poetry','','[]','奴兒婢子，十生九死。',36,'全唐诗/poet.song.99000.json','["奴兒婢子，十生九死。", "於裏不正，被外邊使。", "縱饒開口便過頭，未免渾身輥泥水。"]'),
('d6310a5f-05a2-4bc5-b345-c5c7f3e24bfc','頌古五十七首  其二','釋道昌','宋','宋诗','song-poetry','','[]','二俱不了，隨合多少。',20,'全唐诗/poet.song.99000.json','["二俱不了，隨合多少。", "縱使夜行，投明未到。"]'),
('e66ec333-d584-401a-a807-73af1198f51c','頌古五十七首  其三','釋道昌','宋','宋诗','song-poetry','','[]','水乳不分，菽麥難辨。',44,'全唐诗/poet.song.99000.json','["水乳不分，菽麥難辨。", "擔带病深，改移功淺。", "十二時中不依倚，明見佛性有此理，漿水錢在草鞋裏。"]'),
('70801238-88ca-4c26-8cb4-e2453e175670','頌古五十七首  其四','釋道昌','宋','宋诗','song-poetry','','[]','手攜花鼓到城根，反著麻鞋過短門。',32,'全唐诗/poet.song.99000.json','["手攜花鼓到城根，反著麻鞋過短門。", "笑把柴頭書古字，大家來步月黄昏。"]'),
('83e36b94-e559-481a-baf6-cb9645f67b42','頌古五十七首  其五','釋道昌','宋','宋诗','song-poetry','','[]','活中死眼，無作有用。',44,'全唐诗/poet.song.99000.json','["活中死眼，無作有用。", "方寸不移，十方獨弄。", "巧拙不到處，鹽官有出身。", "親言出親口，雞犬鬧比鄰。"]'),
('76ec18d0-8f68-4a8b-93db-a9134fa53502','頌古五十七首  其六','釋道昌','宋','宋诗','song-poetry','','[]','是兩頭語，未出泥水。',46,'全唐诗/poet.song.99000.json','["是兩頭語，未出泥水。", "非兩頭語，依前自死。", "振錫卓然，白日青天。", "風力還他敗壞時，漫天大網生光輝。"]');
